('admin_forgot_password', 1, 'Forgot Password Email', 'Reset Password Email', '\r\n<table width=\"600px\" cellspacing=\"0\" cellpadding=\"0\" style=\"margin: 0 auto; table-layout: fixed; background: #ffffff; border-radius: 4px; box-shadow: 0 0 10px rgba(0, 0, 0, 0.04)\">\r\n	<tbody>\r\n		<tr>\r\n			<td style=\"background:#fff;padding:20px 0 30px; text-align:center;\">\r\n				<h4 style=\"font-weight:normal; text-transform:uppercase; color:#999;margin:0; padding:10px 0; font-size:18px;\">Request Received</h4>\r\n				<h2 style=\"margin:0; font-size:34px; padding:0;\">Retrieve Password!</h2></td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"background:#fff;padding:0 30px; text-align:center; color:#999;vertical-align:top;\">\r\n				<table width=\"100%\" border=\"0\" align=\"center\" cellpadding=\"0\" cellspacing=\"0\">\r\n					<tbody>\r\n						<tr>\r\n							<td style=\"padding:20px 0 30px;\"><strong style=\"font-size:18px;color:#333;\">Dear {user_full_name} </strong><br />\r\n								It seems that you have used reset password option at <a href=\"{website_url}\">{website_name}</a>.</td>\r\n						</tr>\r\n						<tr>\r\n							<td style=\"padding:20px 0 30px;\">Please click here to below link to change your password.<br />\r\n								<a href=\"{reset_url}\" style=\"font-size:15px; color:#ff3a59;\">Click here</a></td>\r\n						</tr>\r\n						<tr>\r\n							<td style=\"padding:0 0 30px;\">Please ignore this email if you did not use the reset password option</td>\r\n						</tr>\r\n					</tbody>\r\n				</table></td>\r\n		</tr>\r\n	</tbody>\r\n</table>', '{user_full_name} Name of the email receiver<br>\r\n{website_name} Name of our website<br>\r\n{website_url} URL of our website<br>\r\n{reset_url} URL to reset the password<br>\r\n{social_media_icons} <br>\r\n{contact_us_url} <br>', 1),
('admin_new_user_creation_email', 1, 'New Account Created By Admin', 'Welcome to {website_name}', '\r\n<table width=\"100%\" align=\"center\" cellpadding=\"0\" cellspacing=\"0\">    \r\n</table>\r\n<table width=\"600px\" cellspacing=\"0\" cellpadding=\"0\" style=\"margin: 0 auto; table-layout: fixed; background: #ffffff; border-radius: 4px; box-shadow: 0 0 10px rgba(0, 0, 0, 0.04)\">\r\n	<tbody>\r\n		<tr>                        \r\n			<td style=\"background:#fff;padding:20px 0 10px; text-align:center;\">                            \r\n				<h4 style=\"font-weight:normal; text-transform:uppercase; color:#999;margin:0; padding:10px 0; font-size:18px;\"></h4>                            \r\n				<h2 style=\"margin:0; font-size:34px; padding:0;\">Welcome to {website_name}</h2></td>                    \r\n		</tr> \r\n		<tr>                        \r\n			<td style=\"background:#fff;padding:0 30px; text-align:center; color:#999;vertical-align:top;\">                            \r\n				<table width=\"100%\" border=\"0\" align=\"center\" cellpadding=\"0\" cellspacing=\"0\">                                \r\n					<tbody>                                    \r\n						<tr>                                        \r\n							<td style=\"padding:20px 0 30px;\"><strong style=\"font-size:18px;color:#333;\">Dear {name} </strong><br />\r\n								<a href=\"{website_url}\">{website_name}</a> admin has created an {account_type} account for you.</td>                                    \r\n						</tr>                                    \r\n						<tr>                                        \r\n							<td style=\"padding:20px 0 30px;\">To access and verify your account please visit the link given below. Your email address will be your username. \r\n								Please note that the link is valid for next {days} days.<br />\r\n								<a href=\"{reset_url}\">{reset_url}</a>.</td>                                    \r\n						</tr>                                \r\n					</tbody>                       