('affiliate_share_invitation_email', 1, 'Affiliate Invitation Email for Friends', 'Your friend has invited you for Amazing Discounts on {website_name}.', '\r\n<table width=\"600px\" cellspacing=\"0\" cellpadding=\"0\" style=\"margin: 0 auto; table-layout: fixed; background: #ffffff; border-radius: 4px; box-shadow: 0 0 10px rgba(0, 0, 0, 0.04)\">\r\n	<tbody>\r\n		<tr>                        \r\n			<td style=\"background:#fff;padding:20px 0 10px; text-align:center;\">                            \r\n				<h4 style=\"font-weight:normal; text-transform:uppercase; color:#999;margin:0; padding:10px 0; font-size:18px;\"></h4>                            \r\n				<h2 style=\"margin:0; font-size:34px; padding:0;\">Yo!kart Invitation!</h2></td>                    \r\n		</tr>     \r\n		<tr>                        \r\n			<td style=\"background:#fff;padding:0 30px; text-align:center; color:#999;vertical-align:top;\">                            \r\n				<table width=\"100%\" border=\"0\" align=\"center\" cellpadding=\"0\" cellspacing=\"0\">                                \r\n					<tbody>                                    \r\n						<tr>                                        \r\n							<td style=\"padding:20px 0 30px;\"><strong style=\"font-size:18px;color:#333;\">Dear Friend </strong><br />\r\n								This is an invitation from {user_full_name} to join them on <a href=\"{website_url}\">{website_name}</a> and enjoy Amazing Discounts.</td>                                    \r\n						</tr>                                    \r\n						<tr>                                        \r\n							<td style=\"padding:20px 0 30px;\">Click the link below to accept this invitation:<br />\r\n								<a href=\"{tracking_url}\" style=\"font-size:15px; color:#ff3a59;\">Click Here</a></td>                                    \r\n						</tr>                                    \r\n						<tr>                                        \r\n							<td style=\"padding:20px 0 30px;\">{invitation_message}</td>      