('blog_comment_status_changed', 1, 'Blog Comment Status Change - Notification', 'Blog Comment Status Changed at {website_name}', '\r\n<table width=\"600px\" cellspacing=\"0\" cellpadding=\"0\" style=\"margin: 0 auto; table-layout: fixed; background: #ffffff; border-radius: 4px; box-shadow: 0 0 10px rgba(0, 0, 0, 0.04)\">\r\n	<tbody>\r\n		<tr>                        \r\n			<td style=\"background:#fff;padding:20px 0 10px; text-align:center;\">                            \r\n				<h4 style=\"font-weight:normal; text-transform:uppercase; color:#999;margin:0; padding:10px 0; font-size:18px;\">Changed</h4>                            \r\n				<h2 style=\"margin:0; font-size:34px; padding:0;\">Blog Contribution Status</h2></td>                    \r\n		</tr>\r\n		<tr>                        \r\n			<td style=\"background:#fff;padding:0 30px; text-align:center; color:#999;vertical-align:top;\">                            \r\n				<table width=\"100%\" border=\"0\" align=\"center\" cellpadding=\"0\" cellspacing=\"0\">                                \r\n					<tbody>                                    \r\n						<tr>                                        \r\n							<td style=\"padding:20px 0 30px;\"><strong style=\"font-size:18px;color:#333;\">Dear {user_full_name}</strong><br />\r\n								Your Comment (for the post \'{post_title}\' / posted on {posted_on_datetime}) status has been changed to {new_status} at <a href=\"{website_url}\">{website_name}</a>.<br />\r\n								</td>                                    \r\n						</tr>                                    \r\n					</tbody>                            \r\n				</table></td>                    \r\n		</tr>  \r\n	</tbody>\r\n</table>', '{user_full_name} Name of the email receiver<br/> \r\n{new_status} New/Current Order Status<br/>\r\n{posted_on_datetime} - Comment Posted on date time.<br/>\r\n{post_title} - Blog Post title.<br/>\r\n{comment} - Comment.<br/>\r\n{website_name} Name of our website<br>\r\n{website_url} URL of our website<br>\r\n{social_media_icons} <br>\r\n{contact_us_url} <br>\r\n', 1),
('blog_contribution_status_changed', 1, 'Blog Contribution Status Change - Notification', 'Blog Contribution Status Changed at {website_name}', '\r\n<table width=\"600px\" cellspacing=\"0\" cellpadding=\"0\" style=\"margin: 0 auto; table-layout: fixed; background: #ffffff; border-radius: 4px; box-shadow: 0 0 10px rgba(0, 0, 0, 0.04)\">  \r\n	<tbody>\r\n		<tr>                        \r\n			<td style=\"background:#fff;padding:20px 0 10px; text-align:center;\">                            \r\n				<h4 style=\"font-weight:normal; text-transform:uppercase; color:#999;margin:0; padding:10px 0; font-size:18px;\">Changed</h4>                            \r\n				<h2 style=\"margin:0; font-size:34px; padding:0;\">Blog Contribution Status</h2></td>                    \r\n		</tr>    \r\n		<tr>                        \r\n			<td style=\"background:#fff;padding:0 30px; text-align:center; color:#999;vertical-align:top;\">                            \r\n				<table width=\"100%\" border=\"0\" align=\"center\" cellpadding=\"0\" cellspacing=\"0\">                                \r\n					<tbody>                                    \r\n						<tr>                                        \r\n							<td style=\"padding:20px 0 30px;\"><strong style=\"font-size:18px;color:#333;\">Dear {user_full_name}</strong><br />\r\n								Your blog contribution (posted on {posted_on_datetime}) status has been changed to {new_status} at <a href=\"{website_url}\">{website_name}</a>.<br />\r\n								</td>                                    \r\n						</tr>                                    \r\n					</tbody>                            \r\n				</table></td>                    \r\n		</tr> \r\n	</tbody>\r\n</table>', '{user_full_name} Name of the email receiver<br/> \r\n{new_status} New/Current Order Status<br/>\r\n{posted_on_datetime} - Contribution Posted on date time.<br/>\r\n{website_name} Name of our website<br>\r\n{website_url} URL of our website<br>\r\n{social_media_icons} <br>\r\n{contact_us_url} <br>\r\n', 1),
('buyer_notification_review_order_product', 1, 'Buyer Review Order product - Notification', 'Review you order at {website_name}', '\r\n<table width=\"600px\" cellspacing=\"0\" cellpadding=\"0\" style=\"margin: 0 auto; table-layout: fixed; background: #ffffff; border-radius: 4px; box-shadow: 0 0 10px rgba(0, 0, 0, 0.04)\">  \r\n	<tbody>\r\n		<tr>                        \r\n			<td style=\"background:#fff;padding:0 30px; text-align:center; color:#999;vertical-align:top;\">                            \r\n				<table width=\"100%\" border=\"0\" align=\"center\" cellpadding=\"0\" cellspacing=\"0\">                                \r\n					<tbody> \r\n						<tr>                        \r\n							<td style=\"background:#fff;padding:20px 0 10px; text-align:center;\">                            \r\n								<h2 style=\"margin:0; font-size:34px; padding:0;\">Order feedback survey</h2></td>                    \r\n						</tr>    \r\n						<tr>                                        \r\n							<td style=\"padding:20px 0 30px;\"><strong style=\"font-size:18px;color:#333;\">Dear {user_full_name}</strong><br />\r\n								  Thanks for shoppint ( Order Invoice Number {invoice_number}) with <a href=\"{website_url}\">{website_name}</a>. Please feedback your experience to this order  <a href=\"{review_page_url}\" style=\"color:#ff3a59;\">Click Here</a>  </td>                                    \r\n						</tr>                                    \r\n						<tr>                                        \r\n							<td style=\"padding:5px 0 30px;\">{order_items_table_format}</td>                                    \r\n						</tr>                                    \r\n					</tbody>                            \r\n				</table></td>                    \r\n		</tr>\r\n	</tbody>\r\n</table>', '{user_full_name} Name of the email receiver<br/> \r\n{new_order_status} New/Current Order Status<br/>\r\n{invoice_number} - Child Order Invoice Number.<br/>\r\n{order_items_table_format} - Child Order Items in Tabular Format.<br/>\r\n{website_name} Name of our website<br>\r\n{website_url} URL of our website<br>\r\n{social_media_icons} <br>\r\n{contact_us_url} <br>\r\n', 1),
('buyer_notification_review_status_updated', 1, 'Buyer Product Review Status Change - Notification', 'Product Review Status Changed at {website_name}', '\r\n<table width=\"600px\" cellspacing=\"0\" cellpadding=\"0\" style=\"margin: 0 auto; table-layout: fixed; background: #ffffff; border-radius: 4px; box-shadow: 0 0 10px rgba(0, 0, 0, 0.04)\">  \r\n	<tbody>\r\n		<tr>                        \r\n			<td style=\"background:#fff;padding:0 30px; text-align:center; color:#999;vertical-align:top;\">                            \r\n				<table width=\"100%\" border=\"0\" align=\"center\" cellpadding=\"0\" cellspacing=\"0\">                                \r\n					<tbody>   \r\n						<tr>                        \r\n							<td style=\"background:#fff;padding:20px 0 10px; text-align:center;\">                            \r\n								<h4 style=\"font-weight:normal; text-transform:uppercase; color:#999;margin:0; padding:10px 0; font-size:18px;\">Changed</h4>                            \r\n								<h2 style=\"margin:0; font-size:34px; padding:0;\">Review Status</h2></td>                    \r\n						</tr>   \r\n						<tr>                                        \r\n							<td style=\"padding:20px 0 30px;\"><strong style=\"font-size:18px;color:#333;\">Dear {user_full_name}</strong><br />\r\n								Your Review status has been changed to {new_status} at <a href=\"{website_url}\">{website_name}</a>.<br />\r\n								</td>                                    \r\n						</tr>                                    \r\n					</tbody>                            \r\n				</table></td>                    \r\n		</tr>         \r\n	</tbody>\r\n</table>', '{user_full_name} Name of the email receiver<br/> \r\n{new_status} New/Current Review Status<br/>\r\n{website_name} Name of our website<br>\r\n{website_url} URL of our website<br>\r\n{social_media_icons} <br>\r\n{contact_us_url} <br>\r\n', 1),
('cancellation_request_approved_declined', 1, 'Cancellation Request Approved/Declined Email for User', 'Order Cancellation Request {request_status} on {website_name}', '\r\n<table width=\"600px\" cellspacing=\"0\" cellpadding=\"0\" style=\"margin: 0 auto; table-layout: fixed; background: #ffffff; border-radius: 4px; box-shadow: 0 0 10px rgba(0, 0, 0, 0.04)\">\r\n	<tbody>\r\n		<tr>                        \r\n			<td style=\"background:#fff;padding:20px 0 10px; text-align:center;\">                            \r\n				<h4 style=\"font-weight:normal; text-transform:uppercase; color:#999;margin:0; padding:10px 0; font-size:18px;\">Updated</h4>                            \r\n				<h2 style=\"margin:0; font-size:34px; padding:0;\">Order Cancellation Request</h2></td>                    \r\n		</tr> \r\n		<tr>                        \r\n			<td style=\"background:#fff;padding:0 30px; text-align:center; color:#999;vertical-align:top;\">                            \r\n				<table width=\"100%\" border=\"0\" align=\"center\" cellpadding=\"0\" cellspacing=\"0\">                                \r\n					<tbody>                                    \r\n						<tr>                                        \r\n							<td style=\"padding:20px 0 30px;\"><strong style=\"font-size:18px;color:#333;\">Dear {user_name}</strong><br />\r\n								Your order cancellation request on {invoice_number} has been {request_status} on <a href=\"{website_url}\">{website_name}</a>.</td>  \r\n						</tr>                                \r\n					</tbody>                            \r\n				</table></td>                    \r\n		</tr>\r\n	</tbody>\r\n</table>', '{user_name} Name of the email receiver<br />\r\n{invoice_number} Order Invoice Number<br />\r\n{request_status} New Withdrawal Request Status<br />\r\n{website_name} Name of the website<br>\r\n{social_media_icons} <br>\r\n{contact_us_url} <br>', 1),
('cancel_subscription_email', 1, 'Cancel Subscription Email', 'Cancel Subscription Email', '\r\n<table width=\"600px\" cellspacing=\"0\" cellpadding=\"0\" style=\"margin: 0 auto; table-layout: fixed; background: #ffffff; border-radius: 4px; box-shadow: 0 0 10px rgba(0, 0, 0, 0.04)\">\r\n	<tbody>\r\n		<tr>                        \r\n			<td style=\"background:#fff;padding:20px 0 30px; text-align:center;\">                            \r\n				<h4 style=\"font-weight:normal; text-transform:uppercase; color:#999;margin:0; padding:10px 0; font-size:18px;\"><br />\r\n					</h4>                            \r\n				<h2 style=\"margin:0; font-size:34px; padding:0;\">Cancel Subscription!</h2></td>                    \r\n		</tr>                      \r\n		<tr>                        \r\n			<td style=\"background:#fff;padding:0 30px; text-align:center; color:#999;vertical-align:top;\">                            \r\n				<table width=\"100%\" border=\"0\" align=\"center\" cellpadding=\"0\" cellspacing=\"0\">                                \r\n					<tbody>                                    \r\n						<tr>                                        \r\n							<td style=\"padding:20px 0 30px;\"><strong style=\"font-size:18px;color:#333;\">Dear {user_full_name} </strong><br />\r\n								your &nbsp;{spackage_name}<span style=\"color: rgb(149, 149, 149); font-family: \" open=\"\" sans\",=\"\" sans-serif;=\"\" font-size:=\"\" 13px;=\"\" background-color:=\"\" rgb(255,=\"\" 255,=\"\" 255);\"=\"\"> plan has been canceled.</span></td>                                    \r\n						</tr>                                \r\n					</tbody>                            \r\n				</table></td>                    \r\n		</tr>\r\n	</tbody>\r\n</table>', '{user_full_name} Name of the email receiver<br>\r\n{website_name} Name of our website<br>\r\n{website_url} URL of our website<br>\r\n{reset_url} URL to reset the password<br>\r\n{spackage_name} Package name <br>\r\n', 1),
('catalog_request_message_user', 1, 'Catalog request message notification', 'New message received on catalog request at {website_name}', '\r\n<table width=\"600px\" cellspacing=\"0\" cellpadding=\"0\" style=\"margin: 0 auto; table-layout: fixed; background: #ffffff; border-radius: 4px; box-shadow: 0 0 10px rgba(0, 0, 0, 0.04)\">\r\n	<tbody>\r\n		<tr>                        \r\n			<td style=\"background:#fff;padding:0 30px; text-align:center; color:#999;vertical-align:top;\">                            \r\n				<table width=\"100%\" border=\"0\" align=\"center\" cellpadding=\"0\" cellspacing=\"0\">                                \r\n					<tbody>\r\n						<tr>                        \r\n							<td style=\"background:#fff;padding:20px 0 10px; text-align:center;\">                            \r\n								<h4 style=\"font-weight:normal; text-transform:uppercase; color:#999;margin:0; padding:10px 0; font-size:18px;\"></h4>                            \r\n								<h2 style=\"margin:0; font-size:34px; padding:0;\">Message Posted</h2></td>\r\n						</tr>   \r\n						<tr>                                        \r\n							<td style=\"padding:20px 0 30px;\"><strong style=\"font-size:18px;color:#333;\">Dear {user_full_name}</strong><br />\r\n								{username} has posted a message on catalog request at <a href=\"{website_url}\">{website_name}</a><br />\r\n								Message is given as below:</td>                                    \r\n						</tr>                                    \r\n						<tr>                                        \r\n							<td style=\"padding:0 0 30px;\">{message}</td>                                    \r\n						</tr>                                    \r\n						<tr>                                        \r\n							<td style=\"padding:0 0 30px;\">Please {click_here} to reply to this message.</td>                                    \r\n						</tr>                                    \r\n					</tbody>                            \r\n				</table></td>                    \r\n		</tr>\r\n	</tbody>\r\n</table>', '{user_full_name} - Name of the email receiver<br/>\n{username} username of the person posted a message.<br />\n{request_number} Request number on which message is posted.<br />\n{message} message body/comments sent by the sender<br />\n{click_here} Link to reply to the message <br />\n{social_media_icons} <br>\n{contact_us_url} <br>', 1),
('child_order_status_change', 1, 'Child Order Status Change - Notification', 'Order Item Status Changed at {website_name}', '\r\n<table width=\"600px\" cellspacing=\"0\" cellpadding=\"0\" style=\"margin: 0 auto; table-layout: fixed; background: #ffffff; border-radius: 4px; box-shadow: 0 0 10px rgba(0, 0, 0, 0.04)\">\r\n	<tbody>\r\n		<tr>                        \r\n			<td style=\"background:#fff;padding:0 30px; text-align:center; color:#999;vertical-align:top;\">                            \r\n				<table width=\"100%\" border=\"0\" align=\"center\" cellpadding=\"0\" cellspacing=\"0\">                                \r\n					<tbody>    \r\n						<tr>                        \r\n							<td style=\"background:#fff;padding:20px 0 10px; text-align:center;\">                            \r\n								<h4 style=\"font-weight:normal; text-transform:uppercase; color:#999;margin:0; padding:10px 0; font-size:18px;\">Changed</h4>                            \r\n								<h2 style=\"margin:0; font-size:34px; padding:0;\">Order Item Status</h2></td>                    \r\n						</tr>\r\n						<tr>                                        \r\n							<td style=\"padding:20px 0 30px;\"><strong style=\"font-size:18px;color:#333;\">Dear {user_full_name}</strong><br />\r\n								Your order item status has been changed to {new_order_status} corresponding to Order Invoice Number {invoice_number}. at <a href=\"{website_url}\">{website_name}</a>.<br />\r\n								Details are given below:</td>                                    \r\n						</tr>                                    \r\n						<tr>                                        \r\n							<td style=\"padding:5px 0 30px;\">{shipment_information}</td>                                    \r\n						</tr>                                    \r\n						<tr>                                        \r\n							<td style=\"padding:5px 0 30px;\">{order_items_table_format}</td>                                    \r\n						</tr>                                    \r\n						<tr>                                        \r\n							<td style=\"padding:5px 0 30px;\">{order_admin_comments}</td>                                    \r\n						</tr>                                    \r\n					</tbody>                            \r\n				</table></td>                    \r\n		</tr>\r\n	</tbody>\r\n</table>', '{user_full_name} Name of the email receiver<br/> \n{new_order_status} New/Current Order Status<br/>\n{invoice_number} - Child Order Invoice Number.<br/>\n{order_items_table_format} - Child Order Items in Tabular Format.<br/>\n{website_name} Name of our website<br>\n{website_url} URL of our website<br>\n{social_media_icons} <br>\n{contact_us_url} <br>\n', 1),
('COD_OTP_VERIFICATION', 1, 'COD OTP Verification', 'COD OTP Verification', '\r\n<table width=\"600px\" cellspacing=\"0\" cellpadding=\"0\" style=\"margin: 0 auto; table-layout: fixed; background: #ffffff; border-radius: 4px; box-shadow: 0 0 10px rgba(0, 0, 0, 0.04)\">\r\n	<tbody>\r\n		<tr>                        \r\n			<td style=\"background:#fff;padding:20px 0 10px; text-align:center;\">                            \r\n				<h4 style=\"font-weight:normal; text-transform:uppercase; color:#999;margin:0; padding:10px 0; font-size:18px;\"></h4>\r\n				<h2 style=\"margin:0; font-size:34px; padding:0;\">COD OTP Verification</h2>                        </td>                    \r\n		</tr>          \r\n		<tr>                        \r\n			<td style=\"background:#fff;padding:0 30px; text-align:center; color:#999;vertical-align:top;\">                            \r\n				<table width=\"100%\" border=\"0\" align=\"center\" cellpadding=\"0\" cellspacing=\"0\">                                \r\n					<tbody>                                    \r\n						<tr>                                        \r\n							<td style=\"padding:20px 0 30px;\"><strong style=\"font-size:18px;color:#333;\">Dear {user_name}</strong><br />\r\n								{OTP} is the OTP for cash on delivery order verification.<br />\r\n								<a href=\"{website_url}\">{website_name}</a></td>                                    \r\n						</tr>                                \r\n					</tbody>                            \r\n				</table></td>\r\n		</tr>       \r\n	</tbody>\r\n</table>', '{user_name} Name of the email receiver.<br>\r\n{OTP} - One Time Password<br>\r\n{website_name} - Name of the website.\r\n{social_media_icons} <br>\r\n{contact_us_url} <br>', 1);
INSERT IGNORE INTO `tbl_email_templates` (`etpl_code`, `etpl_lang_id`, `etpl_name`, `etpl_subject`, `etpl_body`, `etpl_replacements`, `etpl_status`) VALUES
('contact_us', 1, 'Contact-Us', 'Contact Us Form Submitted on {website_name}', '\r\n<table width=\"600px\" cellspacing=\"0\" cellpadding=\"0\" style=\"margin: 0 auto; table-layout: fixed; background: #ffffff; border-radius: 4px; box-shadow: 0 0 10px rgba(0, 0, 0, 0.04)\">\r\n	<tbody>\r\n		<tr>                        \r\n			<td style=\"background:#fff;padding:20px 0 10px; text-align:center;\">                            \r\n				<h4 style=\"font-weight:normal; text-transform:uppercase; color:#999;margin:0; padding:10px 0; font-size:18px;\"></h4>                            \r\n				<h2 style=\"margin:0; font-size:34px; padding:0;\">Contact Us Data</h2></td>                    \r\n		</tr>   \r\n		<tr>                        \r\n			<td style=\"background:#fff;padding:0 30px; text-align:center; color:#999;vertical-align:top;\">                            \r\n				<table width=\"100%\" border=\"0\" align=\"center\" cellpadding=\"0\" cellspacing=\"0\">                                \r\n					<tbody>                                    \r\n						<tr>                                        \r\n							<td style=\"padding:20px 0 30px;\"><strong style=\"font-size:18px;color:#333;\">Dear Admin </strong><br />\r\n								{name} has submitted the contact us form on <a href=\"{website_url}\">{website_name}</a>.</td>                                    \r\n						</tr>                                    \r\n						<tr>                                        \r\n							<td style=\"padding:20px 0 30px;\">                                            \r\n								<table style=\"border:1px solid #ddd; border-collapse:collapse;\" cellspacing=\"0\" cellpadding=\"0\" border=\"0\">                                                \r\n									<tbody>                                                    \r\n										<tr>                                                        \r\n											<td style=\"padding:10px;font-size:13px;border:1px solid #ddd; color:#333; font-weight:bold;\" width=\"153\">Name</td>                                                        \r\n											<td style=\"padding:10px;font-size:13px; color:#333;border:1px solid #ddd;\" width=\"620\">{name}</td>                                                    \r\n										</tr>                                                        \r\n										<tr>                                                        \r\n											<td style=\"padding:10px;font-size:13px;border:1px solid #ddd; color:#333; font-weight:bold;\" width=\"153\">Email Address<span class=\"Apple-tab-span\" style=\"white-space:pre\"></span></td>                                                        \r\n											<td style=\"padding:10px;font-size:13px; color:#333;border:1px solid #ddd;\" width=\"620\">{email_address}</td>                                                    \r\n										</tr>                                                        \r\n										<tr>                                                        \r\n											<td style=\"padding:10px;font-size:13px;border:1px solid #ddd; color:#333; font-weight:bold;\" width=\"153\">Phone Number</td>                                                        \r\n											<td style=\"padding:10px;font-size:13px; color:#333;border:1px solid #ddd;\" width=\"620\">{phone_number}</td>                                                    \r\n										</tr> \r\n										<tr>                                                        \r\n											<td style=\"padding:10px;font-size:13px;border:1px solid #ddd; color:#333; font-weight:bold;\" width=\"153\">Message</td>                                                        \r\n											<td style=\"padding:10px;font-size:13px; color:#333;border:1px solid #ddd;\" width=\"620\">{message}</td>                                                    \r\n										</tr>   \r\n									</tbody>                                            \r\n								</table></td>                                    \r\n						</tr>                                   \r\n					</tbody>                            \r\n				</table></td>                    \r\n		</tr> \r\n	</tbody>\r\n</table>', '{name} Name of the person who has submitted the contact form<br />\r\n{email_address} Email Address of the sender<br />\r\n{phone_number} Phone Number of the sender<br />\r\n{message} Additional message sent by sender\r\n{social_media_icons} <br>\r\n{contact_us_url} <br>', 1),
('customer_digital_order_email', 1, 'Customer Digital Order Email - Notification', 'Digital Order Details from {website_name}', '\r\n<table width=\"600px\" cellspacing=\"0\" cellpadding=\"0\" style=\"margin: 0 auto; table-layout: fixed; background: #ffffff; border-radius: 4px; box-shadow: 0 0 10px rgba(0, 0, 0, 0.04)\">\r\n	<tbody>\r\n		<tr>                        \r\n			<td style=\"background:#fff;padding:20px 0 10px; text-align:center;\">                            \r\n				<h4 style=\"font-weight:normal; text-transform:uppercase; color:#999;margin:0; padding:10px 0; font-size:18px;\"></h4>                            \r\n				<h2 style=\"margin:0; font-size:34px; padding:0;\">Order Placed</h2></td>                    \r\n		</tr>  \r\n		<tr>                        \r\n			<td style=\"background:#fff;padding:0 30px; text-align:center; color:#999;vertical-align:top;\">                            \r\n				<table cellspacing=\"0\" cellpadding=\"0\" align=\"center\" border=\"0\" width=\"100%\">                                \r\n					<tbody>  \r\n						<tr>                                        \r\n							<td style=\"padding:20px 0 30px;\"><strong style=\"font-size:18px;color:#333;\">Dear {user_full_name} </strong><br />\r\n								Thanks for placing a digital order on <a href=\"{website_url}\">{website_name}</a>. Your order has been received and will be processed and Seller will send the download link once payment has been confirmed.<br />\r\n								Your order information is given below.</td>                                    \r\n						</tr>                                    \r\n						<tr>                                        \r\n							<td style=\"padding:0 0 30px;\">{order_items_table_format}</td>                                    \r\n						</tr>                                    \r\n					</tbody>                            \r\n				</table></td>                    \r\n		</tr>\r\n	</tbody>\r\n</table> ', '{user_full_name} - Name of the email receiver.<br/>\r\n{order_invoice_number} - Invoice Number of the order.<br/>\r\n{website_name} Name of our website<br>\r\n{website_url} URL of our website<br>\r\n{order_items_table_format} Order Item Summary in Tabular Format.<br>\r\n{social_media_icons} <br>\r\n{contact_us_url} <br>', 1),
('customer_order_email', 1, 'Customer Order Email - Notification', 'Order Details from {website_name}', '\r\n<table width=\"600px\" cellspacing=\"0\" cellpadding=\"0\" style=\"margin: 0 auto; table-layout: fixed; background: #ffffff; border-radius: 4px; box-shadow: 0 0 10px rgba(0, 0, 0, 0.04)\">\r\n	<tbody>\r\n		<tr>                        \r\n			<td style=\"background:#fff;padding:20px 0 10px; text-align:center;\">                            \r\n				<h4 style=\"font-weight:normal; text-transform:uppercase; color:#999;margin:0; padding:10px 0; font-size:18px;\"></h4>                            \r\n				<h2 style=\"margin:0; font-size:34px; padding:0;\">Order Placed</h2></td>                    \r\n		</tr>                     \r\n		<tr>                        \r\n			<td style=\"background:#fff;padding:0 30px; text-align:center; color:#999;vertical-align:top;\">                            \r\n				<table width=\"100%\" border=\"0\" align=\"center\" cellpadding=\"0\" cellspacing=\"0\">                                \r\n					<tbody>                                    \r\n						<tr>                                        \r\n							<td style=\"padding:20px 0 30px;\"><strong style=\"font-size:18px;color:#333;\">Dear {user_full_name} </strong><br />\r\n								Thanks for placing an order on <a href=\"{website_url}\">{website_name}</a>. Your order has been received and will be processed once payment has been confirmed.<br />\r\n								Your order information is give below.</td>                                    \r\n						</tr>                                    \r\n						<tr>                                        \r\n							<td style=\"padding:0 0 30px;\">{order_products_table_format}</td>                                    \r\n						</tr>                                    \r\n					</tbody>                            \r\n				</table></td>                    \r\n		</tr> \r\n	</tbody>\r\n</table>', '{user_full_name} - Name of the email receiver.<br/>\n{order_invoice_number} - Invoice Number of the order.<br/>\n{website_name} Name of our website<br>\n{website_url} URL of our website<br>\n{order_products_table_format} Order Products Summary in Tabular Format.<br>\n{social_media_icons} <br>\n{contact_us_url} <br>', 1),
('data_request_notification_to_admin', 1, 'Data request notification to admin', 'Request Data', '\r\n<table width=\"600px\" cellspacing=\"0\" cellpadding=\"0\" style=\"margin: 0 auto; table-layout: fixed; background: #ffffff; border-radius: 4px; box-shadow: 0 0 10px rgba(0, 0, 0, 0.04)\">\r\n	<tbody>\r\n		<tr>                        \r\n			<td style=\"background:#fff;padding:20px 0 10px; text-align:center;\">                            \r\n				<h4 style=\"font-weight:normal; text-transform:uppercase; color:#999;margin:0; padding:10px 0; font-size:18px;\">Updated</h4>                            \r\n				<h2 style=\"margin:0; font-size:34px; padding:0;\">Data Request</h2></td>                    \r\n		</tr>                    \r\n		<tr>                        \r\n			<td style=\"background:#fff;padding:0 30px; text-align:center; color:#999;vertical-align:top;\">                            \r\n				<table width=\"100%\" border=\"0\" align=\"center\" cellpadding=\"0\" cellspacing=\"0\">                                \r\n					<tbody>                                    \r\n						<tr>                                        \r\n							<td style=\"padding:20px 0 30px;\"><strong style=\"font-size:18px;color:#333;\">Dear Admin</strong><br />\r\n								\r\n								<div>Data request has been placed by {user_full_name}</div>                                            \r\n								<div>Phone Number: {user_phone}</div>                                            \r\n								<div>Username: {username}</div>                                            \r\n								<div>Purpose of request:</div>                                            \r\n								<div><span style=\"color: rgb(153, 153, 153); font-family: Arial; text-align: center; background-color: rgb(255, 255, 255);\">{ureq_purpose}</span><br />\r\n									</div></td>                                    \r\n						</tr>                                    \r\n					</tbody>                            \r\n				</table></td>                 