('dummy_template', 1, 'Dummy Template', 'Dummy Template (responsive testing 001)', '\r\n<h1 style=\"font-size: 40px; letter-spacing: -0.4px; margin: 0 0 30px 0; font-weight: 700; color: #212529\">You have a New Message</h1>        \r\n<h5 style=\"font-size: 16px; font-weight: 600; line-height: 1.5; letter-spacing: -0.32px; color: #212529; margin: 0 0 10px 0\">Hello {User}</h5>        \r\n<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">You have received a message from {Buyer_Username} on the following product</p>        \r\n<table width=\"600px\" cellspacing=\"0\" cellpadding=\"0\" style=\"background: #f6f6f6; padding: 10px 20px; border-radius: 4px\">            \r\n	<tbody>                \r\n		<tr>                    \r\n			<td style=\"vertical-align: middle; width: 70px; padding: 15px 0\"> <a href=\"javascript:void(0);\" style=\"width: 50px; height: 50px; background: #ffffff; display: block; border: 1px solid rgba(112, 112, 112, 0.2)\"><img src=\"./p1.png\" alt=\"product-image\" /></a> </td>                    \r\n			<td style=\"vertical-align: middle; padding: 15px 0\"> <a href=\"http://sv-fashion.designer.4livedemo.com/email/order-confirmation-email-2.html#\" style=\"color: #212529; font-size: 14px; line-height: 24px; letter-spacing: -0.2px; text-decoration: none\">Hair\r\n                            Drier (Black) X 1</a> </td>                    \r\n			<td style=\"font-size: 14px; line-height: 24px; letter-spacing: -0.2px; color: #212529; text-align: right; vertical-align: middle; padding: 15px 0\">                        $250\r\n                    </td>                \r\n		</tr>            \r\n	</tbody>        \r\n</table>        \r\n<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 20px 0 20px 0\">            \r\n	Go to your inbox {Embed_link} to read the message.</p>        \r\n<p style=\"font-size: 14px; line-height: 1.71; letter-spacing: -0.28px; color: #212529; margin: 0\">Thank You,<br />\r\n	Team {Website}</p>', '', 1),
('failed_login_attempt', 1, 'Failed Login Attempt', 'Failed Login Attempt', '\r\n<table width=\"600px\" cellspacing=\"0\" cellpadding=\"0\" style=\"margin: 0 auto; table-layout: fixed; background: #ffffff; border-radius: 4px; box-shadow: 0 0 10px rgba(0, 0, 0, 0.04)\">\r\n	<tbody>\r\n		<tr>\r\n			<td style=\"background:#fff;padding:20px 0 10px; text-align:center;\">\r\n				<h4 style=\"font-weight:normal; text-transform:uppercase; color:#999;margin:0; padding:10px 0; font-size:18px;\"></h4>\r\n				<h2 style=\"margin:0; font-size:34px; padding:0;\"><a href=\"http://yokart-v8-1.staging.4demo.biz/admin/%7Bwebsite_url%7D\" style=\"font-family: Arial; text-align: center; background-color: rgb(255, 255, 255);\"></a><a href=\"http://yokart-v8-1.staging.4demo.biz/admin/%7Bwebsite_url%7D\" style=\"font-family: Arial; text-align: center; background-color: rgb(255, 255, 255);\">{website_name}</a></h2></td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"background:#fff;padding:0 30px; text-align:center; color:#999;vertical-align:top;\">\r\n				<table width=\"100%\" border=\"0\" align=\"center\" cellpadding=\"0\" cellspacing=\"0\">\r\n					<tbody>\r\n						<tr>\r\n							<td style=\"padding:20px 0;\"><strong style=\"font-size:18px;color:#333;\">Dear {user_full_name} </strong><br />\r\n								Are you facing problem logging in?</td>\r\n						</tr>\r\n						<tr>\r\n							<td style=\"padding:0px 0px 20px;\">\r\n								<p>You seem to be facing problem logging in at <a href=\"{website_url}\">{website_name}</a><br />\r\n									Please note that your username and password are both case sensitive.<br />\r\n									You can use forgot password feature if you have lost your password.<br />\r\n									If you were not trying logging in, it might be a hacking attempt.<br />\r\n									Also, you should keep your email password secured.<br />\r\n									</p></td>\r\n						</tr>\r\n					</tbody>\r\n				</table></td>\r\n		</tr>       \r\n	</tbody>\r\n</table>', '', 1),
('forgot_password', 1, 'Forgot Password Email', 'Reset Password Email', '\r\n<table width=\"600px\" cellspacing=\"0\" cellpadding=\"0\" style=\"margin: 0 auto; table-layout: fixed; background: #ffffff; border-radius: 4px; box-shadow: 0 0 10px rgba(0, 0, 0, 0.04)\">\r\n	<tbody>\r\n		<tr>\r\n			<td style=\"background:#fff;padding:20px 0 10px; text-align:center;\">\r\n				<h4 style=\"font-weight:normal; text-transform:uppercase; color:#999;margin:0; padding:10px 0; font-size:18px;\"></h4>\r\n				<h2 style=\"margin:0; font-size:34px; padding:0;\">Reset Password!</h2></td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"background:#fff;padding:0 30px; text-align:center; color:#999;vertical-align:top;\">\r\n				<table width=\"100%\" border=\"0\" align=\"center\" cellpadding=\"0\" cellspacing=\"0\">\r\n					<tbody>\r\n						<tr>\r\n							<td style=\"padding:20px 0 30px;\"><strong style=\"font-size:18px;color:#333;\">Dear {user_full_name} </strong><br />\r\n								It seems that you have used reset password option at <a href=\"{website_url}\">{website_name}</a>.</td>\r\n						</tr>\r\n						<tr>\r\n							<td style=\"padding:20px 0 30px;\">Please visit the link given below to reset your password. Please note that the link is valid for next 24 hours only.<br />\r\n								Password reset url: <a href=\"{reset_url}\">{reset_url}</a>.</td>\r\n						</tr>\r\n					</tbody>\r\n				</table></td>\r\n		</tr>\r\n	</tbody>\r\n</table>', '{user_full_name} Name of the email receiver<br>\r\n{website_name} Name of our website<br>\r\n{website_url} URL of our website<br>\r\n{reset_url} URL to reset the password<br>\r\n{social_media_icons} <br>\r\n{contact_us_url} <br>', 1),
('gdpr_request_status_update_notification_to_user', 1, 'GDPR request status update notification to user', 'GDPR Request Status Updated', '\r\n<table width=\"600px\" cellspacing=\"0\" cellpadding=\"0\" style=\"margin: 0 auto; table-layout: fixed; background: #ffffff; border-radius: 4px; box-shadow: 0 0 10px rgba(0, 0, 0, 0.04)\">\r\n	<tbody>\r\n		<tr>\r\n			<td style=\"background:#fff;padding:20px 0 10px; text-align:center;\">\r\n				<h4 style=\"font-weight:normal; text-transform:uppercase; color:#999;margin:0; padding:10px 0; font-size:18px;\">Updated</h4>\r\n				<h2 style=\"margin:0; font-size:34px; padding:0;\">Request Status Update</h2></td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"background:#fff;padding:0 30px; text-align:center; color:#999;vertical-align:top;\">\r\n				<table width=\"100%\" border=\"0\" align=\"center\" cellpadding=\"0\" cellspacing=\"0\">\r\n					<tbody>\r\n						<tr>\r\n							<td style=\"padding:20px 0 30px;\"><strong style=\"font-size:18px;color:#333;\">Dear <span style=\"color: rgb(153, 153, 153); font-family: Arial; text-align: center; background-color: rgb(255, 255, 255);\">{username}</span></strong>\r\n								<div>Your Request for {request_type} has been completed.</div></td>\r\n						</tr>\r\n					</tbody>\r\n				</table></td>\r\n		</tr>\r\n	</tbody>\r\n</table>', '{username} Username\r\n{request_type} Request Type', 1),
('guest_welcome_registration', 1, 'Welcome Mail on Registration', 'Welcome to {website_name}', '\r\n<table width=\"600px\" cellspacing=\"0\" cellpadding=\"0\" style=\"margin: 0 auto; table-layout: fixed; background: #ffffff; border-radius: 4px; box-shadow: 0 0 10px rgba(0, 0, 0, 0.04)\">\r\n	<tbody>\r\n		<tr>                        \r\n			<td style=\"background:#fff;padding:20px 0 10px; text-align:center;\">                            \r\n				<h4 style=\"font-weight:normal; text-transform:uppercase; color:#999;margin:0; padding:10px 0; font-size:18px;\">Congratulations</h4>                            \r\n				<h2 style=\"margin:0; font-size:34px; padding:0;\">Account Created!</h2></td>                    \r\n		</tr>\r\n		<tr>                        \r\n			<td style=\"background:#fff;padding:0 30px; text-align:center; color:#999;vertical-align:top;\">                            \r\n				<table width=\"100%\" border=\"0\" align=\"center\" cellpadding=\"0\" cellspacing=\"0\">                                \r\n					<tbody>                                    \r\n						<tr>                                        \r\n							<td style=\"padding:20px 0 30px;\"><strong style=\"font-size:18px;color:#333;\">Dear {name} </strong><br />\r\n								Your email has been registered. Next time you shop with us, log in for faster checkout at <a href=\"{website_url}\">{website_name}</a>.</td>                                    \r\n						</tr>                                    \r\n						<tr>                                        \r\n							<td style=\"padding:20px 0 30px;\">We are thrilled to have you aboard! You have taken a great first step and we are so excited to connect directly with you.</td>                                    \r\n						</tr>                                    \r\n						<tr>                                        \r\n							<td style=\"padding:0 0 30px;\">If you require any assistance in using our site, or have any feedback or suggestions, you can email us at {contact_us_email}</td>                                    \r\n						</tr>                                    \r\n					</tbody>                            \r\n				</table></td>                    \r\n		</tr>\r\n	</tbody>\r\n</table>', '{name} Name of the signed up user.<br>\r\n{email} Email Address of the signed up user.<br>\r\n{username} Username of the signed up User <br/>\r\n{contact_us_email} - Contact Us Email Address<br/>\r\n{website_name} Name of our website<br>\r\n{social_media_icons} <br>\r\n{contact_us_url} <br>\r\n', 1),
('low_balance_promotional_email', 1, 'Low Balance Promotional Email', 'Maintain Wallet to Keep Promtions Working', '\r\n<table width=\"600px\" cellspacing=\"0\" cellpadding=\"0\" style=\"margin: 0 auto; table-layout: fixed; background: #ffffff; border-radius: 4px; box-shadow: 0 0 10px rgba(0, 0, 0, 0.04)\">\r\n	<tbody>\r\n		<tr>\r\n			<td style=\"background:#fff;padding:20px 0 30px; text-align:center;\">\r\n				<h4 style=\"font-weight:normal; text-transform:uppercase; color:#999;margin:0; padding:10px 0; font-size:18px;\"></h4><br />\r\n				\r\n				<h2 style=\"margin:0; font-size:34px; padding:0;\">Low Wallet Balance</h2></td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"background:#fff;padding:0 30px; text-align:center; color:#999;vertical-align:top;\">\r\n				<table width=\"100%\" border=\"0\" align=\"center\" cellpadding=\"0\" cellspacing=\"0\">\r\n					<tbody>\r\n						<tr>\r\n							<td style=\"padding:20px 0 30px;\"><strong style=\"font-size:18px;color:#333;\">Dear {user_name} </strong><br />\r\n								Please maintain your wallet balance to keep Promotions Working.&nbsp;<br />\r\n								Balance required - &nbsp;{requiredBalance}</td>\r\n						</tr>\r\n					</tbody>\r\n				</table></td>\r\n		</tr>\r\n	</tbody>\r\n</table>', '{user_name} Name of the email receiver<br>\n{website_name} Name of our website<br>\n{website_url} URL of our website<br>\n{reset_url} URL to reset the password<br>\n{social_media_icons} <br>\n{contact_us_url} <br>\n{requiredBalance} Balance For promotions Auto debit Required', 1),
