('reminder_for_items_in_cart', 1, 'Reminder for items in Cart', 'Reminder for items in Cart', '\r\n<table width=\"600px\" cellspacing=\"0\" cellpadding=\"0\" style=\"margin: 0 auto; table-layout: fixed; background: #ffffff; border-radius: 4px; box-shadow: 0 0 10px rgba(0, 0, 0, 0.04)\">\r\n	<tbody>\r\n		<tr>                        \r\n			<td style=\"background:#fff;padding:20px 0 10px; text-align:center;\">                            \r\n				<h4 style=\"font-weight:normal; text-transform:uppercase; color:#999;margin:0; padding:10px 0; font-size:18px;\"></h4>                            \r\n				<h2 style=\"margin:0; font-size:34px; padding:0;\"><a href=\"http://yokart-v8-1.staging.4demo.biz/admin/%7Bwebsite_url%7D\" style=\"font-family: Arial; text-align: center; background-color: rgb(255, 255, 255);\"></a><a href=\"http://yokart-v8-1.staging.4demo.biz/admin/%7Bwebsite_url%7D\" style=\"font-family: Arial; text-align: center; background-color: rgb(255, 255, 255);\">{website_name}</a>&nbsp;is missing you!</h2></td>                    \r\n		</tr>\r\n		<tr>                        \r\n			<td style=\"background:#fff;padding:0 30px; text-align:center; color:#999;vertical-align:top;\">                            \r\n				<table width=\"100%\" border=\"0\" align=\"center\" cellpadding=\"0\" cellspacing=\"0\">                                \r\n					<tbody>                                    \r\n						<tr>                                        \r\n							<td style=\"padding:20px 0 30px;\"><strong style=\"font-size:18px;color:#333;\">Dear {user_full_name} </strong><br />\r\n								Thank you for adding products to your cart.</td>                                          \r\n						</tr>                                    \r\n						<tr>                                        \r\n							<td style=\"padding:20px 0 30px;\">{products_in_cart_format}</td>                                    \r\n						</tr>                                    \r\n						<tr>                                        \r\n							<td style=\"padding:20px 0 30px;\">                                            \r\n								<div>Proceed to checkout, before someone else grabs your products</div><br />\r\n								<a href=\"{checkout_url}\" style=\"background-color: #FF3A59;border: none;color: white;padding: 10px 20px;text-align: center;text-decoration: none;display: inline-block;font-size: 16px;margin: 4px 2px;cursor: pointer;\">Click Here</a></td>                                    \r\n						</tr>                                    \r\n					</tbody>                            \r\n				</table></td>                    \r\n		</tr>\r\n	</tbody>\r\n</table>', '', 1),
('reminder_for_items_in_wishlist', 1, 'Reminder for items in wishlist', 'Reminder for items in wishlist', '\r\n<table width=\"600px\" cellspacing=\"0\" cellpadding=\"0\" style=\"margin: 0 auto; table-layout: fixed; background: #ffffff; border-radius: 4px; box-shadow: 0 0 10px rgba(0, 0, 0, 0.04)\">\r\n	<tbody>\r\n		<tr>                        \r\n			<td style=\"background:#fff;padding:20px 0 10px; text-align:center;\">                            \r\n				<h4 style=\"font-weight:normal; text-transform:uppercase; color:#999;margin:0; padding:10px 0; font-size:18px;\"></h4>                            \r\n				<h2 style=\"margin:0; font-size:34px; padding:0;\"><a href=\"http://yokart-v8-1.staging.4demo.biz/admin/%7Bwebsite_url%7D\" style=\"font-family: Arial; text-align: center; background-color: rgb(255, 255, 255);\"></a><a href=\"http://yokart-v8-1.staging.4demo.biz/admin/%7Bwebsite_url%7D\" style=\"font-family: Arial; text-align: center; background-color: rgb(255, 255, 255);\">{website_name}</a>&nbsp;is missing you!</h2></td>                    \r\n		</tr>\r\n		<tr>                        \r\n			<td style=\"background:#fff;padding:0 30px; text-align:center; color:#999;vertical-align:top;\">                            \r\n				<table width=\"100%\" border=\"0\" align=\"center\" cellpadding=\"0\" cellspacing=\"0\">                                \r\n					<tbody>                                    \r\n						<tr>                                        \r\n							<td style=\"padding:20px 0 30px;\"><strong style=\"font-size:18px;color:#333;\">Dear {user_full_name} </strong><br />\r\n								We are glad you liked our products.</td>                                          \r\n						</tr>                                    \r\n						<tr>                                        \r\n							<td style=\"padding:20px 0 30px;\">{products_in_wishlist_format}</td>                                    \r\n						</tr>                                          \r\n						<tr>                                        \r\n							<td style=\"padding:20px 0 30px;\">Kindly check your favorite products by clicking the following link.<br />\r\n								<a href=\"{wishlist_url}\" style=\"background-color: #FF3A59;border: none;color: white;padding: 10px 20px;text-align: center;text-decoration: none;display: inline-block;font-size: 16px;margin: 4px 2px;cursor: pointer;\">Click Here</a></td>                                    \r\n						</tr>                                    \r\n					</tbody>                            \r\n				</table></td>                    \r\n		</tr>\r\n	</tbody>\r\n</table>', '', 1),
('report_shop', 1, 'Report a shop', 'Report submitted on {website_name}', '\r\n<table width=\"600px\" cellspacing=\"0\" cellpadding=\"0\" style=\"margin: 0 auto; table-layout: fixed; background: #ffffff; border-radius: 4px; box-shadow: 0 0 10px rgba(0, 0, 0, 0.04)\">\r\n	<tbody>\r\n		<tr>\r\n			<td style=\"background:#fff;padding:20px 0 10px; text-align:center;\">\r\n				<h4 style=\"font-weight:normal; text-transform:uppercase; color:#999;margin:0; padding:10px 0; font-size:18px;\"></h4>\r\n				<h2 style=\"margin:0; font-size:34px; padding:0;\">Message Posted</h2></td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"background:#fff;padding:0 30px; text-align:center; color:#999;vertical-align:top;\">\r\n				<table width=\"100%\" border=\"0\" align=\"center\" cellpadding=\"0\" cellspacing=\"0\">\r\n					<tbody>\r\n						<tr>\r\n							<td style=\"padding:20px 0 30px;\"><strong style=\"font-size:18px;color:#333;\">Dear Admin</strong><br />\r\n								{username} has reported a shop on <a href=\"{website_url}\">{website_name}</a>.</td>\r\n						</tr>\r\n						<tr>\r\n							<td style=\"font-size:12px; color:#666;\">\r\n								<table style=\"border:1px solid #ddd; border-collapse:collapse;\" cellspacing=\"0\" cellpadding=\"0\" border=\"0\">\r\n									<tbody>\r\n										<tr>\r\n											<td style=\"padding:10px;font-size:13px;border:1px solid #ddd; color:#333; font-weight:bold;\" width=\"109\">Shop</td>\r\n											<td style=\"padding:10px;font-size:13px; color:#333;border:1px solid #ddd;\" width=\"664\">{shop_name}</td>\r\n										</tr>\r\n										<tr>\r\n											<td style=\"padding:10px;font-size:13px;border:1px solid #ddd; color:#333; font-weight:bold;\">Reason</td>\r\n											<td style=\"padding:10px;font-size:13px; color:#333;border:1px solid #ddd;\">{report_reason}</td>\r\n										</tr>\r\n										<tr>\r\n											<td style=\"padding:10px;font-size:13px;border:1px solid #ddd; color:#333; font-weight:bold;\">Message</td>\r\n											<td style=\"padding:10px;font-size:13px; color:#333;border:1px solid #ddd;\">{report_message}</td>\r\n										</tr>\r\n									</tbody>\r\n								</table></td>\r\n						</tr> \r\n					</tbody>\r\n				</table></td>\r\n		</tr>\r\n	</tbody>\r\n</table>', '{username} Username of the person who submitted the Report<br />\r\n{shop_name} Shop Name<br />\r\n{report_reason} Reason for reported<br />\r\n{report_message} Message submitted by the reporter<br>\r\n{social_media_icons} <br>\r\n{contact_us_url} <br>', 1),
('return_request_message_user', 1, 'Return request message notification - for Buyer/Vendor', 'New message received on return request at {website_name}', '\r\n<table width=\"600px\" cellspacing=\"0\" cellpadding=\"0\" style=\"margin: 0 auto; table-layout: fixed; background: #ffffff; border-radius: 4px; box-shadow: 0 0 10px rgba(0, 0, 0, 0.04)\">\r\n	<tbody>\r\n		<tr>\r\n			<td style=\"background:#fff;padding:20px 0 10px; text-align:center;\">\r\n				<h4 style=\"font-weight:normal; text-transform:uppercase; color:#999;margin:0; padding:10px 0; font-size:18px;\"></h4>\r\n				<h2 style=\"margin:0; font-size:34px; padding:0;\">Message Posted</h2></td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"background:#fff;padding:0 30px; text-align:center; color:#999;vertical-align:top;\">\r\n				<table width=\"100%\" border=\"0\" align=\"center\" cellpadding=\"0\" cellspacing=\"0\">\r\n					<tbody>\r\n						<tr>\r\n							<td style=\"padding:20px 0 30px;\"><strong style=\"font-size:18px;color:#333;\">Dear {user_full_name}</strong><br />\r\n								{username} has posted a message on request reference number {request_number} at <a href=\"{website_url}\">{website_name}</a><br />\r\n								Message is given as below:</td>\r\n						</tr>\r\n						<tr>\r\n							<td style=\"padding:0 0 30px;\">{message}</td>\r\n						</tr>\r\n						<tr>\r\n							<td style=\"padding:0 0 30px;\">Please {click_here} to reply to this message.</td>\r\n						</tr>\r\n					</tbody>\r\n				</table></td>\r\n		</tr>\r\n	</tbody>\r\n</table>', '{user_full_name} - Name of the email receiver<br/>\r\n{username} username of the person posted a message.<br />\r\n{request_number} Request number on which message is posted.<br />\r\n{message} message body/comments sent by the sender<br />\r\n{click_here} Link to reply to the message <br />\r\n{social_media_icons} <br>\r\n{contact_us_url} <br>', 1),
('return_request_status_change_notification', 1, 'Return request status change notification', 'Return request status changed on {website_name}', '\r\n<table width=\"600px\" cellspacing=\"0\" cellpadding=\"0\" style=\"margin: 0 auto; table-layout: fixed; background: #ffffff; border-radius: 4px; box-shadow: 0 0 10px rgba(0, 0, 0, 0.04)\">\r\n	<tbody>\r\n		<tr>                        \r\n			<td style=\"background:#fff;padding:20px 0 10px; text-align:center;\">                            \r\n				<h4 style=\"font-weight:normal; text-transform:uppercase; color:#999;margin:0; padding:10px 0; font-size:18px;\">Updated</h4>                            \r\n				<h2 style=\"margin:0; font-size:34px; padding:0;\">Return Request Status</h2></td>                    \r\n		</tr> \r\n		<tr>                        \r\n			<td style=\"background:#fff;padding:0 30px; text-align:center; color:#999;vertical-align:top;\">                            \r\n				<table width=\"100%\" border=\"0\" align=\"center\" cellpadding=\"0\" cellspacing=\"0\">                                \r\n					<tbody>                                    \r\n						<tr>                                        \r\n							<td style=\"padding:20px 0 30px;\"><strong style=\"font-size:18px;color:#333;\">Dear {user_full_name}</strong><br />\r\n								{username} has {new_status_name} return request reference number {request_number} on <a href=\"{website_url}\">{website_name}</a>.</td>                                    \r\n						</tr>                                    \r\n					</tbody>                            \r\n				</table></td>                    \r\n		</tr> \r\n	</tbody>\r\n</table>', '{user_full_name} Name of the email receiver<br />\r\n{username} username of the person<br />\r\n{new_status_name} New Status of the Request<br />\r\n{request_number} Request number<br />\r\n{website_name} Name of the website.<br>\r\n{social_media_icons} <br>\r\n{contact_us_url} <br>', 1),
('reward_points_credited_debited', 1, 'Reward Points Received/Debited Email for Buyer/Seller', 'Your account has been {debit_credit_type} reward points on {website_name}', '\r\n<table width=\"600px\" cellspacing=\"0\" cellpadding=\"0\" style=\"margin: 0 auto; table-layout: fixed; background: #ffffff; border-radius: 4px; box-shadow: 0 0 10px rgba(0, 0, 0, 0.04)\">\r\n	<tbody>\r\n		<tr>                        \r\n			<td style=\"background:#fff;padding:20px 0 10px; text-align:center;\">                            \r\n				<h4 style=\"font-weight:normal; text-transform:uppercase; color:#999;margin:0; padding:10px 0; font-size:18px;\"></h4>                            \r\n				<h2 style=\"margin:0; font-size:34px; padding:0;\">Reward Point Transaction</h2></td>                    \r\n		</tr>\r\n		<tr>                        \r\n			<td style=\"background:#fff;padding:0 30px; text-align:center; color:#999;vertical-align:top;\">                            \r\n				<table width=\"100%\" border=\"0\" align=\"center\" cellpadding=\"0\" cellspacing=\"0\">                                \r\n					<tbody>                                    \r\n						<tr>                                        \r\n							<td style=\"padding:20px 0 30px;\"><strong style=\"font-size:18px;color:#333;\">Dear {user_name}</strong><br />\r\n								Your account has been {debit_credit_type} reward points at <a href=\"{website_url}\">{website_name}</a>.. Please find the details below:</td>                                    \r\n						</tr>                                    \r\n						<tr>                                        \r\n							<td style=\"padding:20px 0 30px;\">                                            \r\n								<table style=\"border:1px solid #ddd; border-collapse:collapse;\" cellspacing=\"0\" cellpadding=\"0\" border=\"0\">                                                \r\n									<tbody>                                                    \r\n										<tr>                                                        \r\n											<td style=\"padding:10px;font-size:13px;border:1px solid #ddd; color:#333; font-weight:bold;\" width=\"153\">Points</td>\r\n											<td style=\"padding:10px;font-size:13px; color:#333;border:1px solid #ddd;\" width=\"620\">{reward_points}</td>                                                    \r\n										</tr>                                                        \r\n										<tr>                                                        \r\n											<td style=\"padding:10px;font-size:13px;border:1px solid #ddd; color:#333; font-weight:bold;\" width=\"153\">Comment<span class=\"Apple-tab-span\" style=\"white-space:pre\"></span></td>\r\n											<td style=\"padding:10px;font-size:13px; color:#333;border:1px solid #ddd;\" width=\"620\">{comments}</td>                                                    \r\n										</tr>                                                        \r\n									</tbody>                                            \r\n								</table></td>                                    \r\n						</tr>                                    \r\n					</tbody>                            \r\n				</table></td>                    \r\n		</tr>\r\n	</tbody>\r\n</table>', '{user_name} Name of the email receiver.<br />\n{debit_credit_type} - Credited or Debited<br>\n{reward_points} - Reward Points<br>{comments} - Comments<br>\n{website_name} Name of our website<br>\n{website_url} URL of our website<br>', 1),
('seller_brand_request_admin_email', 1, 'Seller - Brand request', 'New Brand Requested at {website_name}', '\r\n<table width=\"600px\" cellspacing=\"0\" cellpadding=\"0\" style=\"margin: 0 auto; table-layout: fixed; background: #ffffff; border-radius: 4px; box-shadow: 0 0 10px rgba(0, 0, 0, 0.04)\">\r\n	<tbody>\r\n		<tr>\r\n			<td style=\"background:#fff;padding:20px 0 10px; text-align:center;\">\r\n				<h4 style=\"font-weight:normal; text-transform:uppercase; color:#999;margin:0; padding:10px 0; font-size:18px;\"></h4>\r\n				<h2 style=\"margin:0; font-size:34px; padding:0;\">New Brand Request</h2></td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"background:#fff;padding:0 30px; text-align:center; color:#999;vertical-align:top;\">\r\n				<table width=\"100%\" border=\"0\" align=\"center\" cellpadding=\"0\" cellspacing=\"0\">\r\n					<tbody>\r\n						<tr>\r\n							<td style=\"padding:20px 0 30px;\"><strong style=\"font-size:18px;color:#333;\">Dear Admin</strong><br />\r\n								New Brand has been requested by Seller {user_full_name}- {brand_name}</td>\r\n						</tr>\r\n					</tbody>\r\n				</table></td>\r\n		</tr>\r\n	</tbody>\r\n</table>', '{user_full_name} - Name of the email receiver.<br/>\r\n{website_name} Name of our website<br>\r\n{brand_name} Brand Name <br>\r\n\r\n{social_media_icons} <br>\r\n{contact_us_url} <br>', 1),
('seller_brand_request_status_change', 1, 'Seller - Brand request Change Status', 'Your Brand Request {new_request_status} at {website_name}', '\r\n<table width=\"600px\" cellspacing=\"0\" cellpadding=\"0\" style=\"margin: 0 auto; table-layout: fixed; background: #ffffff; border-radius: 4px; box-shadow: 0 0 10px rgba(0, 0, 0, 0.04)\">\r\n	<tbody>\r\n		<tr>\r\n			<td style=\"background:#fff;padding:20px 0 10px; text-align:center;\">\r\n				<h4 style=\"font-weight:normal; text-transform:uppercase; color:#999;margin:0; padding:10px 0; font-size:18px;\">Updated</h4>\r\n				<h2 style=\"margin:0; font-size:34px; padding:0;\">Brand Request -{brand_name}</h2></td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"background:#fff;padding:0 30px; text-align:center; color:#999;vertical-align:top;\">\r\n				<table width=\"100%\" cellspacing=\"0\" cellpadding=\"0\" border=\"0\" align=\"center\">\r\n					<tbody>\r\n						<tr>\r\n							<td style=\"padding:20px 0 30px;\"><strong style=\"font-size:18px;color:#333;\">Dear {shop_name} </strong><br />\r\n								Your brand approval request has been {new_request_status}&nbsp;</td>\r\n						</tr>\r\n						<tr>\r\n							<td style=\"padding:20px 0 30px;\">{brand_request_comments}</td>\r\n						</tr>\r\n					</tbody>\r\n				</table></td>\r\n		</tr>\r\n	</tbody>\r\n</table>', '{shop_name} - Shop Name.<br/>\r\n{website_name} Name of our website<br>\r\n{new_request_status} New Request Status (Approved/Declined) <br>\r\n{brand_request_comments} Added comment on status change<br>\r\n{brand_name} Brand Name (Approved/Declined) <br>\r\n{social_media_icons} <br>\r\n{contact_us_url} <br>', 1),
('seller_catalog_request_status_change', 1, 'Seller - Catalog  Status Change', 'Your Catalog {product_name} {new_status} at {website_name}', '\r\n<table width=\"600px\" cellspacing=\"0\" cellpadding=\"0\" style=\"margin: 0 auto; table-layout: fixed; background: #ffffff; border-radius: 4px; box-shadow: 0 0 10px rgba(0, 0, 0, 0.04)\">\r\n	<tbody>\r\n		<tr>\r\n			<td style=\"background:#fff;padding:20px 0 10px; text-align:center;\">\r\n				<h2 style=\"margin:0; font-size:34px; padding:0;\">Catalog {new_status}</h2></td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"background:#fff;padding:0 30px; text-align:center; color:#999;vertical-align:top;\">\r\n				<table width=\"100%\" border=\"0\" align=\"center\" cellpadding=\"0\" cellspacing=\"0\">\r\n					<tbody>\r\n						<tr>\r\n							<td style=\"padding:20px 0 30px;\"><strong style=\"font-size:18px;color:#333;\">Dear {shop_name} </strong><br />\r\n								Your catalog {product_name} has been {new_status} on {website_name}.</td>\r\n						</tr>\r\n					</tbody>\r\n				</table></td>\r\n		</tr>\r\n	</tbody>\r\n</table>', '{shop_name} - Shop Name.<br/>\r\n{website_name} Name of our website<br>\r\n{product_name} Product Name <br>\r\n{new_status} New Request Status (Approved/Declined) <br>\r\n{reference_number} Reference Number of the request<br>\r\n{social_media_icons} <br>\r\n{contact_us_url} <br>', 1);
INSERT IGNORE INTO `tbl_email_templates` (`etpl_code`, `etpl_lang_id`, `etpl_name`, `etpl_subject`, `etpl_body`, `etpl_replacements`, `etpl_status`) VALUES
('seller_category_request_admin_email', 1, 'Seller - Category request', 'New Product Category Requested at {website_name}', '\r\n<table width=\"600px\" cellspacing=\"0\" cellpadding=\"0\" style=\"margin: 0 auto; table-layout: fixed; background: #ffffff; border-radius: 4px; box-shadow: 0 0 10px rgba(0, 0, 0, 0.04)\">\r\n	<tbody>\r\n		<tr>\r\n			<td style=\"background:#fff;padding:20px 0 10px; text-align:center;\">\r\n				<h4 style=\"font-weight:normal; text-transform:uppercase; color:#999;margin:0; padding:10px 0; font-size:18px;\"></h4>\r\n				<h2 style=\"margin:0; font-size:34px; padding:0;\">New Product Category Request</h2></td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"background:#fff;padding:0 30px; text-align:center; color:#999;vertical-align:top;\">\r\n				<table width=\"100%\" border=\"0\" align=\"center\" cellpadding=\"0\" cellspacing=\"0\">\r\n					<tbody>\r\n						<tr>\r\n							<td style=\"padding:20px 0 30px;\"><strong style=\"font-size:18px;color:#333;\">Dear Admin</strong><br />\r\n								New Product Category has been requested by Seller {user_full_name}- {prodcat_name}</td>\r\n						</tr>\r\n					</tbody>\r\n				</table></td>\r\n		</tr>\r\n	</tbody>\r\n</table>', '{user_full_name} - Name of the email receiver.<br/>\r\n{website_name} Name of our website<br>\r\n{prodcat_name} Product Category Name <br>\r\n\r\n{social_media_icons} <br>\r\n{contact_us_url} <br>', 1),
('seller_custom_catalog_request_status_change', 1, 'Supplier - Custom Catalog Request Status Change', 'Your Custom Catalog Request {new_request_status} at {website_name}', '\r\n<table width=\"600px\" cellspacing=\"0\" cellpadding=\"0\" style=\"margin: 0 auto; table-layout: fixed; background: #ffffff; border-radius: 4px; box-shadow: 0 0 10px rgba(0, 0, 0, 0.04)\">\r\n	<tbody>\r\n		<tr>                        \r\n			<td style=\"background:#fff;padding:20px 0 10px; text-align:center;\">                            \r\n				<h2 style=\"margin:0; font-size:34px; padding:0;\">Custom Catalog Approval Request</h2></td>                    \r\n		</tr>                    \r\n		<tr>                        \r\n			<td style=\"background:#fff;padding:0 30px; text-align:center; color:#999;vertical-align:top;\">                            \r\n				<table width=\"100%\" cellspacing=\"0\" cellpadding=\"0\" border=\"0\" align=\"center\">                                \r\n					<tbody>                                    \r\n						<tr>                                        \r\n							<td style=\"padding:20px 0 30px;\"><strong style=\"font-size:18px;color:#333;\">Dear {shop_name} </strong><br />\r\n								Your catalog approval request has been {new_request_status}.</td>                                    \r\n						</tr>                                    \r\n						<tr>                                        \r\n							<td style=\"padding:20px 0 30px;\">                                            \r\n								<table style=\"border:1px solid #ddd; border-collapse:collapse;\" cellspacing=\"0\" cellpadding=\"0\" border=\"0\">                                                \r\n									<tbody>                                                    \r\n										<tr>                                                        \r\n											<td style=\"padding:10px;font-size:13px;border:1px solid #ddd; color:#333; font-weight:bold;\" width=\"153\">Request Comments</td>                                                        \r\n											<td style=\"padding:10px;font-size:13px; color:#333;border:1px solid #ddd;\" width=\"620\">{request_comments}</td>                                                    \r\n										</tr>                                                        \r\n									</tbody>                                            \r\n								</table></td>                                    \r\n						</tr>                                    \r\n					</tbody>                            \r\n				</table></td>                    \r\n		</tr>\r\n	</tbody>\r\n</table>', '{shop_name} - Shop Name.<br/>\r\n{website_name} Name of our website<br>\r\n{new_request_status} New Request Status (Approved/Declined) <br>\r\n{social_media_icons} <br>\r\n{contact_us_url} <br>', 1),
('send_message', 1, 'Send a Message', 'Message received on {website_name}', '\r\n<table width=\"600px\" cellspacing=\"0\" cellpadding=\"0\" style=\"margin: 0 auto; table-layout: fixed; background: #ffffff; border-radius: 4px; box-shadow: 0 0 10px rgba(0, 0, 0, 0.04)\">\r\n	<tbody>\r\n		<tr>                        \r\n			<td style=\"background:#fff;padding:20px 0 10px; text-align:center;\">                            \r\n				<h4 style=\"font-weight:normal; text-transform:uppercase; color:#999;margin:0; padding:10px 0; font-size:18px;\"></h4>                            \r\n				<h2 style=\"margin:0; font-size:34px; padding:0;\">Message Posted</h2></td>                    \r\n		</tr>                    \r\n		<tr>                        \r\n			<td style=\"background:#fff;padding:0 30px; text-align:center; color:#999;vertical-align:top;\">                            \r\n				<table width=\"100%\" border=\"0\" align=\"center\" cellpadding=\"0\" cellspacing=\"0\">                                \r\n					<tbody>                                    \r\n						<tr>                                        \r\n							<td style=\"padding:20px 0 30px;\"><strong style=\"font-size:18px;color:#333;\">Dear {user_full_name}</strong><br />\r\n								{username} has sent you a message on <a href=\"{website_url}\">{website_name}</a>.</td>                                    \r\n						</tr>                                    \r\n						<tr>                                        \r\n							<td style=\"font-size:12px; color:#666;\">                                            \r\n								<table style=\"border:1px solid #ddd; border-collapse:collapse;\" cellspacing=\"0\" cellpadding=\"0\" border=\"0\">                                                \r\n									<tbody>                                                    \r\n										<tr>                                                        \r\n											<td style=\"padding:10px;font-size:13px;border:1px solid #ddd; color:#333; font-weight:bold;\" width=\"109\">Subject</td>                                                        \r\n											<td style=\"padding:10px;font-size:13px; color:#333;border:1px solid #ddd;\" width=\"664\">{message_subject}</td>                                                    \r\n										</tr>    \r\n										<tr>                                                        \r\n											<td style=\"padding:10px;font-size:13px;border:1px solid #ddd; color:#333; font-weight:bold;\">Message</td>                                                        \r\n											<td style=\"padding:10px;font-size:13px; color:#333;border:1px solid #ddd;\">{message}</td>                                                    \r\n										</tr>    \r\n									</tbody>                                            \r\n								</table><br />\r\n								Please {click_here} to reply to this message.</td>                                    \r\n						</tr>                                    \r\n					</tbody>                            \r\n				</table></td>                    \r\n		</tr>\r\n	</tbody>\r\n</table>', '{user_full_name} Name of the person who is receiving this email<br />\r\n{username} Username of the sender<br />\r\n{message_subject} Subject of the message<br />\r\n{message} Additional message/text sent by sender\r\n{social_media_icons} <br>\r\n{contact_us_url} <br>', 1),
('share_earn_invitation_email', 1, 'Invitation Email for Friends', 'Your friend has invited you for Amazing Discounts on {website_name}.', '\r\n<table width=\"600px\" cellspacing=\"0\" cellpadding=\"0\" style=\"margin: 0 auto; table-layout: fixed; background: #ffffff; border-radius: 4px; box-shadow: 0 0 10px rgba(0, 0, 0, 0.04)\">\r\n	<tbody>\r\n		<tr>\r\n			<td style=\"background:#fff;padding:20px 0 10px; text-align:center;\">\r\n				<h4 style=\"font-weight:normal; text-transform:uppercase; color:#999;margin:0; padding:10px 0; font-size:18px;\"></h4>\r\n				<h2 style=\"margin:0; font-size:34px; padding:0;\">Yo!kart Invitation!</h2></td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"background:#fff;padding:0 30px; text-align:center; color:#999;vertical-align:top;\">\r\n				<table width=\"100%\" border=\"0\" align=\"center\" cellpadding=\"0\" cellspacing=\"0\">\r\n					<tbody>\r\n						<tr>\r\n							<td style=\"padding:20px 0 30px;\"><strong style=\"font-size:18px;color:#333;\">Dear Friend </strong><br />\r\n								This is an invitation from {user_full_name} to join them on <a href=\"{website_url}\">{website_name}</a> and enjoy Amazing Discounts.</td>\r\n						</tr>\r\n						<tr>\r\n							<td style=\"padding:20px 0 30px;\">Click the link below to accept this invitation:<br />\r\n								<a href=\"{tracking_url}\" style=\"font-size:15px; color:#ff3a59;\">Click Here</a></td>\r\n						</tr>\r\n						<tr>\r\n							<td style=\"padding:20px 0 30px;\">{invitation_message}</td>\r\n						</tr>\r\n					</tbody>\r\n				</table></td>\r\n		</tr>\r\n	</tbody>\r\n</table>', '{user_full_name} Name of the email receiver.<br>\n{website_name} Name of our website<br>\n{website_url} URL/Link of our website<br>\n{tracking_url} referral url\n{invitation_message} <br>\n{social_media_icons} <br>\n{contact_us_url} <br>', 1),
('subscription_free_package_reminder_email', 1, 'Subscription Free Package Reminder Email', 'Subscription Reminder Email', '\r\n<table width=\"600px\" cellspacing=\"0\" cellpadding=\"0\" style=\"margin: 0 auto; table-layout: fixed; background: #ffffff; border-radius: 4px; box-shadow: 0 0 10px rgba(0, 0, 0, 0.04)\">\r\n	<tbody>\r\n		<tr>                        \r\n			<td style=\"background:#fff;padding:20px 0 10px; text-align:center;\">                            \r\n				<h4 style=\"font-weight:normal; text-transform:uppercase; color:#999;margin:0; padding:10px 0; font-size:18px;\"></h4>                            \r\n				<h2 style=\"margin:0; font-size:34px; padding:0;\">Subscription Reminder!</h2></td>                    \r\n		</tr>\r\n		<tr>                        \r\n			<td style=\"background:#fff;padding:0 30px; text-align:center; color:#999;vertical-align:top;\">                            \r\n				<table width=\"100%\" border=\"0\" align=\"center\" cellpadding=\"0\" cellspacing=\"0\">                                \r\n					<tbody>                                    \r\n						<tr>                                        \r\n							<td style=\"padding:20px 0 30px;\"><strong style=\"font-size:18px;color:#333;\">Dear {user_full_name}</strong><br />\r\n								your Subscription is going to be expire in next 2 days. Kindly Purchase any Package to &nbsp;continue your subscription on&nbsp;<a href=\"{website_url}\">{website_name}</a>&nbsp;.</td>                                    \r\n						</tr>                                    \r\n					</tbody>                            \r\n				</table></td>                    \r\n		</tr>\r\n	</tbody>\r\n</table>', '{user_full_name} Name of the email receiver.<br>\r\n{website_name} Name of our website<br>\r\n{website_url} URL/Link of our website<br>\r\n{tracking_url} referral url\r\n{invitation_message} <br>\r\n{social_media_icons} <br>\r\n{contact_us_url} <br>', 1),
('subscription_reminder_email', 1, 'Subscription Reminder Email', 'Subscription Reminder Email', '\r\n<table width=\"600px\" cellspacing=\"0\" cellpadding=\"0\" style=\"margin: 0 auto; table-layout: fixed; background: #ffffff; border-radius: 4px; box-shadow: 0 0 10px rgba(0, 0, 0, 0.04)\">\r\n	<tbody>\r\n		<tr>                        \r\n			<td style=\"background:#fff;padding:20px 0 10px; text-align:center;\">                            \r\n				<h4 style=\"font-weight:normal; text-transform:uppercase; color:#999;margin:0; padding:10px 0; font-size:18px;\"></h4>                            \r\n				<h2 style=\"margin:0; font-size:34px; padding:0;\">Subscription Reminder!</h2></td>                    \r\n		</tr> \r\n		<tr>                        \r\n			<td style=\"background:#fff;padding:0 30px; text-align:center; color:#999;vertical-align:top;\">                            \r\n				<table width=\"100%\" border=\"0\" align=\"center\" cellpadding=\"0\" cellspacing=\"0\">                                \r\n					<tbody>                                    \r\n						<tr>                                        \r\n							<td style=\"padding:20px 0 30px;\"><strong style=\"font-size:18px;color:#333;\">Dear {user_full_name}</strong><br />\r\n								your Subscription is going to be expire in next 2 days. Kindly maintain your minimum wallet balance to continue your subscription on&nbsp;<a href=\"{website_url}\">{website_name}</a>&nbsp;.</td>                                    \r\n						</tr>                                    \r\n					</tbody>                            \r\n				</table></td>                    \r\n		</tr> \r\n	</tbody>\r\n</table>', '{user_full_name} Name of the email receiver.<br>\r\n{website_name} Name of our website<br>\r\n{website_url} URL/Link of our website<br>\r\n{tracking_url} referral url\r\n{invitation_message} <br>\r\n{social_media_icons} <br>\r\n{contact_us_url} <br>', 1),
('subscription_renew_admin', 1, 'Admin - Subscription Renew', 'Subscription Renewed at {website_name}', '\r\n<table width=\"600px\" cellspacing=\"0\" cellpadding=\"0\" style=\"margin: 0 auto; table-layout: fixed; background: #ffffff; border-radius: 4px; box-shadow: 0 0 10px rgba(0, 0, 0, 0.04)\">   \r\n	<tbody>\r\n		<tr>                        \r\n			<td style=\"background:#fff;padding:20px 0 10px; text-align:center;\">                            \r\n				<h4 style=\"font-weight:normal; text-transform:uppercase; color:#999;margin:0; padding:10px 0; font-size:18px;\"></h4>                            \r\n				<h2 style=\"margin:0; font-size:34px; padding:0;\">Subscription Reminder!</h2></td>                    \r\n		</tr>                            \r\n		<tr>                        \r\n			<td style=\"background:#fff;padding:0 30px; text-align:center; color:#999;vertical-align:top;\">                            \r\n				<table width=\"100%\" border=\"0\" align=\"center\" cellpadding=\"0\" cellspacing=\"0\">                                \r\n					<tbody>                                    \r\n						<tr>                                        \r\n							<td style=\"padding:20px 0 30px;\"><strong style=\"font-size:18px;color:#333;\">Dear {user_full_name}</strong><br />\r\n								your Subscription is going to be expire in next 2 days. Kindly maintain your minimum wallet balance to continue your subscription on&nbsp;<a href=\"{website_url}\">{website_name}</a>&nbsp;.</td>                                    \r\n						</tr>                                    \r\n					</tbody>                            \r\n				</table></td>                    \r\n		</tr> \r\n	</tbody>\r\n</table>', '{website_name} Name of our website<br>\r\n{invoice_number} Invoice Number of the Order<br>\r\n{new_order_status} New Order Status<br>\r\n{social_media_icons} <br>\r\n{contact_us_url} <br>', 1),
('subscription_renew_user', 1, 'Renew Subscription Plan', 'Subscription Renewed at {website_name}', '\r\n<table width=\"600px\" cellspacing=\"0\" cellpadding=\"0\" style=\"margin: 0 auto; table-layout: fixed; background: #ffffff; border-radius: 4px; box-shadow: 0 0 10px rgba(0, 0, 0, 0.04)\">\r\n	<tbody>\r\n		<tr>                        \r\n			<td style=\"background:#fff;padding:20px 0 10px; text-align:center;\">                            \r\n				<h4 style=\"font-weight:normal; text-transform:uppercase; color:#999;margin:0; padding:10px 0; font-size:18px;\">Updated</h4>                            \r\n				<h2 style=\"margin:0; font-size:34px; padding:0;\">Subscription Renew</h2></td>                    \r\n		</tr>\r\n		<tr>                        \r\n			<td style=\"background:#fff;padding:0 30px; text-align:center; color:#999;vertical-align:top;\">                            \r\n				<table width=\"100%\" border=\"0\" align=\"center\" cellpadding=\"0\" cellspacing=\"0\">                                \r\n					<tbody>                                    \r\n						<tr>                                        \r\n							<td style=\"padding:20px 0 30px;\"><strong style=\"font-size:18px;color:#333;\">Dear {user_name}</strong><br />\r\n								\r\n								<div>your subscription has been renewed.</div>                                            \r\n								<div>corresponding to Order Invoice Number - {invoice_number} at <a href=\"{website_url}\">{website_name}</a>.</div></td>                                    \r\n						</tr>                                          \r\n						<tr>                                        \r\n							<td style=\"padding:0 0 30px;\">{order_products_table_format}</td>                                    \r\n						</tr>                                    \r\n					</tbody>                            \r\n				</table></td>                    \r\n		</tr>\r\n	</tbody>\r\n</table>', '{website_name} Name of our website<br>\r\n{user_full_name} User Name <br>\r\n{invoice_number} Invoice Number of the Order<br>\r\n{new_order_status} New Order Status<br>\r\n{social_media_icons} <br>\r\n{contact_us_url} <br>', 1),
('supplier_request_status_change_buyer', 1, 'Buyers - Seller Request Status Change', 'Your Seller Request {new_request_status} at {website_name}', '\r\n<table width=\"600px\" cellspacing=\"0\" cellpadding=\"0\" style=\"margin: 0 auto; table-layout: fixed; background: #ffffff; border-radius: 4px; box-shadow: 0 0 10px rgba(0, 0, 0, 0.04)\">\r\n	<tbody>\r\n		<tr>                        \r\n			<td style=\"background:#fff;padding:20px 0 10px; text-align:center;\">                            \r\n				<h4 style=\"font-weight:normal; text-transform:uppercase; color:#999;margin:0; padding:10px 0; font-size:18px;\">Updated</h4>                            \r\n				<h2 style=\"margin:0; font-size:34px; padding:0;\">Seller Approval Status</h2></td>                    \r\n		</tr>                        \r\n		<tr>                        \r\n			<td style=\"background:#fff;padding:0 30px; text-align:center; color:#999;vertical-align:top;\">                            \r\n				<table width=\"100%\" border=\"0\" align=\"center\" cellpadding=\"0\" cellspacing=\"0\">                                \r\n					<tbody>                                    \r\n						<tr>                                        \r\n							<td style=\"padding:20px 0 30px;\"><strong style=\"font-size:18px;color:#333;\">Dear {user_full_name} </strong><br />\r\n								Your seller approval request has been {new_request_status} corresponding to Reference Number - {reference_number}.{request_comments}</td>                                    \r\n						</tr>                                    \r\n					</tbody> \r\n				</table></td>\r\n		</tr>  \r\n	</tbody>\r\n</table>', '{user_full_name} - Name of the email receiver.<br/>\r\n{website_name} Name of our website<br>\r\n\r\n\r\n{new_request_status} New Request Status (Approved/Declined) <br>\r\n{reference_number} Reference Number of the request<br>\r\n{social_media_icons} <br>\r\n{contact_us_url} <br>', 1),
('taxapi_order_creation_failure', 1, 'TaxApi Order Creation Failure Email', 'TaxApi Order Creation Failed at {website_name}', '\r\n<table width=\"600px\" cellspacing=\"0\" cellpadding=\"0\" style=\"margin: 0 auto; table-layout: fixed; background: #ffffff; border-radius: 4px; box-shadow: 0 0 10px rgba(0, 0, 0, 0.04)\">\r\n	<tbody>\r\n		<tr>                        \r\n			<td style=\"background:#fff;padding:20px 0 10px; text-align:center;\">                            \r\n				<h4 style=\"font-weight:normal; text-transform:uppercase; color:#999;margin:0; padding:10px 0; font-size:18px;\"></h4>                            \r\n				<h2 style=\"margin:0; font-size:34px; padding:0;\">TaxApi Order Creation Failure</h2></td>                    \r\n		</tr>                    \r\n		<tr>                        \r\n			<td style=\"background:#fff;padding:0 30px; text-align:center; color:#999;vertical-align:top;\">                            \r\n				<table width=\"100%\" border=\"0\" align=\"center\" cellpadding=\"0\" cellspacing=\"0\">                                \r\n					<tbody>                                    \r\n						<tr>                                        \r\n							<td style=\"padding:20px 0 30px;\"><strong style=\"font-size:18px;color:#333;\">Dear Admin </strong><br />\r\n								System has tried to create an order/transaction on TaxApi after order is marked as completed by admin, but not able to create an Order/Transaction on TaxApi due to below Error on your site <a href=\"{website_url}\">{website_name}</a> with Yokart Order Invoice Number {invoice_number}.<br />\r\n								Please find the TaxApi Error information below.</td>                                    \r\n						</tr>                                    \r\n						<tr>                                            \r\n							<td style=\"padding:0 0 30px;\">{error_message}</td>                                    \r\n						</tr>                                    \r\n					</tbody>                            \r\n	