('vendor_digital_order_email', 1, 'Vendor Digital Order Email', 'Digital Order Received From {website_name}', '\r\n<table width=\"600px\" cellspacing=\"0\" cellpadding=\"0\" style=\"margin: 0 auto; table-layout: fixed; background: #ffffff; border-radius: 4px; box-shadow: 0 0 10px rgba(0, 0, 0, 0.04)\">\r\n	<tbody>\r\n		<tr>                        \r\n			<td style=\"background:#fff;padding:20px 0 10px; text-align:center;\">                            \r\n				<h4 style=\"font-weight:normal; text-transform:uppercase; color:#999;margin:0; padding:10px 0; font-size:18px;\"></h4>                            \r\n				<h2 style=\"margin:0; font-size:34px; padding:0;\">Order Placed</h2></td>                    \r\n		</tr>\r\n		<tr>                        \r\n			<td style=\"background:#fff;padding:0 30px; text-align:center; color:#999;vertical-align:top;\">                            \r\n				<table width=\"100%\" border=\"0\" align=\"center\" cellpadding=\"0\" cellspacing=\"0\">                                \r\n					<tbody>                                    \r\n						<tr>                                        \r\n							<td style=\"padding:20px 0 30px;\"><strong style=\"font-size:18px;color:#333;\">Dear {vendor_name} </strong><br />\r\n								An order has been placed for your Digital product(s) at <a href=\"{website_url}\">{website_name}</a>. Please Share the downloadable link &nbsp;and other Credentials with the user at Email &nbsp;: {order_user_email}&nbsp;<br />\r\n								Order details are given below:</td>                                    \r\n						</tr>                                    \r\n						<tr>                                        \r\n							<td style=\"padding:5px 0 30px;\">{order_items_table_format}</td>                                    \r\n						</tr>                                     \r\n					</tbody>                            \r\n				</table></td>                    \r\n		</tr>\r\n	</tbody>\r\n</table>', '{vendor_name} Name of the vendor<br/>\r\n{website_name} Name of our website<br>\r\n{website_url} URL of our website<br>\r\n{order_items_table_format} Order items in Tabular Format.<br>\r\n{order_user_email} Buyer Email Address\r\n{social_media_icons} <br>\r\n{contact_us_url} <br>', 1),
('vendor_order_email', 1, 'Vendor Order Email', 'Order Received From {website_name}', '\r\n<table width=\"600px\" cellspacing=\"0\" cellpadding=\"0\" style=\"margin: 0 auto; table-layout: fixed; background: #ffffff; border-radius: 4px; box-shadow: 0 0 10px rgba(0, 0, 0, 0.04)\">\r\n	<tbody>\r\n		<tr>                        \r\n			<td style=\"background:#fff;padding:20px 0 10px; text-align:center;\">                            \r\n				<h4 style=\"font-weight:normal; text-transform:uppercase; color:#999;margin:0; padding:10px 0; font-size:18px;\"></h4>                            \r\n				<h2 style=\"margin:0; font-size:34px; padding:0;\">Order Placed</h2></td>                    \r\n		</tr>                    \r\n		<tr>                        \r\n			<td style=\"background:#fff;padding:0 30px; text-align:center; color:#999;vertical-align:top;\">                            \r\n				<table width=\"100%\" border=\"0\" align=\"center\" cellpadding=\"0\" cellspacing=\"0\">                                \r\n					<tbody>                                    \r\n						<tr>                                        \r\n							<td style=\"padding:20px 0 30px;\"><strong style=\"font-size:18px;color:#333;\">Dear {vendor_name} </strong><br />\r\n								An order has been placed for your product(s) at <a href=\"{website_url}\">{website_name}</a>.<br />\r\n								Order details &amp; Shipping information are given below:</td>                                    \r\n						</tr>                                    \r\n						<tr>                                        \r\n							<td style=\"padding:5px 0 30px;\">{order_items_table_format}</td>                                    \r\n						</tr>                                    \r\n					</tbody>                            \r\n				</table></td>                    \r\n		</tr>\r\n	</tbody>\r\n</table>', '{vendor_name} Name of the vendor<br/>\n{website_name} Name of our website<br>\n{website_url} URL of our website<br>\n{order_items_table_format} Order items in Tabular Format.<br>\n{social_media_icons} <br>\n{contact_us_url} <br>', 1);
INSERT IGNORE INTO `tbl_email_templates` (`etpl_code`, `etpl_lang_id`, `etpl_name`, `etpl_subject`, `etpl_body`, `etpl_replacements`, `etpl_status`) VALUES
('welcome_registration', 1, 'Welcome Mail on Registration', 'Welcome to {website_name}', '\r\n<table width=\"600px\" cellspacing=\"0\" cellpadding=\"0\" style=\"margin: 0 auto; table-layout: fixed; background: #ffffff; border-radius: 4px; box-shadow: 0 0 10px rgba(0, 0, 0, 0.04)\">\r\n	<tbody>\r\n		<tr>                        \r\n			<td style=\"background:#fff;padding:20px 0 10px; text-align:center;\">                            \r\n				<h4 style=\"font-weight:normal; text-transform:uppercase; color:#999;margin:0; padding:10px 0; font-size:18px;\">Congratulations</h4>                            \r\n				<h2 style=\"margin:0; font-size:34px; padding:0;\">Account Created!</h2></td>                    \r\n		</tr>\r\n		<tr>                        \r\n			<td style=\"background:#fff;padding:0 30px; text-align:center; color:#999;vertical-align:top;\">                            \r\n				<table width=\"100%\" border=\"0\" align=\"center\" cellpadding=\"0\" cellspacing=\"0\">                                \r\n					<tbody>                                    \r\n						<tr>                                        \r\n							<td style=\"padding:20px 0 30px;\"><strong style=\"font-size:18px;color:#333;\">Dear {name} </strong><br />\r\n								Thank you for signing up at <a href=\"{website_url}\">{website_name}</a>.</td>                                    \r\n						</tr>                                    \r\n						<tr>                                        \r\n							<td style=\"padding:20px 0 30px;\">We are thrilled to have you aboard! You have taken a great first step and we are so excited to connect directly with you.</td>                                    \r\n						</tr>                                    \r\n						<tr>                                        \r\n							<td style=\"padding:0 0 30px;\">If you require any assistance in using our site, or have any feedback or suggestions, you can email us at {contact_us_email}</td>                                    \r\n						</tr>                                    \r\n					</tbody>                            \r\n				</table></td>                    \r\n		</tr>\r\n	</tbody>\r\n</table>', '{name} Name of the signed up user.<br>\r\n{email} Email Address of the signed up user.<br>\r\n{username} Username of the signed up User <br/>\r\n{contact_us_email} - Contact Us Email Address<br/>\r\n{website_name} Name of our website<br>\r\n{social_media_icons} <br>\r\n{contact_us_url} <br>\r\n', 1),
('withdrawal_request_admin', 1, 'Withdrawal Request - Admin', 'Withdrawal Request on {website_name}', '\r\n<table width=\"600px\" cellspacing=\"0\" cellpadding=\"0\" style=\"margin: 0 auto; table-layout: fixed; background: #ffffff; border-radius: 4px; box-shadow: 0 0 10px rgba(0, 0, 0, 0.04)\">\r\n	<tbody>\r\n		<tr>                        \r\n			<td style=\"background:#fff;padding:20px 0 10px; text-align:center;\">                            \r\n				<h4 style=\"font-weight:normal; text-transform:uppercase; color:#999;margin:0; padding:10px 0; font-size:18px;\">Request Received</h4>                            \r\n				<h2 style=\"margin:0; font-size:34px; padding:0;\">Withdrawal Request</h2></td>                    \r\n		</tr>\r\n		<tr>                        \r\n			<td style=\"background:#fff;padding:0 30px; text-align:center; color:#999;vertical-align:top;\">                            \r\n				<table width=\"100%\" border=\"0\" align=\"center\" cellpadding=\"0\" cellspacing=\"0\">                                \r\n					<tbody>                                    \r\n						<tr>                                        \r\n							<td style=\"padding:20px 0 30px;\"><strong style=\"font-size:18px;color:#333;\">Dear Admin</strong><br />\r\n								{username} has submitted a withdrawal request on {website_name}. Please find the details below:</td>                                    \r\n						</tr>                                    \r\n						<tr>                                        \r\n							<td style=\"padding:20px 0 30px;\">                                            \r\n								<table style=\"border:1px solid #ddd; border-collapse:collapse;\" cellspacing=\"0\" cellpadding=\"0\" border=\"0\">                                                \r\n									<tbody>                                                    \r\n										<tr>                                                        \r\n											<td style=\"padding:10px;font-size:13px;border:1px solid #ddd; color:#333; font-weight:bold;\" width=\"153\">Request ID</td>                                                        \r\n											<td style=\"padding:10px;font-size:13px; color:#333;border:1px solid #ddd;\" width=\"620\">{request_id}</td>                                                    \r\n										</tr>                                                        \r\n										<tr>                                                        \r\n											<td style=\"padding:10px;font-size:13px;border:1px solid #ddd; color:#333; font-weight:bold;\" width=\"153\">Amount<span class=\"Apple-tab-span\" style=\"white-space:pre\"></span></td>\r\n											<td style=\"padding:10px;font-size:13px; color:#333;border:1px solid #ddd;\" width=\"620\">{request_amount}</td>                                                    \r\n										</tr>                                                    \r\n										<tr>                                                        \r\n											<td style=\"padding:10px;font-size:13px;border:1px solid #ddd; color:#333; font-weight:bold;\" colspan=\"2\">Withdrawal details are as below:</td>                                        \r\n										</tr>                                                \r\n									</tbody>                                            \r\n								</table>                                            \r\n								{withdrawal_detail_table_format_html}</td>                                    \r\n						</tr>                                    \r\n					</tbody>                            \r\n				</table></td>                    \r\n		</tr> \r\n	</tbody>\r\n</table>', '{username} Username of the person submitted the withdrawal request<br />\r\n{website_name} Name of the website<br />\r\n{request_id} Withdrawal Request ID<br />\r\n{request_amount} Withdrawal Request Amount<br />\r\n{social_media_icons} <br>\r\n{withdrawal_detail_table_format_html}: Withdrawal Payment Details like Bank Details, Cheque Details, PayPal Details etc\r\n{contact_us_url} <br>', 1),
('withdrawal_request_approved_declined', 1, 'Withdrawal Request Approved/Declined Email for User', 'Fund Withdrawal Request {request_status} on {website_name}', '\r\n<table width=\"600px\" cellspacing=\"0\" cellpadding=\"0\" style=\"margin: 0 auto; table-layout: fixed; background: #ffffff; border-radius: 4px; box-shadow: 0 0 10px rgba(0, 0, 0, 0.04)\">\r\n	<tbody>\r\n		<tr>                        \r\n			<td style=\"background:#fff;padding:20px 0 10px; text-align:center;\">                            \r\n				<h4 style=\"font-weight:normal; text-transform:uppercase; color:#999;margin:0; padding:10px 0; font-size:18px;\">Updated</h4>                            \r\n				<h2 style=\"margin:0; font-size:34px; padding:0;\">Withdrawal Request Status</h2></td>                    \r\n		</tr> \r\n		<tr>                        \r\n			<td style=\"background:#fff;padding:0 30px; text-align:center; color:#999;vertical-align:top;\">                            \r\n				<table width=\"100%\" border=\"0\" align=\"center\" cellpadding=\"0\" cellspacing=\"0\">                                \r\n					<tbody>                                    \r\n						<tr>                                        \r\n							<td style=\"padding:20px 0 30px;\"><strong style=\"font-size:18px;color:#333;\">Dear {user_name}</strong><br />\r\n								Your fund withdrawal request {request_id} of {request_amount} has been {request_status} on <a href=\"{website_url}\">{website_name}</a>.</td>                                    \r\n						</tr>                                    \r\n					</tbody>                            \r\n				</table></td>                    \r\n		</tr>\r\n	</tbody>\r\n</table>', '{user_name} Name of the email receiver<br />\r\n{request_id} Withdrawal Request ID<br />\r\n{request_amount} Withdrawal Request Amount.<br />\r\n{request_status} New Withdrawal Request Status<br />\r\n{website_name} Name of the website\r\n{social_media_icons} <br>\r\n{contact_us_url} <br>', 1);

