UPDATE `tbl_configurations` SET `conf_val` = '\r\n<table width=\"600px\" cellspacing=\"0\" cellpadding=\"0\" style=\"margin: 0 auto; table-layout: fixed\">                \r\n	<tbody>\r\n		<tr>                    \r\n			<td style=\"text-align: center\">                        \r\n				<p style=\" font-family: \'Poppins\', sans-serif; font-size: 14px; letter-spacing: -0.2px; display: block; box-sizing: border-box; font-weight: 400; color: #212529; line-height: 26px; margin: 0 0 20px 0; \">                            Contact {website_name} at<br />\r\n					                            <a href=\"mailto:{CONTACT-EMAIL}\" style=\"color: #f13925; text-decoration: none\">                                {CONTACT-EMAIL}\r\n                            </a>                            or call at\r\n                            <a href=\"tel:{SITE-PHONE}\" style=\"color: #f13925; text-decoration: none\">                                {SITE-PHONE}\r\n                            </a>                        </p>                        \r\n				<h5 style=\"font-size: 18px; font-weight: 600; text-transform: uppercase; letter-spacing: -0.2px; line-height: 24px; display: block; margin: 0 0 15px 0; color: #212529\">                            Get In Touch\r\n                        </h5>                        {social_media_icons}\r\n                        <span style=\"display: block; width: 100%; font-size: 12px; padding: 10px 0; color: #212529\">                        </span>                    </td>                \r\n		</tr>            \r\n	</tbody>\r\n</table>' WHERE `tbl_configurations`.`conf_name` = 'CONF_EMAIL_TEMPLATE_FOOTER_HTML1';
UPDATE `tbl_email_templates` SET `etpl_body` = '\r\n<table id=\"body\">                                \r\n	<tbody>                                    \r\n		<tr>                                        \r\n			<td style=\"padding: 30px 40px 50px 40px; text-align: center\">                                            \r\n				<h1 style=\"font-size: 40px; letter-spacing: -0.4px; margin: 0 0 30px 0; font-weight: 700; color: #212529\">Welcome to {website_name}</h1>                                            \r\n				<p style=\"font-size: 16px; line-height: 1.5; letter-spacing: -0.32px; color: #212529; margin: 0 0 10px 0\">Hello {username},</p>                                            \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                                                Your email has been registered. Next time you shop with us, log in for faster checkout\r\n                                            </p>                                            \r\n				<p style=\"text-align: center; font-size: 20px\">Jump in and get started</p>                                            \r\n				<div class=\"btn-wrapper\" style=\"text-align: center\">                                                <a href=\"{website_url}\" style=\" border-radius: 4px; background-color: #f13925; color: #fff; font-size: 14px; letter-spacing: -0.28px; text-decoration: none; padding: 9px 20px; display: inline-block; margin-bottom: 30px; \">Shop Now</a>                                            </div>                                            \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                                                If you require assistance in using our site, or have any feedback or suggestions, please email us at {contact_us_email}\r\n                                            </p>                                            \r\n				<p style=\"font-size: 14px; line-height: 1.71; letter-spacing: -0.28px; color: #212529; margin: 0\">                                                Thank You<br />\r\n					                                                Team {website_name}\r\n                                            </p>                                        </td>                                    \r\n		</tr>                                \r\n	</tbody>                            \r\n</table>', `etpl_replacements` = '{name} Name of the signed up user.<br>\r\n{email} Email Address of the signed up user.<br>\r\n{username} Username of the signed up User <br>\r\n{contact_us_email} - Contact Us Email Address<br>\r\n{website_name} Name of our website<br>\r\n{social_media_icons}<br>\r\n{contact_us_url}' WHERE `tbl_email_templates`.`etpl_code` = 'guest_welcome_registration';
UPDATE `tbl_email_templates` SET `etpl_name` = 'Welcome Mail on Guest Registration' WHERE `tbl_email_templates`.`etpl_code` = 'guest_welcome_registration';
UPDATE `tbl_email_templates` SET `etpl_body` = '\r\n<table id=\"body\">                                \r\n	<tbody>                                    \r\n		<tr>                                        \r\n			<td style=\"padding: 30px 40px 50px 40px; text-align: center\">                                            \r\n				<h1 style=\"font-size: 40px; letter-spacing: -0.4px; margin: 0 0 30px 0; font-weight: 700; color: #212529\">Welcome to {website_name}</h1>                                            \r\n				<p style=\"font-size: 16px; line-height: 1.5; letter-spacing: -0.32px; color: #212529; margin: 0 0 10px 0\">Hello {username},</p>                                            \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                                                Thank you for signing up, we are very excited to have you onboard.\r\n                                            </p>                                            \r\n				<p style=\"text-align: center; font-size: 20px\">Jump in and get started</p>                                            \r\n				<div class=\"btn-wrapper\" style=\"text-align: center\">                                                <a href=\"{website_url}\" style=\" border-radius: 4px; background-color: #f13925; color: #fff; font-size: 14px; letter-spacing: -0.28px; text-decoration: none; padding: 9px 20px; display: inline-block; margin-bottom: 30px; \">Shop Now</a>                                            </div>                                            \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                                                If you require assistance in using our site, or have any feedback or suggestions, please email us at {contact_us_email}\r\n                                            </p>                                            \r\n				<p style=\"font-size: 14px; line-height: 1.71; letter-spacing: -0.28px; color: #212529; margin: 0\">                                                Thank You<br />\r\n					                                                Team {website_name}\r\n                                            </p>                                        </td>                                    \r\n		</tr>                                \r\n	</tbody>                            \r\n</table>', `etpl_replacements` = '{name} Name of the signed up user.<br>\r\n{email} Email Address of the signed up user.<br>\r\n{username} Username of the signed up User <br>\r\n{contact_us_email} - Contact Us Email Address<br>\r\n{website_name} Name of our website<br>\r\n{social_media_icons}<br>\r\n{contact_us_url}' WHERE `tbl_email_templates`.`etpl_code` = 'welcome_registration';

DELETE FROM `tbl_email_templates` WHERE `tbl_email_templates`.`etpl_code` = 'threshold_notification_vendor_custom';
INSERT IGNORE INTO `tbl_language_labels` (`label_key`, `label_lang_id`, `label_caption`, `label_type`) VALUES
('LBL_NEWSLETTER_FORM_DESCRIPTION', 1, 'Leave your email here and stay informed about our promotions and new arrivals.', 1)
ON DUPLICATE KEY UPDATE label_caption = VALUES(label_caption);

DELETE FROM `tbl_email_templates` WHERE `tbl_email_templates`.`etpl_code` = 'dummy_template';

ALTER TABLE `tbl_promotions` CHANGE `promotion_budget` `promotion_budget` DECIMAL(12,2) NOT NULL;

INSERT INTO `tbl_email_templates` (`etpl_code`, `etpl_lang_id`, `etpl_name`, `etpl_subject`, `etpl_body`, `etpl_replacements`, `etpl_priority`, `etpl_status`) VALUES
('abandoned_cart_deleted_discount_notification', 1, 'Abandoned Cart Deleted Discount Notification', 'Abandoned Cart Deleted Discount Notification', '\r\n<table id=\"body\" width=\"100%\">    \r\n	<tbody>        \r\n		<tr>            \r\n			<td style=\"padding: 30px 40px 50px 40px; text-align: center\">                \r\n				<h1 style=\"font-size: 40px; letter-spacing: -0.4px; margin: 0 0 30px 0; font-weight: 700; color: #212529\">                    Product Remove from Cart\r\n                </h1>                \r\n				<p style=\"font-size: 16px; line-height: 1.5; letter-spacing: -0.32px; color: #212529; margin: 0 0 10px 0\">                    Hello {user_full_name},\r\n                </p>                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    We noticed you removed <span style=\"text-decoration: underline;\">{product_name}</span> from your cart.\r\n                </p>                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    Just for you : Get <span style=\"color:#333; font-weight: bold;\">{discount}</span> off on\r\n                                your order with code <span style=\"color:#333; font-weight: bold;\">{coupon_code}.\r\n                    </span>                </p>                \r\n                \r\n				<div class=\"btn-wrapper\" style=\"text-align: center\"> \r\n                    <a href=\"{checkout_now}\" style=\" border-radius: 4px; background-color: #f13925; color: #fff; font-size: 14px; letter-spacing: -0.28px; text-decoration: none; padding: 9px 20px; display: inline-block; margin-bottom: 30px; \">                        Checkout Now\r\n                    </a> \r\n                </div>                \r\n                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    If you require assistance in using our site, or have any feedback or suggestions, please email us at\r\n                    {CONTACT-EMAIL}\r\n                </p>                \r\n				<p style=\"font-size: 14px; line-height: 1.71; letter-spacing: -0.28px; color: #212529; margin: 0\"> Thank\r\n                    You<br />\r\n					                    Team {website_name}\r\n                </p>            </td>        \r\n		</tr>    \r\n	</tbody>\r\n</table>', '{user_full_name} Name of the email receiver<br>\r\n{website_name} Name of our website<br>\r\n{website_url} URL of our website<br>\r\n{social_media_icons} <br>\r\n{contact_us_url} <br>\r\n{discount} <br>\r\n{coupon_code} <br>\r\n{checkout_now} <br>', 1, 1),
('abandoned_cart_discount_notification', 1, 'Abandoned Cart Discount Notification', 'Abandoned Cart Discount Notification', '\r\n<table id=\"body\" width=\"100%\">    \r\n	<tbody>        \r\n		<tr>            \r\n			<td style=\"padding: 30px 40px 50px 40px; text-align: center\">                \r\n				<h1 style=\"font-size: 40px; letter-spacing: -0.4px; margin: 0 0 30px 0; font-weight: 700; color: #212529\">                    Abandoned Cart Discount\r\n                </h1>                \r\n				<p style=\"font-size: 16px; line-height: 1.5; letter-spacing: -0.32px; color: #212529; margin: 0 0 10px 0\">                    Hello {user_full_name},\r\n                </p>                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    Finish your order before your items sell out!\r\n                </p>                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    Just for you : Get <span style=\"color:#333; font-weight: bold;\">{discount} OFF</span>                                off on your order with code \r\n                    <span style=\"color:#333; font-weight: bold;\">{coupon_code}.\r\n                    </span>                </p>                \r\n                \r\n				<div class=\"btn-wrapper\" style=\"text-align: center\"> \r\n                    <a href=\"{checkout_now}\" style=\" border-radius: 4px; background-color: #f13925; color: #fff; font-size: 14px; letter-spacing: -0.28px; text-decoration: none; padding: 9px 20px; display: inline-block; margin-bottom: 30px; \">                        Checkout Now\r\n                    </a> \r\n                </div>                \r\n				<table width=\"100%\" cellspacing=\"0\" cellpadding=\"0\" style=\"background: #f6f6f6; padding: 10px 20px; border-radius: 4px\">                    \r\n					<tbody>                        \r\n						<tr>                            \r\n							<td style=\"vertical-align: middle; width: 70px; padding: 15px 0\">                                <img src=\"{product_image}\" alt=\"product-image\" />                            </td>                            \r\n							<td style=\"vertical-align: middle; padding: 15px 0\">                                {product_name}\r\n                            </td>                            \r\n							<td style=\"font-size: 14px; line-height: 24px; letter-spacing: -0.2px; color: #212529; text-align: right; vertical-align: middle; padding: 15px 0\">                                {product_price}\r\n                            </td>                        \r\n						</tr>                    \r\n					</tbody>                \r\n				</table>                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    If you require assistance in using our site, or have any feedback or suggestions, please email us at\r\n                    {CONTACT-EMAIL}\r\n                </p>                \r\n				<p style=\"font-size: 14px; line-height: 1.71; letter-spacing: -0.28px; color: #212529; margin: 0\"> Thank\r\n                    You<br />\r\n					                    Team {website_name}\r\n                </p>            </td>        \r\n		</tr>    \r\n	</tbody>\r\n</table> ', '{user_full_name} Name of the email receiver<br>\r\n{website_name} Name of our website<br>\r\n{website_url} URL of our website<br>\r\n{social_media_icons} <br>\r\n{contact_us_url} <br>\r\n{discount} <br>\r\n{coupon_code} <br>\r\n{checkout_now} <br>\r\n{product_image} <br>\r\n{product_name} <br>\r\n{product_price}<br>', 1, 1),
('abandoned_cart_email', 1, 'Abandoned Cart Email', 'Abandoned Cart Email', '\r\n<table id=\"body\" width=\"100%\">    \r\n	<tbody>        \r\n		<tr>            \r\n			<td style=\"padding: 30px 40px 0; text-align: center\">                \r\n				<h1 style=\"font-size: 40px; letter-spacing: -0.4px; margin: 0 0 20px 0; font-weight: 700; color: #212529\">                    We have some unfinished business !</h1>                <br />\r\n				                \r\n				<h5 style=\"font-size: 16px; font-weight: 600; line-height: 1.5; letter-spacing: -0.32px; color: #212529; margin: 0 0 10px 0\">                    Hello {user_full_name}</h5>                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    You have left some great items in your cart, order while they are in stock.\r\n                </p>            </td>        \r\n		</tr>        \r\n		<tr>            \r\n			<td style=\"padding: 15px 40px\">                \r\n				<h4 style=\"text-align: center; font-size: 14px; font-weight: 600; text-transform: uppercase; color: #212529; letter-spacing: -0.2px; margin: 0 0 20px 0\">                    Cart Details\r\n                </h4>                {product_detail_table}\r\n            </td>        \r\n		</tr>        \r\n		<tr>            \r\n			<td style=\"padding: 15px 40px 40px 40px\">                \r\n				<p style=\"font-size: 14px; line-height: 1.71; text-align: center; letter-spacing: -0.28px; color: #212529; margin: 0\">                    Thank You,<br />\r\n					                    Team {Website}\r\n                </p>            </td>        \r\n		</tr>    \r\n	</tbody>\r\n</table>', '{user_full_name} Name of the email receiver<br>\r\n{website_name} Name of our website<br>\r\n{website_url} URL of our website<br>\r\n{social_media_icons} <br>\r\n{contact_us_url} <br>\r\n{product_detail_table} <br>', 1, 1),
('account_credited_debited', 1, 'Credits Received/Debited Email for Vendor', 'Your account has been {txn_type} on {website_name}', '\r\n<table id=\"body\" width=\"100%\">    \r\n	<tbody>        \r\n		<tr>            \r\n			<td style=\"padding: 30px 40px 50px 40px; text-align: center\">                \r\n				<h1 style=\"font-size: 40px; letter-spacing: -0.4px; margin: 0 0 30px 0; font-weight: 700; color: #212529\">                    Account Transaction\r\n                </h1>                \r\n				<p style=\"font-size: 16px; line-height: 1.5; letter-spacing: -0.32px; color: #212529; margin: 0 0 10px 0\">                    Hello {user_name},\r\n                </p>                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    Your account has been {txn_type} at <a href=\"{website_url}\">{website_name}</a>.\r\n                </p>                \r\n				<div style=\"margin-bottom: 20px; text-align: left; padding: 0 20px; border-radius: 4px; background: #f6f6f6; border: 1px solid #f6f6f6\">                    \r\n					<h5 style=\"opacity: 0.6; font-size: 16px\">Transaction Details</h5>                    \r\n					<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\"><span style=\"font-weight: bold;\">ID:</span> {txn_id}</p>                    \r\n					<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\"><span style=\"font-weight: bold;\">Amount:</span> {txn_amount}</p>                    \r\n					<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\"><span style=\"font-weight: bold;\">Comments:</span> {txn_comments}</p>                </div>                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    If you require assistance in using our site, or have any feedback or suggestions, please email us at\r\n                    {CONTACT-EMAIL}\r\n                </p>                \r\n				<p style=\"font-size: 14px; line-height: 1.71; letter-spacing: -0.28px; color: #212529; margin: 0\"> Thank\r\n                    You<br />\r\n					                    Team {website_name}\r\n                </p>            </td>        \r\n		</tr>    \r\n	</tbody>\r\n</table>', '{user_name} Name of the email receiver.<br>\r\n{txn_type} - Credited or Debited<br>{txn_id} - Transaction ID<br>{txn_amount} - Transaction Amount<br>{txn_comments} - Transaction Comments<br>{website_name} - Name of the website.\r\n{social_media_icons} <br>\r\n{contact_us_url} <br>', 5, 1),
('admin_forgot_password', 1, 'Forgot Password Email', 'Reset Password Email', '\r\n<table id=\"body\" width=\"100%\">    \r\n	<tbody>        \r\n		<tr>            \r\n			<td style=\"padding: 30px 40px 50px 40px; text-align: center\">                \r\n				<h1 style=\"font-size: 40px; letter-spacing: -0.4px; margin: 0 0 30px 0; font-weight: 700; color: #212529\">                    Retrieve Password!</h1>                \r\n				<p style=\"font-size: 16px; line-height: 1.5; letter-spacing: -0.32px; color: #212529; margin: 0 0 10px 0\">                    Hello {user_full_name},</p>                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    It seems that you have used reset password option at <a href=\"{website_url}\">{website_name}</a>.\r\n                </p>                \r\n				<p style=\"opacity: 0.7; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">Please click below link to change your password.\r\n                </p>                \r\n				<div class=\"btn-wrapper\" style=\"text-align: center\"> <a href=\"{reset_url}\" style=\" border-radius: 4px; background-color: #f13925; color: #fff; font-size: 14px; letter-spacing: -0.28px; text-decoration: none; padding: 9px 20px; display: inline-block; margin-bottom: 30px; \">                        Reset Password</a>                </div>                \r\n		               \r\n				<p style=\"font-size: 14px; line-height: 1.71; letter-spacing: -0.28px; color: #212529; margin: 0\"> Thank\r\n                    You<br />\r\n					                    Team {website_name}\r\n                </p>            </td>        \r\n		</tr>    \r\n	</tbody>\r\n</table>', '{user_full_name} Name of the email receiver<br>\r\n{website_name} Name of our website<br>\r\n{website_url} URL of our website<br>\r\n{reset_url} URL to reset the password<br>\r\n{social_media_icons} <br>\r\n{contact_us_url} <br>', 5, 1),
('admin_new_user_creation_email', 1, 'New Account Created By Admin', 'Welcome to {website_name}', '\r\n<table id=\"body\" wisth=\"100%\">    \r\n	<tbody>        \r\n		<tr>            \r\n			<td style=\"padding: 30px 40px 50px 40px; text-align: center\">                \r\n				<h1 style=\"font-size: 40px; letter-spacing: -0.4px; margin: 0 0 30px 0; font-weight: 700; color: #212529\">                    Welcome to {website_name}</h1>                \r\n				<p style=\"font-size: 16px; line-height: 1.5; letter-spacing: -0.32px; color: #212529; margin: 0 0 10px 0\">                    Hello {username},</p>                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    Admin has created an {account_type} account for you.\r\n                </p>                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    To access and verify your account please visit the link given below. Your email address will be your\r\n                    username.\r\n                    Please note that the link is valid for next {days} days.\r\n                </p>                \r\n				<div class=\"btn-wrapper\" style=\"text-align: center\"> <a href=\"{reset_url}\" style=\" border-radius: 4px; background-color: #f13925; color: #fff; font-size: 14px; letter-spacing: -0.28px; text-decoration: none; padding: 9px 20px; display: inline-block; margin-bottom: 30px; \">                        Set Password</a>                </div>                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    If you require assistance in using our site, or have any feedback or suggestions, please email us at\r\n                    {contact_us_email}\r\n                </p>                \r\n				<p style=\"font-size: 14px; line-height: 1.71; letter-spacing: -0.28px; color: #212529; margin: 0\"> Thank\r\n                    You<br />\r\n					                    Team {website_name}\r\n                </p>            </td>        \r\n		</tr>    \r\n	</tbody>\r\n</table>', '{username} Name of the email receiver<br>\r\n{user_email} User Email <br>\r\n{account_type} Account Type <br>\r\n{days} Days after which link expire\r\n{website_name} Name of our website<br>\r\n{website_url} URL of our website<br>\r\n{reset_url} URL to reset the password<br>\r\n{social_media_icons} <br>\r\n{contact_us_url} <br>', 3, 1),
('admin_notification_abusive_review_posted', 1, 'Abusive Review posted - Notificationsssas', 'Abusive review posted at {website_name}', '\r\n<table id=\"body\" width=\"100%\">    \r\n	<tbody>        \r\n		<tr>            \r\n			<td style=\"padding: 30px 40px 50px 40px; text-align: center\">                \r\n				<h1 style=\"font-size: 40px; letter-spacing: -0.4px; margin: 0 0 30px 0; font-weight: 700; color: #212529\">                    Order feedback survey\r\n                </h1>                \r\n				<p style=\"font-size: 16px; line-height: 1.5; letter-spacing: -0.32px; color: #212529; margin: 0 0 10px 0\">                    Hello Admin,\r\n                </p>                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    {user_full_name} has posted an abusive review at\r\n                    <a href=\"{website_url}\">{website_name}</a>                </p>                \r\n				<div class=\"btn-wrapper\" style=\"text-align: center\">                    <a href=\"{review_url}\" style=\" border-radius: 4px; background-color: #f13925; color: #fff; font-size: 14px; letter-spacing: -0.28px; text-decoration: none; padding: 9px 20px; display: inline-block; margin-bottom: 30px; \">Link\r\n                        to review\r\n                    </a>                </div>            </td>        \r\n		</tr>    \r\n	</tbody>\r\n</table>', '{user_full_name} Name of the email receiver<br> \r\n{website_name} Name of our website<br>\r\n{website_url} URL of our website<br>\r\n{social_media_icons} <br>\r\n{contact_us_url} <br>\r\n', 1, 1),
('admin_order_email', 1, 'Admin Order Email', 'Order placed at {website_name}', '\r\n<table id=\"body\" width=\"100%\">    \r\n	<tbody>        \r\n		<tr>            \r\n			<td style=\"padding: 30px 40px 50px 40px; text-align: center\">                \r\n				<h1 style=\"font-size: 40px; letter-spacing: -0.4px; margin: 0 0 30px 0; font-weight: 700; color: #212529\">                    Order Received\r\n                </h1>                \r\n				<p style=\"font-size: 16px; line-height: 1.5; letter-spacing: -0.32px; color: #212529; margin: 0 0 10px 0\">                    Hello Admin,\r\n                </p> \r\n                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    An order has been received on your site <a href=\"{website_url}\">{website_name}</a> with\r\n                                Order Invoice Number {order_invoice_number}.\r\n                </p>  \r\n                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    {order_products_table_format}\r\n                </p>              \r\n                \r\n				<p style=\"font-size: 14px; line-height: 1.71; letter-spacing: -0.28px; color: #212529; margin: 0\"> Thank\r\n                    You<br />\r\n					                    Team {website_name}\r\n                </p>            </td>        \r\n		</tr>    \r\n	</tbody>\r\n</table>', '{user_full_name} - Name of the email receiver.<br>\n{order_invoice_number} - Invoice Number of the order.<br>\n{order_date} - Date of the order.<br>\n{website_name} Name of our website<br>\n{website_url} URL of our website<br>\n{order_products_table_format} Order Products Summary in Tabular Format.<br>\n{social_media_icons} <br>\n{contact_us_url} <br>', 3, 1),
('ADMIN_ORDER_PAYMENT_TRANSFERRED_TO_BANK', 1, 'Order Payment Transferred To Bank', 'Order #{ORDER_ID} Payment Transferred To Bank', '\r\n<table id=\"body\" width=\"100%\">    \r\n	<tbody>        \r\n		<tr>            \r\n			<td style=\"padding: 30px 40px 50px 40px; text-align: center\">                \r\n				<h1 style=\"font-size: 40px; letter-spacing: -0.4px; margin: 0 0 30px 0; font-weight: 700; color: #212529\">                    Bank Transfer\r\n                </h1>                \r\n				<p style=\"font-size: 16px; line-height: 1.5; letter-spacing: -0.32px; color: #212529; margin: 0 0 10px 0\">                    Hello Admin,\r\n                </p>                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    Order Payment Detail Submitted BY {USER_NAME} For #{ORDER_ID}.\r\n                </p>  \r\n                \r\n				<div style=\"margin-bottom: 20px; text-align: left; padding: 0 20px; border-radius: 4px; background: #f6f6f6; border: 1px solid #f6f6f6\">                    \r\n					<h5 style=\"opacity: 0.6; font-size: 16px\">Bank Transfer Details</h5>                    \r\n					<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\"><span style=\"font-weight: bold;\">Payment Method:</span> {PAYMENT_METHOD}</p>                    \r\n					<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\"><span style=\"font-weight: bold;\">Transaction Id:</span> {TRANSACTION_ID}</p>                    \r\n					<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\"><span style=\"font-weight: bold;\">Amount:</span> {AMOUNT}</p>                    \r\n					<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\"><span style=\"font-weight: bold;\">Comments:</span> {COMMENTS}</p>                </div>                \r\n				<p style=\"font-size: 14px; line-height: 1.71; letter-spacing: -0.28px; color: #212529; margin: 0\"> Thank\r\n                    You<br />\r\n					                    Team {website_name}\r\n                </p>            </td>        \r\n		</tr>    \r\n	</tbody>\r\n</table>', '{USER_NAME} - Name of the User.<br>\r\n{ORDER_ID} - Order Id.<br>\r\n{PAYMENT_METHOD} - Payment Method Used By Buyer.<br>\r\n{TRANSACTION_ID} - Transaction Id<br>\r\n{AMOUNT} - Amount<br>\r\n{COMMENTS} - Comments.<br>', 3, 1),
('affiliate_share_invitation_email', 1, 'Affiliate Invitation Email for Friends', 'Your friend has invited you for Amazing Discounts on {website_name}.', '\r\n<table id=\"body\" width=\"100%\">    \r\n	<tbody>        \r\n		<tr>            \r\n			<td style=\"padding: 30px 40px 50px 40px; text-align: center\">                \r\n				<h1 style=\"font-size: 40px; letter-spacing: -0.4px; margin: 0 0 30px 0; font-weight: 700; color: #212529\">                    {website_name} Invitation\r\n                </h1>                \r\n				<p style=\"font-size: 16px; line-height: 1.5; letter-spacing: -0.32px; color: #212529; margin: 0 0 10px 0\">                    Hello Friend,\r\n                </p>                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">This is an invitation from {user_full_name} to join them on <a href=\"{website_url}\">{website_name}</a> and enjoy Amazing Discounts.\r\n                </p> \r\n                \r\n				<p style=\"text-align: center; font-size: 20px\">Click the link below to accept this invitation:</p> \r\n                \r\n                \r\n				<div class=\"btn-wrapper\" style=\"text-align: center\"> \r\n                    <a href=\"{tracking_url}\" style=\" border-radius: 4px; background-color: #f13925; color: #fff; font-size: 14px; letter-spacing: -0.28px; text-decoration: none; padding: 9px 20px; display: inline-block; margin-bottom: 30px; \">                        Click Here\r\n                    </a> \r\n                </div>                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    If you require assistance in using our site, or have any feedback or suggestions, please email us at\r\n                    {CONTACT-EMAIL}\r\n                </p>              \r\n                \r\n				<p style=\"font-size: 14px; line-height: 1.71; letter-spacing: -0.28px; color: #212529; margin: 0\"> Thank\r\n                    You<br />\r\n					                    Team {website_name}\r\n                </p>            </td>        \r\n		</tr>    \r\n	</tbody>\r\n</table>', '{user_full_name} Name of the email receiver.<br>\r\n{website_name} Name of our website<br>\r\n{website_url} URL/Link of our website<br>\r\n{tracking_url} referral url\r\n{invitation_message} <br>\r\n{social_media_icons} <br>\r\n{contact_us_url} <br>', 1, 1),
('affiliate_welcome_registration', 1, 'Affiliate Welcome Mail on Registration', 'Welcome to {website_name}', '\r\n<table id=\"body\" width=\"100%\">    \r\n	<tbody>        \r\n		<tr>            \r\n			<td style=\"padding: 30px 40px 50px 40px; text-align: center\">                \r\n				<h1 style=\"font-size: 40px; letter-spacing: -0.4px; margin: 0 0 30px 0; font-weight: 700; color: #212529\">                    Welcome to {website_name}</h1>                \r\n				<p style=\"font-size: 16px; line-height: 1.5; letter-spacing: -0.32px; color: #212529; margin: 0 0 10px 0\">                    Hello {username},</p>                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    Thank you for signing up, we are very excited to have you onboard.\r\n                </p>                \r\n				<p style=\"text-align: center; font-size: 20px\">Jump in and get started</p>                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    If you require assistance in using our site, or have any feedback or suggestions, please email us at\r\n                    {contact_us_email}\r\n                </p>                \r\n				<p style=\"font-size: 14px; line-height: 1.71; letter-spacing: -0.28px; color: #212529; margin: 0\"> Thank\r\n                    You<br />\r\n					                    Team {website_name}\r\n                </p>            </td>        \r\n		</tr>    \r\n	</tbody>\r\n</table>', '{name} Name of the signed up user.<br>\r\n{email} Email Address of the signed up user.<br>\r\n{username} Username of the signed up User <br>\r\n{contact_us_email} - Contact Us Email Address<br>\r\n{website_name} Name of our website<br>\r\n{social_media_icons} <br>\r\n{contact_us_url} <br>\r\n', 5, 1),
('blog_comment_status_changed', 1, 'Blog Comment Status Change - Notification', 'Blog Comment Status Changed at {website_name}', '\r\n<table id=\"body\">    \r\n	<tbody>        \r\n		<tr>            \r\n			<td style=\"padding: 30px 40px 50px 40px; text-align: center\">                \r\n				<h1 style=\"font-size: 40px; letter-spacing: -0.4px; margin: 0 0 30px 0; font-weight: 700; color: #212529\">                    Blog Comment Status</h1>                \r\n				<p style=\"font-size: 16px; line-height: 1.5; letter-spacing: -0.32px; color: #212529; margin: 0 0 10px 0\">                    Hello {user_full_name},</p>                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    Your Comment (for the post \'{post_title}\' / posted on {posted_on_datetime}) status has been changed to {new_status} at <a href=\"{website_url}\">{website_name}</a>.\r\n                </p>                \r\n                \r\n				<p style=\"font-size: 14px; line-height: 1.71; letter-spacing: -0.28px; color: #212529; margin: 0\"> Thank\r\n                    You<br />\r\n					                    Team {website_name}\r\n                </p>            </td>        \r\n		</tr>    \r\n	</tbody>\r\n</table>', '{user_full_name} Name of the email receiver<br> \r\n{new_status} New/Current Order Status<br>\r\n{posted_on_datetime} - Comment Posted on date time.<br>\r\n{post_title} - Blog Post title.<br>\r\n{comment} - Comment.<br>\r\n{website_name} Name of our website<br>\r\n{website_url} URL of our website<br>\r\n{social_media_icons} <br>\r\n{contact_us_url} <br>\r\n', 1, 1),
('blog_contribution_status_changed', 1, 'Blog Contribution Status Change - Notification', 'Blog Contribution Status Changed at {website_name}', '\r\n<table id=\"body\" width=\"100%\">    \r\n	<tbody>        \r\n		<tr>            \r\n			<td style=\"padding: 30px 40px 50px 40px; text-align: center\">                \r\n				<h1 style=\"font-size: 40px; letter-spacing: -0.4px; margin: 0 0 30px 0; font-weight: 700; color: #212529\">                    Blog Contribution Status</h1>                \r\n				<p style=\"font-size: 16px; line-height: 1.5; letter-spacing: -0.32px; color: #212529; margin: 0 0 10px 0\">                    Hello {user_full_name},</p>               \r\n                \r\n				<p style=\"text-align: center; font-size: 20px\">Your blog contribution (posted on {posted_on_datetime}) status has been changed to {new_status} at <a href=\"{website_url}\">{website_name}</a></p>               \r\n              \r\n                \r\n				<p style=\"font-size: 14px; line-height: 1.71; letter-spacing: -0.28px; color: #212529; margin: 0\"> Thank\r\n                    You<br />\r\n					                    Team {website_name}\r\n                </p>            </td>        \r\n		</tr>    \r\n	</tbody>\r\n</table>', '{user_full_name} Name of the email receiver<br> \r\n{new_status} New/Current Order Status<br>\r\n{posted_on_datetime} - Contribution Posted on date time.<br>\r\n{website_name} Name of our website<br>\r\n{website_url} URL of our website<br>\r\n{social_media_icons} <br>\r\n{contact_us_url} <br>\r\n', 1, 1),
('buyer_notification_review_order_product', 1, 'Buyer Review Order product - Notification', 'Review you order at {website_name}', '\r\n<table id=\"body\" width=\"100%\">    \r\n	<tbody>        \r\n		<tr>            \r\n			<td style=\"padding: 30px 40px 50px 40px; text-align: center\">                \r\n				<h1 style=\"font-size: 40px; letter-spacing: -0.4px; margin: 0 0 30px 0; font-weight: 700; color: #212529\">                    We\'d love to hear from you on how we did!</h1>                \r\n				<p style=\"font-size: 16px; line-height: 1.5; letter-spacing: -0.32px; color: #212529; margin: 0 0 10px 0\">                    Hello {user_full_name},</p>                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    Thanks for shoping ( Order Invoice Number {invoice_number}) with\r\n                    <a href=\"{website_url}\">{website_name}</a>.\r\n                    Please feedback your experience to this order\r\n                </p>                \r\n				<p> {order_items_table_format}</p>               \r\n                \r\n				<div class=\"btn-wrapper\" style=\"text-align: center\">                    <a href=\"{review_page_url}\" style=\" border-radius: 4px; background-color: #f13925; color: #fff; font-size: 14px; letter-spacing: -0.28px; text-decoration: none; padding: 9px 20px; display: inline-block; margin-bottom: 30px; \">                        Share Feedback\r\n                    </a>                </div>                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    If you require assistance in using our site, or have any feedback or suggestions, please email us at\r\n                    {CONTACT-EMAIL}\r\n                </p>                \r\n				<p style=\"font-size: 14px; line-height: 1.71; letter-spacing: -0.28px; color: #212529; margin: 0\"> Thank\r\n                    You<br />\r\n					                    Team {website_name}\r\n                </p>            </td>        \r\n		</tr>    \r\n	</tbody>\r\n</table>', '{user_full_name} Name of the email receiver<br> \r\n{new_order_status} New/Current Order Status<br>\r\n{invoice_number} - Child Order Invoice Number.<br>\r\n{order_items_table_format} - Child Order Items in Tabular Format.<br>\r\n{website_name} Name of our website<br>\r\n{website_url} URL of our website<br>\r\n{social_media_icons} <br>\r\n{contact_us_url} <br>\r\n', 4, 1),
('buyer_notification_review_status_updated', 1, 'Buyer Product Review Status Change - Notification', 'Product Review Status Changed at {website_name}', '\r\n<table id=\"body\" width=\"100%\">    \r\n	<tbody>        \r\n		<tr>            \r\n			<td style=\"padding: 30px 40px 50px 40px; text-align: center\">                \r\n				<h1 style=\"font-size: 40px; letter-spacing: -0.4px; margin: 0 0 30px 0; font-weight: 700; color: #212529\">                    Review Status\r\n                </h1>                \r\n				<p style=\"font-size: 16px; line-height: 1.5; letter-spacing: -0.32px; color: #212529; margin: 0 0 10px 0\">                    Hello {user_full_name},\r\n                </p>                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    Your Review status has been changed to {new_status} at\r\n                    <a href=\"{website_url}\">{website_name}</a>.\r\n                </p>                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    If you require assistance in using our site, or have any feedback or suggestions, please email us at\r\n                    {CONTACT-EMAIL}\r\n                </p>               \r\n                \r\n				<p style=\"font-size: 14px; line-height: 1.71; letter-spacing: -0.28px; color: #212529; margin: 0\"> Thank\r\n                    You<br />\r\n					                    Team {website_name}\r\n                </p>            </td>        \r\n		</tr>    \r\n	</tbody>\r\n</table>', '{user_full_name} Name of the email receiver<br> \r\n{new_status} New/Current Review Status<br>\r\n{website_name} Name of our website<br>\r\n{website_url} URL of our website<br>\r\n{social_media_icons} <br>\r\n{contact_us_url} <br>\r\n', 4, 1),
('cancellation_request_approved_declined', 1, 'Cancellation Request Approved/Declined Email for User', 'Order Cancellation Request {request_status} on {website_name}', '\r\n<table id=\"body\" width=\"100%\">    \r\n	<tbody>        \r\n		<tr>            \r\n			<td style=\"padding: 30px 40px 50px 40px; text-align: center\">                \r\n				<h1 style=\"font-size: 40px; letter-spacing: -0.4px; margin: 0 0 30px 0; font-weight: 700; color: #212529\">                    Order Cancellation Request Status</h1>                \r\n				<p style=\"font-size: 16px; line-height: 1.5; letter-spacing: -0.32px; color: #212529; margin: 0 0 10px 0\">                    Hello {user_name},</p>                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    Your order cancellation request on {invoice_number} has been {request_status} on <a href=\"{website_url}\">{website_name}</a>                </p>  \r\n                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    If you require assistance in using our site, or have any feedback or suggestions, please email us at\r\n                    {CONTACT-EMAIL}\r\n                </p>             \r\n                \r\n				<p style=\"font-size: 14px; line-height: 1.71; letter-spacing: -0.28px; color: #212529; margin: 0\"> Thank\r\n                    You<br />\r\n					                    Team {website_name}\r\n                </p>            </td>        \r\n		</tr>    \r\n	</tbody>\r\n</table>', '{user_name} Name of the email receiver<br>\r\n{invoice_number} Order Invoice Number<br>\r\n{request_status} New Withdrawal Request Status<br>\r\n{website_name} Name of the website<br>\r\n{social_media_icons} <br>\r\n{contact_us_url} <br>', 2, 1),
('cancel_subscription_email', 1, 'Cancel Subscription Email', 'Cancel Subscription Email', '\r\n<table id=\"body\" width=\"100%\">    \r\n	<tbody>        \r\n		<tr>            \r\n			<td style=\"padding: 30px 40px 50px 40px; text-align: center\">                \r\n				<h1 style=\"font-size: 40px; letter-spacing: -0.4px; margin: 0 0 30px 0; font-weight: 700; color: #212529\">                    Cancel Subscription</h1>                \r\n				<p style=\"font-size: 16px; line-height: 1.5; letter-spacing: -0.32px; color: #212529; margin: 0 0 10px 0\">                    Hello {user_full_name},</p>                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    your {spackage_name} plan has been canceled.\r\n                </p>                              \r\n                \r\n				<p style=\"font-size: 14px; line-height: 1.71; letter-spacing: -0.28px; color: #212529; margin: 0\"> Thank\r\n                    You<br />\r\n					                    Team {website_name}\r\n                </p>            </td>        \r\n		</tr>    \r\n	</tbody>\r\n</table>', '{user_full_name} Name of the email receiver<br>\r\n{website_name} Name of our website<br>\r\n{website_url} URL of our website<br>\r\n{reset_url} URL to reset the password<br>\r\n{spackage_name} Package name <br>\r\n', 2, 1),
('catalog_request_message_user', 1, 'Catalog request message notification', 'New message received on catalog request at {website_name}', '\r\n<table id=\"body\" width=\"100%\">    \r\n	<tbody>        \r\n		<tr>            \r\n			<td style=\"padding: 30px 40px 50px 40px; text-align: center\">                \r\n				<h1 style=\"font-size: 40px; letter-spacing: -0.4px; margin: 0 0 30px 0; font-weight: 700; color: #212529\">                    You have a New Message\r\n                </h1>                \r\n				<p style=\"font-size: 16px; line-height: 1.5; letter-spacing: -0.32px; color: #212529; margin: 0 0 10px 0\">                    Hello {user_full_name},\r\n                </p>                          \r\n                \r\n				<div style=\"margin-bottom: 20px; text-align: left; padding: 20px; border-radius: 4px; background: #f6f6f6; border: 1px solid #f6f6f6\">                    \r\n					<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0\">                        {username} has posted a message on catalog request at <a href=\"{website_url}\">{website_name}</a><br />\r\n						          \r\n                        <span style=\"font-weight: bold;\">Message:</span> {message}\r\n                    </p>                </div>                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    If you require assistance in using our site, or have any feedback or suggestions, please email us at\r\n                    {CONTACT-EMAIL}\r\n                </p>  \r\n                \r\n				<p style=\"font-size: 14px; line-height: 1.71; letter-spacing: -0.28px; color: #212529; margin: 0\"> Thank\r\n                    You<br />\r\n					                    Team {website_name}\r\n                </p>            </td>        \r\n		</tr>    \r\n	</tbody>\r\n</table>', '{user_full_name} - Name of the email receiver<br>\n{username} username of the person posted a message.<br>\n{request_number} Request number on which message is posted.<br>\n{message} message body/comments sent by the sender<br>\n{click_here} Link to reply to the message <br>\n{social_media_icons} <br>\n{contact_us_url} <br>', 1, 1),
('child_order_status_change', 1, 'Child Order Status Change - Notification', 'Order Item Status Changed at {website_name}', '\r\n<table id=\"body\" width=\"100%\">    \r\n	<tbody>        \r\n		<tr>            \r\n			<td style=\"padding: 30px 40px 50px 40px; text-align: center\">                \r\n				<h1 style=\"font-size: 40px; letter-spacing: -0.4px; margin: 0 0 30px 0; font-weight: 700; color: #212529\">                    Order Item Status\r\n                </h1>                \r\n				<p style=\"font-size: 16px; line-height: 1.5; letter-spacing: -0.32px; color: #212529; margin: 0 0 10px 0\">                    Hello {user_full_name},\r\n                </p> \r\n                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    Your order item status has been changed to {new_order_status} corresponding to Order Invoice Number {invoice_number}. at <a href=\"{website_url}\">{website_name}</a>                </p> \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    {order_items_table_format}\r\n                </p>      \r\n              \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    {shipment_information}\r\n                </p> \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    {order_admin_comments}\r\n                </p>                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    If you require assistance in using our site, or have any feedback or suggestions, please email us at\r\n                    {CONTACT-EMAIL}\r\n                </p> \r\n                           \r\n                \r\n				<p style=\"font-size: 14px; line-height: 1.71; letter-spacing: -0.28px; color: #212529; margin: 0\"> Thank\r\n                    You<br />\r\n					                    Team {website_name}\r\n                </p>            </td>        \r\n		</tr>    \r\n	</tbody>\r\n</table>', '{user_full_name} Name of the email receiver<br> \n{new_order_status} New/Current Order Status<br>\n{invoice_number} - Child Order Invoice Number.<br>\n{order_items_table_format} - Child Order Items in Tabular Format.<br>\n{website_name} Name of our website<br>\n{website_url} URL of our website<br>\n{social_media_icons} <br>\n{contact_us_url} <br>\n', 4, 1),
('COD_OTP_VERIFICATION', 1, 'COD OTP Verification', 'COD OTP Verification', '\r\n<table id=\"body\" width=\"100%\">    \r\n	<tbody>        \r\n		<tr>            \r\n			<td style=\"padding: 30px 40px 50px 40px; text-align: center\">                \r\n				<h1 style=\"font-size: 40px; letter-spacing: -0.4px; margin: 0 0 30px 0; font-weight: 700; color: #212529\">                    COD OTP Verification\r\n                </h1>                \r\n				<p style=\"font-size: 16px; line-height: 1.5; letter-spacing: -0.32px; color: #212529; margin: 0 0 10px 0\">                    Hello {user_name},\r\n                </p>                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    {OTP} is the OTP for cash on delivery order verification.<br />\r\n					                    <a href=\"{website_url}\">{website_name}</a>                </p>             \r\n                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    If you require assistance in using our site, or have any feedback or suggestions, please email us at\r\n                    {CONTACT-EMAIL}\r\n                </p>  \r\n                \r\n				<p style=\"font-size: 14px; line-height: 1.71; letter-spacing: -0.28px; color: #212529; margin: 0\"> Thank\r\n                    You<br />\r\n					                    Team {website_name}\r\n                </p>            </td>        \r\n		</tr>    \r\n	</tbody>\r\n</table>', '{user_name} Name of the email receiver.<br>\r\n{OTP} - One Time Password<br>\r\n{website_name} - Name of the website.\r\n{social_media_icons} <br>\r\n{contact_us_url} <br>', 5, 1),
('contact_us', 1, 'Contact-Us', 'Contact Us Form Submitted on {website_name}', '\r\n<table id=\"body\" width=\"100%\">    \r\n	<tbody>        \r\n		<tr>            \r\n			<td style=\"padding: 30px 40px 50px 40px; text-align: center\">                \r\n				<h1 style=\"font-size: 40px; letter-spacing: -0.4px; margin: 0 0 30px 0; font-weight: 700; color: #212529\">Contact Us Data</h1>                \r\n				<p style=\"font-size: 16px; line-height: 1.5; letter-spacing: -0.32px; color: #212529; margin: 0 0 10px 0\">Hello Admin,</p>                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">{name} has submitted the contact us form on <a href=\"{website_url}\">{website_name}</a></p>                \r\n				<div style=\"margin-bottom: 20px; text-align: left; padding: 0 20px; border-radius: 4px; background: #f6f6f6; border: 1px solid #f6f6f6\">                    \r\n					<h5 style=\"opacity: 0.6; font-size: 16px\">Details</h5>                    \r\n					<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\"><span style=\"font-weight: bold;\">Name:</span> {name}</p>                    \r\n					<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\"><span style=\"font-weight: bold;\">Email:</span> {email_address}</p>                    \r\n					<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\"><span style=\"font-weight: bold;\">Phone Number:</span> {phone_number}</p>                    \r\n					<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\"><span style=\"font-weight: bold;\">Message:</span> {message}</p>                </div>                \r\n				<p style=\"font-size: 14px; line-height: 1.71; letter-spacing: -0.28px; color: #212529; margin: 0\">                    Thank You<br />\r\n					                    Team {website name}\r\n                </p>            </td>        \r\n		</tr>    \r\n	</tbody>\r\n</table>', '{name} Name of the person who has submitted the contact form<br>\r\n{email_address} Email Address of the sender<br>\r\n{phone_number} Phone Number of the sender<br>\r\n{message} Additional message sent by sender\r\n{social_media_icons} <br>\r\n{contact_us_url} <br>', 1, 1),
('customer_digital_order_email', 1, 'Customer Digital Order Email - Notification', 'Digital Order Details from {website_name}', '\r\n<table id=\"body\" width=\"100%\">    \r\n	<tbody>        \r\n		<tr>            \r\n			<td style=\"padding: 30px 40px 50px 40px; text-align: center\">                \r\n				<h1 style=\"font-size: 40px; letter-spacing: -0.4px; margin: 0 0 30px 0; font-weight: 700; color: #212529\">                    Order Placed</h1>                \r\n				<p style=\"font-size: 16px; line-height: 1.5; letter-spacing: -0.32px; color: #212529; margin: 0 0 10px 0\">                    Hello {user_full_name},</p>                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    Thanks for placing a digital order on <a href=\"{website_url}\">{website_name}</a>. Your\r\n                                order has been received and will be processed and Seller will send the download link\r\n                                once payment has been confirmed.\r\n                </p>                \r\n				<p style=\"text-align: center; font-size: 20px\">Your order information is given below.</p>                \r\n				<p>{order_items_table_format}</p>          \r\n                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    If you require assistance in using our site, or have any feedback or suggestions, please email us at\r\n                    {CONTACT-EMAIL}\r\n                </p>                \r\n				<p style=\"font-size: 14px; line-height: 1.71; letter-spacing: -0.28px; color: #212529; margin: 0\"> Thank\r\n                    You<br />\r\n					                    Team {website_name}\r\n                </p>            </td>        \r\n		</tr>    \r\n	</tbody>\r\n</table>', '{user_full_name} - Name of the email receiver.<br>\r\n{order_invoice_number} - Invoice Number of the order.<br>\r\n{website_name} Name of our website<br>\r\n{website_url} URL of our website<br>\r\n{order_items_table_format} Order Item Summary in Tabular Format.<br>\r\n{social_media_icons} <br>\r\n{contact_us_url} <br>', 4, 1)
ON DUPLICATE KEY UPDATE etpl_body=VALUES(etpl_body),etpl_replacements=VALUES(etpl_replacements);
INSERT INTO `tbl_email_templates` (`etpl_code`, `etpl_lang_id`, `etpl_name`, `etpl_subject`, `etpl_body`, `etpl_replacements`, `etpl_priority`, `etpl_status`) VALUES
('customer_order_email', 1, 'Customer Order Email - Notification', 'Order Details from {website_name}', '\r\n<table id=\"body\" width=\"100%\">    \r\n	<tbody>        \r\n		<tr>            \r\n			<td style=\"padding: 30px 40px 50px 40px; text-align: center\">                \r\n				<h1 style=\"font-size: 40px; letter-spacing: -0.4px; margin: 0 0 30px 0; font-weight: 700; color: #212529\">                    Order Placed\r\n                </h1>                \r\n				<p style=\"font-size: 16px; line-height: 1.5; letter-spacing: -0.32px; color: #212529; margin: 0 0 10px 0\">                    Hello {user_full_name},\r\n                </p> \r\n                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    Thanks for placing an order on <a href=\"{website_url}\">{website_name}</a>. Your order has been received and will be processed once payment has been confirmed.<br />\r\n					                </p>               \r\n                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    {order_products_table_format}\r\n                </p>             \r\n                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    If you require assistance in using our site, or have any feedback or suggestions, please email us at\r\n                    {CONTACT-EMAIL}\r\n                </p> \r\n                           \r\n                \r\n				<p style=\"font-size: 14px; line-height: 1.71; letter-spacing: -0.28px; color: #212529; margin: 0\"> Thank\r\n                    You<br />\r\n					                    Team {website_name}\r\n                </p>            </td>        \r\n		</tr>    \r\n	</tbody>\r\n</table>', '{user_full_name} - Name of the email receiver.<br>\n{order_invoice_number} - Invoice Number of the order.<br>\n{website_name} Name of our website<br>\n{website_url} URL of our website<br>\n{order_products_table_format} Order Products Summary in Tabular Format.<br>\n{social_media_icons} <br>\n{contact_us_url} <br>', 4, 1),
('data_request_notification_to_admin', 1, 'Data request notification to admin', 'Request Data', '\r\n<table id=\"body\" width=\"100%\">    \r\n	<tbody>        \r\n		<tr>            \r\n			<td style=\"padding: 30px 40px 50px 40px; text-align: center\">                \r\n				<h1 style=\"font-size: 40px; letter-spacing: -0.4px; margin: 0 0 30px 0; font-weight: 700; color: #212529\">                    Data Request\r\n                </h1>                \r\n				<p style=\"font-size: 16px; line-height: 1.5; letter-spacing: -0.32px; color: #212529; margin: 0 0 10px 0\">                    Hello Admin,</p>                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    Data request has been placed by {user_full_name}\r\n                </p>                \r\n				<div style=\"margin-bottom: 20px; text-align: left; padding: 0 20px; border-radius: 4px; background: #f6f6f6; border: 1px solid #f6f6f6\">                    \r\n					<h5 style=\"opacity: 0.6; font-size: 16px\">Details</h5>                    \r\n					<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\"><span style=\"font-weight: bold;\">Phone Number:</span> {user_phone}</p>                    \r\n					<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\"><span style=\"font-weight: bold;\">Username:</span> {username}</p>                    \r\n					<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\"><span style=\"font-weight: bold;\">Purpose of request:</span> {ureq_purpose}</p>                    \r\n                </div>                          \r\n                \r\n				<p style=\"font-size: 14px; line-height: 1.71; letter-spacing: -0.28px; color: #212529; margin: 0\"> Thank\r\n                    You<br />\r\n					                    Team {website_name}\r\n                </p>            </td>        \r\n		</tr>    \r\n	</tbody>\r\n</table>', '{user_full_name} Full User name<br>\r\n{username} Username<br>\r\n{user_phone} User phone Number<br>\r\n{ureq_purpose} Request Purpose', 1, 1),
('failed_login_attempt', 1, 'Failed Login Attempt', 'Failed Login Attempt', '\r\n<table id=\"body\" width=\"100%\">    \r\n	<tbody>        \r\n		<tr>            \r\n			<td style=\"padding: 30px 40px 50px 40px; text-align: center\">                \r\n				<h1 style=\"font-size: 40px; letter-spacing: -0.4px; margin: 0 0 30px 0; font-weight: 700; color: #212529\">Failed login attempts</h1>                \r\n				<p style=\"font-size: 16px; line-height: 1.5; letter-spacing: -0.32px; color: #212529; margin: 0 0 10px 0\">Hello {user_full_name},</p>                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    You seem to be facing problem logging in at <a href=\"{website_url}\">{website_name}</a><br />\r\n					                    Please note that your username and password are both case sensitive.<br />\r\n					                    You can use forgot password feature if you have lost your password.<br />\r\n					                    If you were not trying logging in, it might be a hacking attempt.<br />\r\n					                    Also, you should keep your email password secured.<br />\r\n					                </p>                \r\n				<p style=\"font-size: 14px; line-height: 1.71; letter-spacing: -0.28px; color: #212529; margin: 0\">                    Thank You<br />\r\n					                    Team {website name}\r\n                </p>            </td>        \r\n		</tr>    \r\n	</tbody>\r\n</table>', '', 5, 1),
