('new_seller_approved_admin', 1, 'New Seller Approval - Admin', 'New Seller Approval on {website_name}', '\r\n<table id=\"body\" width=\"100%\">    \r\n	<tbody>        \r\n		<tr>            \r\n			<td style=\"padding: 30px 40px 50px 40px; text-align: center\">                \r\n				<h1 style=\"font-size: 40px; letter-spacing: -0.4px; margin: 0 0 30px 0; font-weight: 700; color: #212529\">                    Seller Approval\r\n                </h1>                \r\n				<p style=\"font-size: 16px; line-height: 1.5; letter-spacing: -0.32px; color: #212529; margin: 0 0 10px 0\">                    Hello Admin,\r\n                </p>                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    New seller has been registered on <a href=\"{website_url}\">{website_name}</a>                </p>  \r\n                \r\n				<div style=\"margin-bottom: 20px; text-align: left; padding: 0 20px; border-radius: 4px; background: #f6f6f6; border: 1px solid #f6f6f6\">                    \r\n					<h5 style=\"opacity: 0.6; font-size: 16px\">Seller Details</h5>                    \r\n					<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\"><span style=\"font-weight: bold;\">Reference Number:</span> {reference_number}</p>                    \r\n					<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\"><span style=\"font-weight: bold;\">Username:</span> {username}</p>                    \r\n					<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\"><span style=\"font-weight: bold;\">Email:</span> {email}</p>                    \r\n					<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\"><span style=\"font-