('new_subscription_purchase', 1, 'New Subscription Plan Purchased', 'New Subscription Plan purchased at {website_name}', '\r\n<table id=\"body\" width=\"100%\">    \r\n	<tbody>        \r\n		<tr>            \r\n			<td style=\"padding: 30px 40px 50px 40px; text-align: center\">                \r\n				<h1 style=\"font-size: 40px; letter-spacing: -0.4px; margin: 0 0 30px 0; font-weight: 700; color: #212529\">                    New Subscription Plan\r\n                </h1>                \r\n				<p style=\"font-size: 16px; line-height: 1.5; letter-spacing: -0.32px; color: #212529; margin: 0 0 10px 0\">                    Hello {user_full_name},\r\n                </p>                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    Order payment status has been changed to {new_order_status} corresponding to <br />\r\n					 Order Invoice Number - {invoice_number} at <a href=\"{website_url}\">{website_name}</a>                </p>  \r\n                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    {order_products_table_format}\r\n                </p>            \r\n                \r\n				<p style=\"font-size: 14px; line-height: 1.71; letter-spacing: -0.28px; color: #212529; margin: 0\"> Thank\r\n                    You<br />\r\n					                    Team {website_name}\r\n                </p>            </td>        \r\n		</tr>    \r\n	</tbody>\r\n</table>', '{website_name} Name of our website<br>\r\n{user_full_name} User Name <br>\r\n{invoice_number} Invoice Number of the Order<br>\r\n{new_order_status} New Order Status<br>\r\n{social_media_icons} <br>\r\n{contact_us_url} <br>', 4, 1),
('new_subscription_purchase_admin', 1, 'Admin - New Subscription Plan Purchased', 'New Subscription Plan purchased at {website_name}', '\r\n<table id=\"body\" width=\"100%\">    \r\n	<tbody>        \r\n		<tr>            \r\n			<td style=\"padding: 30px 40px 50px 40px; text-align: center\">                \r\n				<h1 style=\"font-size: 40px; letter-spacing: -0.4px; margin: 0 0 30px 0; font-weight: 700; color: #212529\">                    New Subscription Purchase\r\n                </h1>                \r\n				<p style=\"font-size: 16px; line-height: 1.5; letter-spacing: -0.32px; color: #212529; margin: 0 0 10px 0\">                    Hello Admin,\r\n                </p>                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    New subscription plan has been purchase by user &nbsp;corresponding to Order Invoice Number - {invoice_number} at <a href=\"{website_url}\">{website_name}</a>.\r\n                </p>                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    {order_products_table_format}\r\n                </p> \r\n                \r\n				<p style=\"font-size: 14px; line-height: 1.71; letter-spacing: -0.28px; color: #212529; margin: 0\"> Thank\r\n                    You<br />\r\n					                    Team {website_name}\r\n                </p>            </td>        \r\n		</tr>    \r\n	</tbody>\r\n</table>', '{website_name} Name of our website<br>\r\n{invoice_number} Invoice Number of the Order<br>\r\n{new_order_status} New Order Status<br>\r\n{social_media_icons} <br>\r\n{contact_us_url} <br>', 2, 1),
('new_supplier_approval_admin', 1, 'New Seller Approval Request - Admin', 'New Seller Approval Request on {website_name}', '\r\n<table width=\"600px\" cellspacing=\"0\" cellpadding=\"0\" style=\"margin: 0 auto; table-layout: fixed; background: #ffffff; border-radius: 4px; box-shadow: 0 0 10px rgba(0, 0, 0, 0.04)\">\r\n	<tbody>\r\n		<tr>                        \r\n			<td style=\"background:#fff;padding:20px 0 10px; text-align:center;\">                            \r\n				<h4 style=\"font-weight:normal; text-transform:uppercase; color:#999;margin:0; padding:10px 0; font-size:18px;\">Request Received</h4>                            \r\n				<h2 style=\"margin:0; font-size:34px; padding:0;\">Seller Approval</h2></td>                    \r\n		</tr>\r\n		<tr>                        \r\n			<td style=\"background:#fff;padding:0 30px; text-align:center; color:#999;vertical-align:top;\">                            \r\n				<table width=\"100%\" border=\"0\" align=\"center\" cellpadding=\"0\" cellspacing=\"0\">                                \r\n					<tbody>                                    \r\n						<tr>                                        \r\n							<td style=\"padding:20px 0 30px;\"><strong style=\"font-size:18px;color:#333;\">Dear Admin </strong><br />\r\n								We have received a new seller approval request on <a href=\"{website_url}\">{website_name}</a>. Please find the details below:</td>                                    \r\n						</tr>                                    \r\n						<tr>                                        \r\n							<td style=\"padding:20px 0 30px;\">                                            \r\n								<table style=\"border:1px solid #ddd; border-collapse:collapse;\" cellspacing=\"0\" cellpadding=\"0\" border=\"0\">                                                \r\n									<tbody>                                                    \r\n										<tr>                                                        \r\n											<td style=\"padding:10px;font-size:13px;border:1px solid #ddd; color:#333; font-weight:bold;\" width=\"153\">Reference Number</td>                                                        \r\n											<td style=\"padding:10px;font-size:13px; color:#333;border:1px solid #ddd;\" width=\"620\">{reference_number}</td>                                                    \r\n										</tr>                                                        \r\n										<tr>                                                        \r\n											<td style=\"padding:10px;font-size:13px;border:1px solid #ddd; color:#333; font-weight:bold;\" width=\"153\">Username<span class=\"Apple-tab-span\" style=\"white-space:pre\"></span></td>                                                        \r\n											<td style=\"padding:10px;font-size:13px; color:#333;border:1px solid #ddd;\" width=\"620\">{username}</td>                                                    \r\n										</tr>  \r\n										<tr>                                                        \r\n											<td style=\"padding:10px;font-size:13px;border:1px solid #ddd; color:#333; font-weight:bold;\" width=\"153\">Email</td>                                                        \r\n											<td style=\"padding:10px;font-size:13px; color:#333;border:1px solid #ddd;\" width=\"620\">{email}</td>                                                    \r\n										</tr> \r\n										<tr>                                                        \r\n											<td style=\"padding:10px;font-size:13px;border:1px solid #ddd; color:#333; font-weight:bold;\" width=\"153\">Name</td>                                                        \r\n											<td style=\"padding:10px;font-size:13px; color:#333;border:1px solid #ddd;\" width=\"620\">{name}</td>                                                    \r\n										</tr>                                                        \r\n									</tbody>                                            \r\n								</table></td>                                    \r\n						</tr>                                    \r\n					</tbody>                            \r\n				</table></td>                    \r\n		</tr>\r\n	</tbody>\r\n</table>', '{website_name} Name of the website<br>\r\n{username} \r\n\r\nUsername of the person registered<br>\r\n{email} Email Address of the person registered<br>\r\n{name} Name of the person sent request<br>\r\n{reference_number} \r\n\r\nReference Number of the request<br>\r\n{social_media_icons} <br>\r\n{contact_us_url} <br>\r\n', 3, 1),
('order_cancellation_notification', 1, 'Order Cancellation Notification - Vendor & Admin', 'Order Cancellation Request Received on {website_name}', '\r\n<table id=\"body\" width=\"100%\">    \r\n	<tbody>        \r\n		<tr>            \r\n			<td style=\"padding: 30px 40px 50px 40px; text-align: center\">                \r\n				<h1 style=\"font-size: 40px; letter-spacing: -0.4px; margin: 0 0 30px 0; font-weight: 700; color: #212529\">                    Order Cancellation</h1>                \r\n				<p style=\"font-size: 16px; line-height: 1.5; letter-spacing: -0.32px; color: #212529; margin: 0 0 10px 0\">                    Hello {user_name},</p>                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    Buyer has submitted the Order Cancellation Request corresponding to Order Invoice Number\r\n                                {invoice_number}.\r\n                </p>               \r\n                \r\n				<p style=\"font-size: 14px; line-height: 1.71; letter-spacing: -0.28px; color: #212529; margin: 0\"> Thank\r\n                    You<br />\r\n					                    Team {website_name}\r\n                </p>            </td>        \r\n		</tr>    \r\n	</tbody>\r\n</table>', '{user_name} Name of the email receiver<br>\r\n{website_name} Name of the website<br>\r\n{click_here} Click here Link to update inventory.\r\n{social_media_icons} <br>\r\n{contact_us_url} <br>', 4, 1),
('password_changed_successfully', 1, 'Password Changed Successfully', 'Password Changed Successfully at {website_name}', '\r\n<table id=\"body\" width=\"100%\">    \r\n	<tbody>        \r\n		<tr>            \r\n			<td style=\"padding: 30px 40px 50px 40px; text-align: center\">                \r\n				<h1 style=\"font-size: 40px; letter-spacing: -0.4px; margin: 0 0 30px 0; font-weight: 700; color: #212529\">                    Changed Password!</h1>                \r\n				<p style=\"font-size: 16px; line-height: 1.5; letter-spacing: -0.32px; color: #212529; margin: 0 0 10px 0\">                    Hello {user_full_name},</p>                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    You have successfully changed your password, now you can log in with your new password.\r\n                </p>                \r\n				<p style=\"opacity: 0.7; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    Please click below link to Login to your Account.\r\n                </p>                \r\n				<div class=\"btn-wrapper\" style=\"text-align: center\"> <a href=\"{login_link}\" style=\" border-radius: 4px; background-color: #f13925; color: #fff; font-size: 14px; letter-spacing: -0.28px; text-decoration: none; padding: 9px 20px; display: inline-block; margin-bottom: 30px; \">                        Login</a>                </div>                \r\n                \r\n				<p style=\"font-size: 14px; line-height: 1.71; letter-spacing: -0.28px; color: #212529; margin: 0\"> Thank\r\n                    You<br />\r\n					                    Team {website_name}\r\n                </p>            </td>        \r\n		</tr>    \r\n	</tbody>\r\n</table>', '{full_name} Name of the email receiver.<br>\r\n{website_name} Name of our website<br>\r\n{social_media_icons} <br>\r\n{contact_us_url} <br>', 5, 1),
('primary_order_bank_transfer_payment_status_admin', 1, 'Admin - Primary Order Payment Status', 'Payment Status at {website_name}', '\r\n<table id=\"body\" width=\"100%\">    \r\n	<tbody>        \r\n		<tr>            \r\n			<td style=\"padding: 30px 40px 50px 40px; text-align: center\">                \r\n				<h1 style=\"font-size: 40px; letter-spacing: -0.4px; margin: 0 0 30px 0; font-weight: 700; color: #212529\">                    Order Placed \r\n                </h1>                \r\n				<p style=\"font-size: 16px; line-height: 1.5; letter-spacing: -0.32px; color: #212529; margin: 0 0 10px 0\">                    Hello Admin,\r\n                </p> \r\n                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    Order placed via {order_payment_method} corresponding to Order Invoice Number - {invoice_number} at <a href=\"{website_url}\">{website_name}</a>                </p>                          \r\n                \r\n				<p style=\"font-size: 14px; line-height: 1.71; letter-spacing: -0.28px; color: #212529; margin: 0\"> Thank\r\n                    You<br />\r\n					                    Team {website_name}\r\n                </p>            </td>        \r\n		</tr>    \r\n	</tbody>\r\n</table>', '{user_full_name} - Name of the email receiver.<br>\r\n{website_name} Name of our website<br>\r\n{order_payment_method} Order payment method (Bank Transfer) <br>\r\n{invoice_number} Invoice Number of the order<br>\r\n{social_media_icons} <br>\r\n{contact_us_url} <br>', 3, 1),
('primary_order_bank_transfer_payment_status_buyer', 1, 'Buyers - Primary Order Payment Status', 'Order Payment Status at {website_name}', '\r\n<table id=\"body\" width=\"100%\">    \r\n	<tbody>        \r\n		<tr>            \r\n			<td style=\"padding: 30px 40px 50px 40px; text-align: center\">                \r\n				<h1 style=\"font-size: 40px; letter-spacing: -0.4px; margin: 0 0 30px 0; font-weight: 700; color: #212529\">                    Order Placed \r\n                </h1>                \r\n				<p style=\"font-size: 16px; line-height: 1.5; letter-spacing: -0.32px; color: #212529; margin: 0 0 10px 0\">                    Hello {user_full_name},\r\n                </p> \r\n                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    Your order has been placed to {order_payment_method} corresponding to Order Invoice Number - {invoice_number} at <a href=\"{website_url}\">{website_name}</a>                </p> \r\n                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    If you require assistance in using our site, or have any feedback or suggestions, please email us at\r\n                    {CONTACT-EMAIL}\r\n                </p> \r\n                           \r\n                \r\n				<p style=\"font-size: 14px; line-height: 1.71; letter-spacing: -0.28px; color: #212529; margin: 0\"> Thank\r\n                    You<br />\r\n					                    Team {website_name}\r\n                </p>            </td>        \r\n		</tr>    \r\n	</tbody>\r\n</table>', '{user_full_name} - Name of the email receiver.<br>\r\n{website_name} Name of our website<br>\r\n{order_payment_method} Order payment method (Bank Transfer) <br>\r\n{invoice_number} Invoice Number of the order<br>\r\n{social_media_icons} <br>\r\n{contact_us_url} <br>', 3, 1),
('primary_order_payment_status_admin', 1, 'Admin - Primary Order Payment Status', 'Payment Status at {website_name}', '\r\n<table id=\"body\" width=\"100%\">    \r\n	<tbody>        \r\n		<tr>            \r\n			<td style=\"padding: 30px 40px 50px 40px; text-align: center\">                \r\n				<h1 style=\"font-size: 40px; letter-spacing: -0.4px; margin: 0 0 30px 0; font-weight: 700; color: #212529\">                    Order Placed\r\n                </h1>                \r\n				<p style=\"font-size: 16px; line-height: 1.5; letter-spacing: -0.32px; color: #212529; margin: 0 0 10px 0\">                    Hello Admin,\r\n                </p> \r\n                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    Order placed via {order_payment_method} corresponding to Order Invoice Number - {invoice_number} at <a href=\"{website_url}\">{website_name}</a>                </p>               \r\n                \r\n				<p style=\"font-size: 14px; line-height: 1.71; letter-spacing: -0.28px; color: #212529; margin: 0\"> Thank\r\n                    You<br />\r\n					                    Team {website_name}\r\n                </p>            </td>        \r\n		</tr>    \r\n	</tbody>\r\n</table>', '{user_full_name} - Name of the email receiver.<br>\r\n{website_name} Name of our website<br>\r\n{order_payment_method} Order payment method (cash on delivery) <br>\r\n{invoice_number} Invoice Number of the order<br>\r\n{social_media_icons} <br>\r\n{contact_us_url} <br>', 4, 1),
('primary_order_payment_status_buyer', 1, 'Buyers - Primary Order Payment Status', 'Order Payment Status at {website_name}', '\r\n<table id=\"body\" width=\"100%\">    \r\n	<tbody>        \r\n		<tr>            \r\n			<td style=\"padding: 30px 40px 50px 40px; text-align: center\">                \r\n				<h1 style=\"font-size: 40px; letter-spacing: -0.4px; margin: 0 0 30px 0; font-weight: 700; color: #212529\">                    Order Placed\r\n                </h1>                \r\n				<p style=\"font-size: 16px; line-height: 1.5; letter-spacing: -0.32px; color: #212529; margin: 0 0 10px 0\">                    Hello {user_full_name},\r\n                </p> \r\n                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    Your order placed via {order_payment_method} corresponding to Order Invoice Number - {invoice_number} at <a href=\"{website_url}\">{website_name}</a>                </p> \r\n                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    If you require assistance in using our site, or have any feedback or suggestions, please email us at\r\n                    {CONTACT-EMAIL}\r\n                </p> \r\n                           \r\n                \r\n				<p style=\"font-size: 14px; line-height: 1.71; letter-spacing: -0.28px; color: #212529; margin: 0\"> Thank\r\n                    You<br />\r\n					                    Team {website_name}\r\n                </p>            </td>        \r\n		</tr>    \r\n	</tbody>\r\n</table>', '{user_full_name} - Name of the email receiver.<br>\r\n{website_name} Name of our website<br>\r\n{order_payment_method} Order payment method (cash on delivery) <br>\r\n{invoice_number} Invoice Number of the order<br>\r\n{social_media_icons} <br>\r\n{contact_us_url} <br>', 4, 1),
('primary_order_payment_status_change_admin', 1, 'Admin - Primary Order Payment Status Change', 'Payment Status Changed at {website_name}', '\r\n<table id=\"body\" width=\"100%\">    \r\n	<tbody>        \r\n		<tr>            \r\n			<td style=\"padding: 30px 40px 50px 40px; text-align: center\">                \r\n				<h1 style=\"font-size: 40px; letter-spacing: -0.4px; margin: 0 0 30px 0; font-weight: 700; color: #212529\">                    Order Payment Status\r\n                </h1>                \r\n				<p style=\"font-size: 16px; line-height: 1.5; letter-spacing: -0.32px; color: #212529; margin: 0 0 10px 0\">                    Hello Admin,\r\n                </p> \r\n                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    Order payment status has been changed to {new_order_status} corresponding to Order Invoice Number - {invoice_number} at <a href=\"{website_url}\">{website_name}</a>                </p>               \r\n                \r\n				<p style=\"font-size: 14px; line-height: 1.71; letter-spacing: -0.28px; color: #212529; margin: 0\"> Thank\r\n                    You<br />\r\n					                    Team {website_name}\r\n                </p>            </td>        \r\n		</tr>    \r\n	</tbody>\r\n</table>', '{website_name} Name of our website<br>\r\n{invoice_number} Invoice Number of the Order<br>\r\n{new_order_status} New Order Status<br>\r\n{social_media_icons} <br>\r\n{contact_us_url} <br>', 4, 1)
ON DUPLICATE KEY UPDATE etpl_body=VALUES(etpl_body),etpl_replacements=VALUES(etpl_replacements);
INSERT INTO `tbl_email_templates` (`etpl_code`, `etpl_lang_id`, `etpl_name`, `etpl_subject`, `etpl_body`, `etpl_replacements`, `etpl_priority`, `etpl_status`) VALUES
('primary_order_payment_status_change_buyer', 1, 'Buyers - Primary Order Payment Status Change', 'Order Payment Status Changed at {website_name}', '\r\n<table id=\"body\" width=\"100%\">    \r\n	<tbody>        \r\n		<tr>            \r\n			<td style=\"padding: 30px 40px 50px 40px; text-align: center\">                \r\n				<h1 style=\"font-size: 40px; letter-spacing: -0.4px; margin: 0 0 30px 0; font-weight: 700; color: #212529\">                    Order Payment Status\r\n                </h1>                \r\n				<p style=\"font-size: 16px; line-height: 1.5; letter-spacing: -0.32px; color: #212529; margin: 0 0 10px 0\">                    Hello {user_full_name},\r\n                </p> \r\n                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    Your order payment status has been changed to {new_order_status} corresponding to Order Invoice Number - {invoice_number} at <a href=\"{website_url}\">{website_name}</a>                </p> \r\n                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    If you require assistance in using our site, or have any feedback or suggestions, please email us at\r\n                    {CONTACT-EMAIL}\r\n                </p> \r\n                           \r\n                \r\n				<p style=\"font-size: 14px; line-height: 1.71; letter-spacing: -0.28px; color: #212529; margin: 0\"> Thank\r\n                    You<br />\r\n					                    Team {website_name}\r\n                </p>            </td>        \r\n		</tr>    \r\n	</tbody>\r\n</table>', '{user_full_name} - Name of the email receiver.<br>\r\n{website_name} Name of our website<br>\r\n{new_order_status} New Payment Status (Pending/Paid) <br>\r\n{invoice_number} Invoice Number of the order<br>\r\n{social_media_icons} <br>\r\n{contact_us_url} <br>', 4, 1),
('product_return', 1, 'Product Return - Vendor Notification', 'Product return request submitted on {website_name}', '\r\n<table id=\"body\" width=\"100%\">    \r\n	<tbody>        \r\n		<tr>            \r\n			<td style=\"padding: 30px 40px 50px 40px; text-align: center\">                \r\n				<h1 style=\"font-size: 40px; letter-spacing: -0.4px; margin: 0 0 30px 0; font-weight: 700; color: #212529\">                    Order Return Request\r\n                </h1>                \r\n				<p style=\"font-size: 16px; line-height: 1.5; letter-spacing: -0.32px; color: #212529; margin: 0 0 10px 0\">                    Hello {user_name},\r\n                </p>                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    {username} has submitted a {return_request_type} request on a product.\r\n                </p>  \r\n                \r\n				<div style=\"margin-bottom: 20px; text-align: left; padding: 0 20px; border-radius: 4px; background: #f6f6f6; border: 1px solid #f6f6f6\">                    \r\n					<h5 style=\"opacity: 0.6; font-size: 16px\">Order Return Request Details</h5>                    \r\n					<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\"><span style=\"font-weight: bold;\">Order Id/Invoice Number:</span> {child_order_invoice_number}</p>                    \r\n					<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\"><span style=\"font-weight: bold;\">Product:</span> {return_prod_title}</p>                    \r\n					<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\"><span style=\"font-weight: bold;\">Qty:</span> {return_qty}</p>                    \r\n					<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\"><span style=\"font-weight: bold;\">Request ID:</span> {return_request_id}</p>                    \r\n					<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\"><span style=\"font-weight: bold;\">Request Type:</span> {return_request_type}</p>                    \r\n					<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\"><span style=\"font-weight: bold;\">Reason:</span> {return_reason}</p>                    \r\n					<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\"><span style=\"font-weight: bold;\">Comments:</span> {return_comments}</p>                </div>                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    If you require assistance in using our site, or have any feedback or suggestions, please email us at\r\n                    {CONTACT-EMAIL}\r\n                </p>                \r\n				<p style=\"font-size: 14px; line-height: 1.71; letter-spacing: -0.28px; color: #212529; margin: 0\"> Thank\r\n                    You<br />\r\n					                    Team {website_name}\r\n                </p>            </td>        \r\n		</tr>    \r\n	</tbody>\r\n</table>', '{user_name} Name of the email receiver<br>\r\n{username} Username of the person, who placed return request.<br>\r\n{return_request_type} - Refund or Return. .<br>\r\n{return_prod_title} - Product for which return request is placed.<br>\r\n{return_qty} Return request QTY.<br>\r\n{return_reason} Return Reason selected by buyer.<br>\r\n{return_comments} Comments submitted by the buyer<br>\r\n{return_request_id} Return Request Number<br>\r\n{child_order_invoice_number} Order ID/Invoice Number\r\n{social_media_icons} <br>\r\n{contact_us_url} <br>\r\n\r\n', 3, 1),
('promotion_approval_required_to_admin', 1, 'Approval Required for promotion', 'New Promotion Request  at {website_name}', '\r\n<table id=\"body\" width=\"100%\">    \r\n	<tbody>        \r\n		<tr>            \r\n			<td style=\"padding: 30px 40px 50px 40px; text-align: center\">                \r\n				<h1 style=\"font-size: 40px; letter-spacing: -0.4px; margin: 0 0 30px 0; font-weight: 700; color: #212529\">                    Promotion Approval Request\r\n                </h1>                \r\n				<p style=\"font-size: 16px; line-height: 1.5; letter-spacing: -0.32px; color: #212529; margin: 0 0 10px 0\">                    Hello Admin,\r\n                </p>                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    New promotion approval request has been by {user_full_name} corresponding to Promotion - {promotion_name}.\r\n                </p>     \r\n                \r\n				<p style=\"font-size: 14px; line-height: 1.71; letter-spacing: -0.28px; color: #212529; margin: 0\"> Thank\r\n                    You<br />\r\n					                    Team {website_name}\r\n                </p>            </td>        \r\n		</tr>    \r\n	</tbody>\r\n</table>', '{user_full_name} - Name of the email receiver.<br>\r\n{website_name} Name of our website<br>\r\n\r\n\r\n{new_request_status} New Request Status (Approved/Declined) <br>\r\n{promotion_name} Promotion Name<br>\r\n{social_media_icons} <br>\r\n{contact_us_url} <br>', 2, 1),
('promotion_request_status_change', 1, 'Promotion Status Change', 'Your Promotion Request {new_request_status} at {website_name}', '\r\n<table id=\"body\" width=\"100%\">    \r\n	<tbody>        \r\n		<tr>            \r\n			<td style=\"padding: 30px 40px 50px 40px; text-align: center\">                \r\n				<h1 style=\"font-size: 40px; letter-spacing: -0.4px; margin: 0 0 30px 0; font-weight: 700; color: #212529\">                    Promotion Approval Request\r\n                </h1>                \r\n				<p style=\"font-size: 16px; line-height: 1.5; letter-spacing: -0.32px; color: #212529; margin: 0 0 10px 0\">                    Hello {user_full_name},\r\n                </p>                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    Your promotion approval request has been {new_request_status} corresponding to Promotion\r\n                                - {promotion_name}.\r\n                </p>                  \r\n                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    If you require assistance in using our site, or have any feedback or suggestions, please email us at\r\n                    {CONTACT-EMAIL}\r\n                </p>                \r\n				<p style=\"font-size: 14px; line-height: 1.71; letter-spacing: -0.28px; color: #212529; margin: 0\"> Thank\r\n                    You<br />\r\n					                    Team {website_name}\r\n                </p>            </td>        \r\n		</tr>    \r\n	</tbody>\r\n</table>', '{user_full_name} - Name of the email receiver.<br>\r\n{website_name} Name of our website<br>\r\n\r\n\r\n{new_request_status} New Request Status (Approved/Declined) <br>\r\n{promotion_name} Promotion Name<br>\r\n{social_media_icons} <br>\r\n{contact_us_url} <br>', 2, 1),
('reminder_for_items_in_cart', 1, 'Reminder for items in Cart', 'Reminder for items in Cart', '\r\n<table id=\"body\" width=\"100%\">    \r\n	<tbody>        \r\n		<tr>            \r\n			<td style=\"padding: 30px 40px 50px 40px; text-align: center\">                \r\n				<h1 style=\"font-size: 40px; letter-spacing: -0.4px; margin: 0 0 30px 0; font-weight: 700; color: #212529\">                    {website_name} is missing you!\r\n                </h1>                \r\n				<p style=\"font-size: 16px; line-height: 1.5; letter-spacing: -0.32px; color: #212529; margin: 0 0 10px 0\">                    Hello {user_full_name},\r\n                </p>                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    Thank you for adding products to your cart.\r\n                </p>                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    Proceed to checkout, before someone else grabs your products\r\n                </p>                \r\n				<div class=\"btn-wrapper\" style=\"text-align: center\"> \r\n                    <a href=\"{checkout_url}\" style=\" border-radius: 4px; background-color: #f13925; color: #fff; font-size: 14px; letter-spacing: -0.28px; text-decoration: none; padding: 9px 20px; display: inline-block; margin-bottom: 30px; \">                        Checkout\r\n                    </a> \r\n                </div>               \r\n                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    If you require assistance in using our site, or have any feedback or suggestions, please email us at\r\n                    {CONTACT-EMAIL}\r\n                </p>                \r\n				<p style=\"font-size: 14px; line-height: 1.71; letter-spacing: -0.28px; color: #212529; margin: 0\"> Thank\r\n                    You<br />\r\n					                    Team {website_name}\r\n                </p>            </td>        \r\n		</tr>    \r\n	</tbody>\r\n</table>', '', 1, 1),
('reminder_for_items_in_wishlist', 1, 'Reminder for items in wishlist', 'Reminder for items in wishlist', '\r\n<table id=\"body\" width=\"100%\">    \r\n	<tbody>        \r\n		<tr>            \r\n			<td style=\"padding: 30px 40px 50px 40px; text-align: center\">                \r\n				<h1 style=\"font-size: 40px; letter-spacing: -0.4px; margin: 0 0 30px 0; font-weight: 700; color: #212529\">                    {website_name} is missing you!\r\n                </h1>                \r\n				<p style=\"font-size: 16px; line-height: 1.5; letter-spacing: -0.32px; color: #212529; margin: 0 0 10px 0\">                    Hello {user_full_name},\r\n                </p>                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    We are glad you liked our products.\r\n                </p>                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    {products_in_wishlist_format}\r\n                </p>                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    Kindly check your favorite products by clicking the following link.\r\n                </p>                \r\n				<div class=\"btn-wrapper\" style=\"text-align: center\"> \r\n                    <a href=\"{wishlist_url}\" style=\" border-radius: 4px; background-color: #f13925; color: #fff; font-size: 14px; letter-spacing: -0.28px; text-decoration: none; padding: 9px 20px; display: inline-block; margin-bottom: 30px; \">                        Click Here\r\n                    </a> \r\n                </div>               \r\n                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    If you require assistance in using our site, or have any feedback or suggestions, please email us at\r\n                    {CONTACT-EMAIL}\r\n                </p>                \r\n				<p style=\"font-size: 14px; line-height: 1.71; letter-spacing: -0.28px; color: #212529; margin: 0\"> Thank\r\n                    You<br />\r\n					                    Team {website_name}\r\n                </p>            </td>        \r\n		</tr>    \r\n	</tbody>\r\n</table>', '', 1, 1),
('report_shop', 1, 'Report a shop', 'Report submitted on {website_name}', '\r\n<table id=\"body\" width=\"100%\">    \r\n	<tbody>        \r\n		<tr>            \r\n			<td style=\"padding: 30px 40px 50px 40px; text-align: center\">                \r\n				<h1 style=\"font-size: 40px; letter-spacing: -0.4px; margin: 0 0 30px 0; font-weight: 700; color: #212529\">                    Shop Reported\r\n                </h1>                \r\n				<p style=\"font-size: 16px; line-height: 1.5; letter-spacing: -0.32px; color: #212529; margin: 0 0 10px 0\">                    Hello Admin,\r\n                </p>               \r\n                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    {username} has reported a shop on <a href=\"{website_url}\">{website_name}</a>                </p> \r\n                \r\n				<div style=\"margin-bottom: 20px; text-align: left; padding: 0 20px; border-radius: 4px; background: #f6f6f6; border: 1px solid #f6f6f6\">                    \r\n					<h5 style=\"opacity: 0.6; font-size: 16px\">Details</h5>                    \r\n					<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\"><span style=\"font-weight: bold;\">Shop:</span> {shop_name}</p>                    \r\n					<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\"><span style=\"font-weight: bold;\">Reason:</span> {report_reason}</p>                    \r\n					<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\"><span style=\"font-weight: bold;\">Message:</span> {report_message Type}</p>                    \r\n                </div>   \r\n              \r\n                \r\n				<p style=\"font-size: 14px; line-height: 1.71; letter-spacing: -0.28px; color: #212529; margin: 0\"> Thank\r\n                    You<br />\r\n					                    Team {website_name}\r\n                </p>            </td>        \r\n		</tr>    \r\n	</tbody>\r\n</table>', '{username} Username of the person who submitted the Report<br>\r\n{shop_name} Shop Name<br>\r\n{report_reason} Reason for reported<br>\r\n{report_message} Message submitted by the reporter<br>\r\n{social_media_icons} <br>\r\n{contact_us_url} <br>', 1, 1),
('return_request_message_user', 1, 'Return request message notification - for Buyer/Vendor', 'New message received on return request at {website_name}', '\r\n<table id=\"body\" width=\"100%\">    \r\n	<tbody>        \r\n		<tr>            \r\n			<td style=\"padding: 30px 40px 50px 40px; text-align: center\">                \r\n				<h1 style=\"font-size: 40px; letter-spacing: -0.4px; margin: 0 0 30px 0; font-weight: 700; color: #212529\">                    You have a New Message\r\n                </h1>                \r\n				<p style=\"font-size: 16px; line-height: 1.5; letter-spacing: -0.32px; color: #212529; margin: 0 0 10px 0\">                    Hello {user_full_name},\r\n                </p>                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    {username} has posted a message on request reference number {request_number} at <a href=\"{website_url}\">{website_name}</a>                </p>                \r\n				<div style=\"margin-bottom: 20px; text-align: left; padding: 0 20px; border-radius: 4px; background: #f6f6f6; border: 1px solid #f6f6f6\">                    \r\n					<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\"><span style=\"font-weight: bold;\">Message:</span> {message}</p>                   \r\n                </div>              \r\n                \r\n				<div class=\"btn-wrapper\" style=\"text-align: center\"> \r\n                    <a href=\"{click_here}\" style=\" border-radius: 4px; background-color: #f13925; color: #fff; font-size: 14px; letter-spacing: -0.28px; text-decoration: none; padding: 9px 20px; display: inline-block; margin-bottom: 30px; \">                        Reply\r\n                    </a> \r\n                </div>                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    If you require assistance in using our site, or have any feedback or suggestions, please email us at\r\n                    {CONTACT-EMAIL}\r\n                </p>                \r\n				<p style=\"font-size: 14px; line-height: 1.71; letter-spacing: -0.28px; color: #212529; margin: 0\"> Thank\r\n                    You<br />\r\n					                    Team {website_name}\r\n                </p>            </td>        \r\n		</tr>    \r\n	</tbody>\r\n</table>', '{user_full_name} - Name of the email receiver<br>\r\n{username} username of the person posted a message.<br>\r\n{request_number} Request number on which message is posted.<br>\r\n{message} message body/comments sent by the sender<br>\r\n{click_here} Link to reply to the message <br>\r\n{social_media_icons} <br>\r\n{contact_us_url} <br>', 3, 1),
('return_request_status_change_notification', 1, 'Return request status change notification', 'Return request status changed on {website_name}', '\r\n<table width=\"600px\" cellspacing=\"0\" cellpadding=\"0\" style=\"margin: 0 auto; table-layout: fixed; background: #ffffff; border-radius: 4px; box-shadow: 0 0 10px rgba(0, 0, 0, 0.04)\">\r\n	<tbody>\r\n		<tr>                        \r\n			<td style=\"background:#fff;padding:20px 0 10px; text-align:center;\">                            \r\n				<h4 style=\"font-weight:normal; text-transform:uppercase; color:#999;margin:0; padding:10px 0; font-size:18px;\">Updated</h4>                            \r\n				<h2 style=\"margin:0; font-size:34px; padding:0;\">Return Request Status</h2></td>                    \r\n		</tr> \r\n		<tr>                        \r\n			<td style=\"background:#fff;padding:0 30px; text-align:center; color:#999;vertical-align:top;\">                            \r\n				<table width=\"100%\" border=\"0\" align=\"center\" cellpadding=\"0\" cellspacing=\"0\">                                \r\n					<tbody>                                    \r\n						<tr>                                        \r\n							<td style=\"padding:20px 0 30px;\"><strong style=\"font-size:18px;color:#333;\">Dear {user_full_name}</strong><br />\r\n								{username} has {new_status_name} return request reference number {request_number} on <a href=\"{website_url}\">{website_name}</a>.</td>                                    \r\n						</tr>                                    \r\n					</tbody>                            \r\n				</table></td>                    \r\n		</tr> \r\n	</tbody>\r\n</table>', '{user_full_name} Name of the email receiver<br>\r\n{username} username of the person<br>\r\n{new_status_name} New Status of the Request<br>\r\n{request_number} Request number<br>\r\n{website_name} Name of the website.<br>\r\n{social_media_icons} <br>\r\n{contact_us_url} <br>', 3, 1),
('reward_points_credited_debited', 1, 'Reward Points Received/Debited Email for Buyer/Seller', 'Your account has been {debit_credit_type} reward points on {website_name}', '\r\n<table id=\"body\" width=\"100%\">    \r\n	<tbody>        \r\n		<tr>            \r\n			<td style=\"padding: 30px 40px 50px 40px; text-align: center\">                \r\n				<h1 style=\"font-size: 40px; letter-spacing: -0.4px; margin: 0 0 30px 0; font-weight: 700; color: #212529\">                    Reward Point Transaction\r\n                </h1>                \r\n				<p style=\"font-size: 16px; line-height: 1.5; letter-spacing: -0.32px; color: #212529; margin: 0 0 10px 0\">                    Hello {user_name},\r\n                </p>                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    Your account has been {debit_credit_type} reward points at <a href=\"{website_url}\">{website_name}</a>                </p>                        \r\n                \r\n				<div style=\"margin-bottom: 20px; text-align: left; padding: 0 20px; border-radius: 4px; background: #f6f6f6; border: 1px solid #f6f6f6\">                    \r\n					<h5 style=\"opacity: 0.6; font-size: 16px\">Please find the details below:</h5>                    \r\n					<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\"><span style=\"font-weight: bold;\">Points:</span> {reward_points}</p>                    \r\n					<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\"><span style=\"font-weight: bold;\">Comment:</span> {comments}</p>                </div>                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    If you require assistance in using our site, or have any feedback or suggestions, please email us at\r\n                    {CONTACT-EMAIL}\r\n                </p>                \r\n				<p style=\"font-size: 14px; line-height: 1.71; letter-spacing: -0.28px; color: #212529; margin: 0\"> Thank\r\n                    You<br />\r\n					                    Team {website_name}\r\n                </p>            </td>        \r\n		</tr>    \r\n	</tbody>\r\n</table>', '{user_name} Name of the email receiver.<br>\n{debit_credit_type} - Credited or Debited<br>\n{reward_points} - Reward Points<br>{comments} - Comments<br>\n{website_name} Name of our website<br>\n{website_url} URL of our website<br>', 5, 1),
