('subscription_free_package_reminder_email', 1, 'Subscription Free Package Reminder Email', 'Subscription Reminder Email', '\r\n<table id=\"body\" width=\"100%\">    \r\n	<tbody>        \r\n		<tr>            \r\n			<td style=\"padding: 30px 40px 50px 40px; text-align: center\">                \r\n				<h1 style=\"font-size: 40px; letter-spacing: -0.4px; margin: 0 0 30px 0; font-weight: 700; color: #212529\">                    Subscription Reminder\r\n                </h1>                \r\n				<p style=\"font-size: 16px; line-height: 1.5; letter-spacing: -0.32px; color: #212529; margin: 0 0 10px 0\">                    Hello {user_full_name},\r\n                </p>                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    Your Subscription is going to be expire in next 2 days. Kindly Purchase any Package to continue your subscription on <a href=\"{website_url}\">{website_name}\r\n                                </a>                </p>                            \r\n                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    If you require assistance in using our site, or have any feedback or suggestions, please email us at\r\n                    {CONTACT-EMAIL}\r\n                </p>                \r\n				<p style=\"font-size: 14px; line-height: 1.71; letter-spacing: -0.28px; color: #212529; margin: 0\"> Thank\r\n                    You<br />\r\n					                    Team {website_name}\r\n                </p>            </td>        \r\n		</tr>    \r\n	</tbody>\r\n</table>', '{user_full_name} Name of the email receiver.<br>\r\n{website_name} Name of our website<br>\r\n{website_url} URL/Link of our website<br>\r\n{tracking_url} referral url\r\n{invitation_message} <br>\r\n{social_media_icons} <br>\r\n{contact_us_url} <br>', 2, 1),
('subscription_reminder_email', 1, 'Subscription Reminder Email', 'Subscription Reminder Email', '\r\n<table id=\"body\" width=\"100%\">    \r\n	<tbody>        \r\n		<tr>            \r\n			<td style=\"padding: 30px 40px 50px 40px; text-align: center\">                \r\n				<h1 style=\"font-size: 40px; letter-spacing: -0.4px; margin: 0 0 30px 0; font-weight: 700; color: #212529\">                    Subscription Reminder\r\n                </h1>                \r\n				<p style=\"font-size: 16px; line-height: 1.5; letter-spacing: -0.32px; color: #212529; margin: 0 0 10px 0\">                    Hello {user_full_name},\r\n                </p>                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    your Subscription is going to be expire in next 2 days. Kindly maintain your minimum\r\n                                wallet balance to continue your subscription on&nbsp;<a href=\"{website_url}\">{website_name}</a>                </p>                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    If you require assistance in using our site, or have any feedback or suggestions, please email us at\r\n                    {CONTACT-EMAIL}\r\n                </p>                \r\n				<p style=\"font-size: 14px; line-height: 1.71; letter-spacing: -0.28px; color: #212529; margin: 0\"> Thank\r\n                    You<br />\r\n					                    Team {website_name}\r\n                </p>            </td>        \r\n		</tr>    \r\n	</tbody>\r\n</table>', '{user_full_name} Name of the email receiver.<br>\r\n{website_name} Name of our website<br>\r\n{website_url} URL/Link of our website<br>\r\n{tracking_url} referral url\r\n{invitation_message} <br>\r\n{social_media_icons} <br>\r\n{contact_us_url} <br>', 2, 1),
('subscription_renew_admin', 1, 'Admin - Subscription Renew', 'Subscription Renewed at {website_name}', '\r\n<table id=\"body\" width=\"100%\">    \r\n	<tbody>        \r\n		<tr>            \r\n			<td style=\"padding: 30px 40px 50px 40px; text-align: center\">                \r\n				<h1 style=\"font-size: 40px; letter-spacing: -0.4px; margin: 0 0 30px 0; font-weight: 700; color: #212529\">                    Subscription Reminder\r\n                </h1>                \r\n				<p style=\"font-size: 16px; line-height: 1.5; letter-spacing: -0.32px; color: #212529; margin: 0 0 10px 0\">                    Hello {user_full_name},\r\n                </p>                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    your Subscription is going to be expire in next 2 days. Kindly maintain your minimum\r\n                                wallet balance to continue your subscription on&nbsp;<a href=\"{website_url}\">{website_name}</a>                </p>  \r\n                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    If you require assistance in using our site, or have any feedback or suggestions, please email us at\r\n                    {CONTACT-EMAIL}\r\n                </p>              \r\n                \r\n				<p style=\"font-size: 14px; line-height: 1.71; letter-spacing: -0.28px; color: #212529; margin: 0\"> Thank\r\n                    You<br />\r\n					                    Team {website_name}\r\n                </p>            </td>        \r\n		</tr>    \r\n	</tbody>\r\n</table>', '{website_name} Name of our website<br>\r\n{invoice_number} Invoice Number of the Order<br>\r\n{new_order_status} New Order Status<br>\r\n{social_media_icons} <br>\r\n{contact_us_url} <br>', 2, 1),
('subscription_renew_user', 1, 'Renew Subscription Plan', 'Subscription Renewed at {website_name}', '\r\n<table id=\"body\" width=\"100%\">    \r\n	<tbody>        \r\n		<tr>            \r\n			<td style=\"padding: 30px 40px 50px 40px; text-align: center\">                \r\n				<h1 style=\"font-size: 40px; letter-spacing: -0.4px; margin: 0 0 30px 0; font-weight: 700; color: #212529\">                    Subscription Renew\r\n                </h1>                \r\n				<p style=\"font-size: 16px; line-height: 1.5; letter-spacing: -0.32px; color: #212529; margin: 0 0 10px 0\">                    Hello {user_name},\r\n                </p>               \r\n                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                   Your subscription has been renewed.<br />\r\n					Corresponding to Order Invoice Number - {invoice_number} at <a href=\"{website_url}\">{website_name}</a>.\r\n                </p>    \r\n                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    {order_products_table_format}\r\n                </p>                \r\n                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    If you require assistance in using our site, or have any feedback or suggestions, please email us at\r\n                    {CONTACT-EMAIL}\r\n                </p>                \r\n				<p style=\"font-size: 14px; line-height: 1.71; letter-spacing: -0.28px; color: #212529; margin: 0\"> Thank\r\n                    You<br />\r\n					                    Team {website_name}\r\n                </p>            </td>        \r\n		</tr>    \r\n	</tbody>\r\n</table>', '{website_name} Name of our website<br>\r\n{user_full_name} User Name <br>\r\n{invoice_number} Invoice Number of the Order<br>\r\n{new_order_status} New Order Status<br>\r\n{social_media_icons} <br>\r\n{contact_us_url} <br>', 2, 1),
('supplier_request_status_change_buyer', 1, 'Buyers - Seller Request Status Change', 'Your Seller Request {new_request_status} at {website_name}', '\r\n<table id=\"body\" width=\"100%\">    \r\n	<tbody>        \r\n		<tr>            \r\n			<td style=\"padding: 30px 40px 50px 40px; text-align: center\">                \r\n				<h1 style=\"font-size: 40px; letter-spacing: -0.4px; margin: 0 0 30px 0; font-weight: 700; color: #212529\">                    Seller Approval Status\r\n                </h1>                \r\n				<p style=\"font-size: 16px; line-height: 1.5; letter-spacing: -0.32px; color: #212529; margin: 0 0 10px 0\">                    Hello {user_full_name},\r\n                </p>                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    Your seller approval request has been {new_request_status} corresponding to Reference\r\n                                Number - {reference_number}.\r\n                </p> \r\n                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    {request_comments}\r\n                </p>  \r\n                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    If you require assistance in using our site, or have any feedback or suggestions, please email us at\r\n                    {CONTACT-EMAIL}\r\n                </p>  \r\n                \r\n				<p style=\"font-size: 14px; line-height: 1.71; letter-spacing: -0.28px; color: #212529; margin: 0\"> Thank\r\n                    You<br />\r\n					                    Team {website_name}\r\n                </p>            </td>        \r\n		</tr>    \r\n	</tbody>\r\n</table>', '{user_full_name} - Name of the email receiver.<br>\r\n{website_name} Name of our website<br>\r\n\r\n\r\n{new_request_status} New Request Status (Approved/Declined) <br>\r\n{reference_number} Reference Number of the request<br>\r\n{social_media_icons} <br>\r\n{contact_us_url} <br>', 3, 1)
ON DUPLICATE KEY UPDATE etpl_body=VALUES(etpl_body),etpl_replacements=VALUES(etpl_replacements);
INSERT INTO `tbl_email_templates` (`etpl_code`, `etpl_lang_id`, `etpl_name`, `etpl_subject`, `etpl_body`, `etpl_replacements`, `etpl_priority`, `etpl_status`) VALUES
('taxapi_order_creation_failure', 1, 'TaxApi Order Creation Failure Email', 'TaxApi Order Creation Failed at {website_name}', '\r\n<table id=\"body\" width=\"100%\">    \r\n	<tbody>        \r\n		<tr>            \r\n			<td style=\"padding: 30px 40px 50px 40px; text-align: center\">                \r\n				<h1 style=\"font-size: 40px; letter-spacing: -0.4px; margin: 0 0 30px 0; font-weight: 700; color: #212529\">TaxApi Order Creation Failure</h1>                \r\n				<p style=\"font-size: 16px; line-height: 1.5; letter-spacing: -0.32px; color: #212529; margin: 0 0 10px 0\">Hello Admin,</p>                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    System has tried to create an order/transaction on TaxApi after order is marked as completed by admin, but not able to create an Order/Transaction on TaxApi due to below Error on your site <a href=\"{website_url}\">{website_name}</a> with Yokart Order Invoice Number {invoice_number}.<br />\r\n					Please find the TaxApi Error information below.\r\n                </p>                \r\n				<p style=\"font-size: 14px; line-height: 1.71; letter-spacing: -0.28px; color: #212529; margin: 0\"> Thank\r\n                    You<br />\r\n					                    Team {website_name}\r\n                </p>            </td>        \r\n		</tr>    \r\n	</tbody>\r\n</table>', '{invoice_number} - Yokart Order Invoice Number.<br>\r\n{website_name} Name of our website<br>\r\n{website_url} URL of our website<br>\r\n{error_message} -  Error Message received from TaxApi while creating order \r\n{social_media_icons} <br>\r\n{contact_us_url} <br>', 3, 1),
('test_email', 1, 'Test Email', 'Test Email', '\r\n<table id=\"body\" width=\"100%\">    \r\n	<tbody>        \r\n		<tr>            \r\n			<td style=\"padding: 30px 40px 50px 40px; text-align: center\">                \r\n				<h1 style=\"font-size: 40px; letter-spacing: -0.4px; margin: 0 0 30px 0; font-weight: 700; color: #212529\">                    Test Email</h1>                \r\n				<p style=\"font-size: 16px; line-height: 1.5; letter-spacing: -0.32px; color: #212529; margin: 0 0 10px 0\">                    Hello Admin</p>                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    This is the test email from <a href=\"{website_url}\">{website_name}</a>                </p>                \r\n				<p style=\"font-size: 14px; line-height: 1.71; letter-spacing: -0.28px; color: #212529; margin: 0\"> Thank\r\n                    You<br />\r\n					                    Team {website_name}\r\n                </p>            </td>        \r\n		</tr>    \r\n	</tbody>\r\n</table>', '\r\n{website_name} Name of our website<br>\r\n', 5, 1),
('threshold_notification_vendor', 1, 'Threshold Level Notification - Seller', 'Product threshold level achieved on {website_name}', '\r\n<table id=\"body\" width=\"100%\">    \r\n	<tbody>        \r\n		<tr>            \r\n			<td style=\"padding: 30px 40px 50px 40px; text-align: center\">                \r\n				<h1 style=\"font-size: 40px; letter-spacing: -0.4px; margin: 0 0 30px 0; font-weight: 700; color: #212529\">                    Product Stock Alert\r\n                </h1>                \r\n				<p style=\"font-size: 16px; line-height: 1.5; letter-spacing: -0.32px; color: #212529; margin: 0 0 10px 0\">                    Hello {shop_name},\r\n                </p>                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    Your product {prod_title} has achieved threshold level on <a href=\"{website_url}\">{website_name}</a>                </p>                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    Please click below link to refill stock quantity.\r\n                </p>               \r\n                \r\n				<div class=\"btn-wrapper\" style=\"text-align: center\"> \r\n                    <a href=\"{click_here}\" style=\" border-radius: 4px; background-color: #f13925; color: #fff; font-size: 14px; letter-spacing: -0.28px; text-decoration: none; padding: 9px 20px; display: inline-block; margin-bottom: 30px; \">                        Refill Stock\r\n                    </a> \r\n                </div>                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    If you require assistance in using our site, or have any feedback or suggestions, please email us at\r\n                    {CONTACT-EMAIL}\r\n                </p>                \r\n				<p style=\"font-size: 14px; line-height: 1.71; letter-spacing: -0.28px; color: #212529; margin: 0\"> Thank\r\n                    You<br />\r\n					                    Team {website_name}\r\n                </p>            </td>        \r\n		</tr>    \r\n	</tbody>\r\n</table>', '{shop_name} Shop Name<br>\r\n{prod_title} Name of the product<br>\r\n{website_name} Name of the website<br>\r\n{click_here} Click here Link to update inventory.\r\n{social_media_icons} <br>\r\n{contact_us_url} <br>', 4, 1),
('user_admin_password_changed_successfully', 1, 'User/Admin Password Changed Successfully', 'Password reset successfully {website_name}', '\r\n<table id=\"body\" width=\"100%\">    \r\n	<tbody>        \r\n		<tr>            \r\n			<td style=\"padding: 30px 40px 50px 40px; text-align: center\">                \r\n				<h1 style=\"font-size: 40px; letter-spacing: -0.4px; margin: 0 0 30px 0; font-weight: 700; color: #212529\">                Password changed</h1>                \r\n				<p style=\"font-size: 16px; line-height: 1.5; letter-spacing: -0.32px; color: #212529; margin: 0 0 10px 0\">                    Hello {user_full_name},</p>                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    Your password has been changed successfully.\r\n                </p>                \r\n				<p style=\"opacity: 0.7; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    Please click below link to Login to your Account.\r\n                </p>                \r\n				<div class=\"btn-wrapper\" style=\"text-align: center\"> <a href=\"{login_link}\" style=\" border-radius: 4px; background-color: #f13925; color: #fff; font-size: 14px; letter-spacing: -0.28px; text-decoration: none; padding: 9px 20px; display: inline-block; margin-bottom: 30px; \">                        Login</a>                </div>                \r\n                \r\n				<p style=\"font-size: 14px; line-height: 1.71; letter-spacing: -0.28px; color: #212529; margin: 0\"> Thank\r\n                    You<br />\r\n					                    Team {website_name}\r\n                </p>            </td>        \r\n		</tr>    \r\n	</tbody>\r\n</table>', '{user_full_name}<br>\r\n{website_name}<br>\r\n{website_url}<br>\r\n{login_link}<br>\r\n{social_media_icons} <br>\r\n{contact_us_url} <br>', 5, 1),
('user_change_email_request_notification', 1, 'Email Change Request', 'Email Change Request at {website_name}', '\r\n<table id=\"body\" width=\"100%\">    \r\n	<tbody>        \r\n		<tr>            \r\n			<td style=\"padding: 30px 40px 50px 40px; text-align: center\">                \r\n				<h1 style=\"font-size: 40px; letter-spacing: -0.4px; margin: 0 0 30px 0; font-weight: 700; color: #212529\">                    Account Verification\r\n                </h1>                \r\n				<p style=\"font-size: 16px; line-height: 1.5; letter-spacing: -0.32px; color: #212529; margin: 0 0 10px 0\">                    Hello {user_full_name},\r\n                </p>                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    It seems that you have requested to change email to {new_email} at <a href=\"{website_url}\">{website_name}</a>                </p>             \r\n                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    If you require assistance in using our site, or have any feedback or suggestions, please email us at\r\n                    {CONTACT-EMAIL}\r\n                </p>                \r\n				<p style=\"font-size: 14px; line-height: 1.71; letter-spacing: -0.28px; color: #212529; margin: 0\"> Thank\r\n                    You<br />\r\n					                    Team {website_name}\r\n                </p>            </td>        \r\n		</tr>    \r\n	</tbody>\r\n</table>', '{user_full_name} Name of the email receiver.<br>\r\n{new_email} New email address \r\n{website_name} Name of our website<br>\r\n{website_url} URL/Link of our website<br>\r\n{verification_url} Url to verify email\r\n{social_media_icons} <br>\r\n{contact_us_url} <br>', 5, 1),
('user_discount_coupon_notification', 1, 'Discount Gift Voucher', 'Discount Gift Voucher at {website_name}', '\r\n<table id=\"body\" width=\"100%\">    \r\n	<tbody>        \r\n		<tr>            \r\n			<td style=\"padding: 30px 40px 50px 40px; text-align: center\">                \r\n				<h1 style=\"font-size: 40px; letter-spacing: -0.4px; margin: 0 0 30px 0; font-weight: 700; color: #212529\">                    Discount Gift Voucher\r\n                </h1>                \r\n				<p style=\"font-size: 16px; line-height: 1.5; letter-spacing: -0.32px; color: #212529; margin: 0 0 10px 0\">                    Hello {user_name},\r\n                </p>                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    Your are eligible to avail {discount_value} discount on your next purchase at <a href=\"{website_url}\">{website_name}</a>                </p>                \r\n				<div style=\"margin-bottom: 20px; text-align: left; padding: 0 20px; border-radius: 4px; background: #f6f6f6; border: 1px solid #f6f6f6\">                    \r\n					<h5 style=\"opacity: 0.6; font-size: 16px\">Coupon Details</h5>                    \r\n					<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\"><span style=\"font-weight: bold;\">Coupon Code:</span> {coupon_code}</p>                    \r\n					<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\"><span style=\"font-weight: bold;\">Expired On:</span> {expired_on}</p>                    \r\n                </div>                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    If you require assistance in using our site, or have any feedback or suggestions, please email us at\r\n                  