('user_email_changed_notification', 1, 'Email Changed', 'Email Changed at {website_name}', '\r\n<table id=\"body\" width=\"100%\">    \r\n	<tbody>        \r\n		<tr>            \r\n			<td style=\"padding: 30px 40px 50px 40px; text-align: center\">                \r\n				<h1 style=\"font-size: 40px; letter-spacing: -0.4px; margin: 0 0 30px 0; font-weight: 700; color: #212529\">                    Email Address Changed\r\n                </h1>                \r\n				<p style=\"font-size: 16px; line-height: 1.5; letter-spacing: -0.32px; color: #212529; margin: 0 0 10px 0\">                    Hello {user_full_name},\r\n                </p>                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    Your Email Address has been changed to {new_email} at <a href=\"{website_url}\">{website_name}</a>                </p>             \r\n                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    If you require assistance in using our site, or have any feedback or suggestions, please email us at\r\n                    {CONTACT-EMAIL}\r\n                </p>                \r\n				<p style=\"font-size: 14px; line-height: 1.71; letter-spacing: -0.28px; color: #212529; margin: 0\"> Thank\r\n                    You<br />\r\n					                    Team {website_name}\r\n                </p>            </td>        \r\n		</tr>    \r\n	</tbody>\r\n</table>', '{user_full_name} Name of the email receiver.<br>\r\n{new_email} New email address \r\n{website_name} Name of our website<br>\r\n{website_url} URL/Link of our website<br>\r\n{verification_url} Url to verify email\r\n{social_media_icons} <br>\r\n{contact_us_url} <br>', 5, 1),
