('withdrawal_request_admin', 1, 'Withdrawal Request - Admin', 'Withdrawal Request on {website_name}', '\r\n<table id=\"body\" width=\"100%\">    \r\n	<tbody>        \r\n		<tr>            \r\n			<td style=\"padding: 30px 40px 50px 40px; text-align: center\">                \r\n				<h1 style=\"font-size: 40px; letter-spacing: -0.4px; margin: 0 0 30px 0; font-weight: 700; color: #212529\">                    Withdrawal Request\r\n                </h1>                \r\n				<p style=\"font-size: 16px; line-height: 1.5; letter-spacing: -0.32px; color: #212529; margin: 0 0 10px 0\">                    Hello Admin,\r\n                </p>               \r\n                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    {username} has submitted a withdrawal request on {website_name}.\r\n                </p> \r\n                \r\n				<div style=\"margin-bottom: 20px; text-align: left; padding: 0 20px; border-radius: 4px; background: #f6f6f6; border: 1px solid #f6f6f6\">                    \r\n					<h5 style=\"opacity: 0.6; font-size: 16px\">Withdrawal Request Details</h5>                    \r\n					<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\"><span style=\"font-weight: bold;\">Request ID:</span> {request_id}</p>                    \r\n					<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\"><span style=\"font-weight: bold;\">Amount:</span> {request_amount}</p>                </div>                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    {withdrawal_detail_table_format_html}\r\n                </p>                              \r\n                \r\n				<p style=\"font-size: 14px; line-height: 1.71; letter-spacing: -0.28px; color: #212529; margin: 0\"> Thank\r\n                    You<br />\r\n					                    Team {website_name}\r\n                </p>            </td>        \r\n		</tr>    \r\n	</tbody>\r\n</table>', '{username} Username of the person submitted the withdrawal request<br>\r\n{website_name} Name of the website<br>\r\n{request_id} Withdrawal Request ID<br>\r\n{request_amount} Withdrawal Request Amount<br>\r\n{social_media_icons} <br>\r\n{withdrawal_detail_table_format_html}: Withdrawal Payment Details like Bank Details, Cheque Details, PayPal Details etc\r\n{contact_us_url} <br>', 2, 1),
('withdrawal_request_approved_declined', 1, 'Withdrawal Request Approved/Declined Email for User', 'Fund Withdrawal Request {request_status} on {website_name}', '\r\n<table id=\"body\" width=\"100%\">    \r\n	<tbody>        \r\n		<tr>            \r\n			<td style=\"padding: 30px 40px 50px 40px; text-align: center\">                \r\n				<h1 style=\"font-size: 40px; letter-spacing: -0.4px; margin: 0 0 30px 0; font-weight: 700; color: #212529\">                    Withdrawal Request Status\r\n                </h1>                \r\n				<p style=\"font-size: 16px; line-height: 1.5; letter-spacing: -0.32px; color: #212529; margin: 0 0 10px 0\">                    Hello {user_name},\r\n                </p>               \r\n                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    Your fund withdrawal request {request_id} of {request_amount} has been {request_status}\r\n                                on <a href=\"{website_url}\">{website_name}</a>                </p> \r\n                \r\n				<p style=\"opacity: 0.6; font-size: 14px; letter-spacing: -0.28px; color: #212529; line-height: 1.71; margin: 0 0 20px 0\">                    If you require assistance in using our site, or have any feedback or suggestions, please email us at\r\n                    {CONTACT-EMAIL}\r\n                </p>              \r\n                \r\n				<p style=\"font-size: 14px; line-height: 1.71; letter-spacing: -0.28px; color: #212529; margin: 0\"> Thank\r\n                    You<br />\r\n					                    Team {website_name}\r\n                </p>            </td>        \r\n		</tr>    \r\n	</tbody>\r\n</table>', '{user_name} Name of the email receiver<br>\r\n{request_id} Withdrawal Request ID<br>\r\n{request_amount} Withdrawal Request Amount.<br>\r\n{request_status} New Withdrawal Request Status<br>\r\n{website_name} Name of the website\r\n{social_media_icons} <br>\r\n{contact_us_url} <br>', 2, 1)
ON DUPLICATE KEY UPDATE etpl_body=VALUES(etpl_body),etpl_replacements=VALUES(etpl_replacements);

